{
  "name": "@node/diet-tracker",
  "version": "1.0.0",
  "description": "Track daily meals, calories, and macronutrient categories with weekly chart visualization",
  "modnet": {
    "contentType": "health",
    "structure": "list",
    "mechanics": ["track", "chart"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type FoodCategory = 'protein' | 'carbs' | 'fat' | 'fiber';

export type FoodItem = {
  name: string;
  calories: number;
  categories: FoodCategory[];
};

export type Meal = {
  id: string;
  name: string;
  items: FoodItem[];
  timestamp: string; // ISO 8601
  totalCalories: number;
};

export type DailyGoal = {
  calories: number;
  updatedAt: string; // ISO 8601
};

export type DailySummary = {
  date: string; // YYYY-MM-DD
  meals: Meal[];
  totalCalories: number;
  categoryBreakdown: Record<FoodCategory, number>;
  goal: number | null;
  goalProgress: number | null; // 0-1 ratio
};

export type WeeklyData = {
  days: {
    date: string;
    totalCalories: number;
  }[];
  goal: number | null;
};

export type Settings = {
  dailyGoal: DailyGoal | null;
};

import type { Meal, Settings } from './types';

const DATA_DIR = new URL('./data/', import.meta.url).pathname;
const MEALS_PATH = `${DATA_DIR}meals.jsonl`;
const SETTINGS_PATH = `${DATA_DIR}settings.json`;

const ensureDataDir = async (): Promise<void> => {
  const dir = Bun.file(DATA_DIR);
  if (!await dir.exists()) {
    await Bun.$`mkdir -p ${DATA_DIR}`.quiet();
  }
};

export const appendMeal = async (meal: Meal): Promise<void> => {
  await ensureDataDir();
  const line = JSON.stringify(meal) + '\n';
  const file = Bun.file(MEALS_PATH);
  if (await file.exists()) {
    const existing = await file.text();
    await Bun.write(MEALS_PATH, existing + line);
  } else {
    await Bun.write(MEALS_PATH, line);
  }
};

export const readAllMeals = async (): Promise<Meal[]> => {
  const file = Bun.file(MEALS_PATH);
  if (!await file.exists()) return [];
  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Meal);
};

export const readMealsByDate = async (date: string): Promise<Meal[]> => {
  const all = await readAllMeals();
  return all.filter((meal) => meal.timestamp.startsWith(date));
};

export const readSettings = async (): Promise<Settings> => {
  const file = Bun.file(SETTINGS_PATH);
  if (!await file.exists()) return { dailyGoal: null };
  const text = await file.text();
  return JSON.parse(text) as Settings;
};

export const writeSettings = async (settings: Settings): Promise<void> => {
  await ensureDataDir();
  await Bun.write(SETTINGS_PATH, JSON.stringify(settings, null, 2));
};

export const deleteMeal = async (mealId: string): Promise<boolean> => {
  const meals = await readAllMeals();
  const filtered = meals.filter((m) => m.id !== mealId);
  if (filtered.length === meals.length) return false;
  await ensureDataDir();
  const content = filtered.map((m) => JSON.stringify(m)).join('\n') + (filtered.length > 0 ? '\n' : '');
  await Bun.write(MEALS_PATH, content);
  return true;
};

import type { DailySummary, FoodCategory, FoodItem, Meal, WeeklyData } from './types';
import { appendMeal, deleteMeal, readMealsByDate, readSettings, writeSettings } from './data';

const generateId = (): string => crypto.randomUUID();

const toDateString = (date: Date): string =>
  date.toISOString().slice(0, 10);

const today = (): string => toDateString(new Date());

export const logMeal = async (
  name: string,
  items: FoodItem[],
  timestamp?: string,
): Promise<Meal> => {
  const meal: Meal = {
    id: generateId(),
    name,
    items,
    timestamp: timestamp ?? new Date().toISOString(),
    totalCalories: items.reduce((sum, item) => sum + item.calories, 0),
  };
  await appendMeal(meal);
  return meal;
};

export const removeMeal = async (mealId: string): Promise<boolean> => {
  return deleteMeal(mealId);
};

export const setDailyGoal = async (calories: number): Promise<void> => {
  const settings = await readSettings();
  settings.dailyGoal = {
    calories,
    updatedAt: new Date().toISOString(),
  };
  await writeSettings(settings);
};

export const getDailyGoal = async (): Promise<number | null> => {
  const settings = await readSettings();
  return settings.dailyGoal?.calories ?? null;
};

export const getDailySummary = async (date?: string): Promise<DailySummary> => {
  const targetDate = date ?? today();
  const meals = await readMealsByDate(targetDate);
  const goal = await getDailyGoal();

  const totalCalories = meals.reduce((sum, meal) => sum + meal.totalCalories, 0);

  const categoryBreakdown: Record<FoodCategory, number> = {
    protein: 0,
    carbs: 0,
    fat: 0,
    fiber: 0,
  };

  for (const meal of meals) {
    for (const item of meal.items) {
      for (const cat of item.categories) {
        categoryBreakdown[cat] += item.calories;
      }
    }
  }

  return {
    date: targetDate,
    meals,
    totalCalories,
    categoryBreakdown,
    goal,
    goalProgress: goal ? Math.min(totalCalories / goal, 1) : null,
  };
};

export const getWeeklyData = async (endDate?: string): Promise<WeeklyData> => {
  const end = endDate ? new Date(endDate) : new Date();
  const days: WeeklyData['days'] = [];

  for (let i = 6; i >= 0; i--) {
    const d = new Date(end);
    d.setDate(d.getDate() - i);
    const dateStr = toDateString(d);
    const meals = await readMealsByDate(dateStr);
    const totalCalories = meals.reduce((sum, m) => sum + m.totalCalories, 0);
    days.push({ date: dateStr, totalCalories });
  }

  const goal = await getDailyGoal();
  return { days, goal };
};

import { h } from 'plaited';
import type { WeeklyData } from './types';

const BAR_MAX_WIDTH = 300;
const BAR_HEIGHT = 28;
const ROW_GAP = 6;

const COLORS = {
  bar: '#4ade80',
  barOver: '#f87171',
  goalLine: '#facc15',
  label: '#e2e8f0',
  value: '#94a3b8',
  bg: '#1e293b',
};

export const renderWeeklyChart = (data: WeeklyData) => {
  const maxCal = Math.max(
    ...data.days.map((d) => d.totalCalories),
    data.goal ?? 0,
    1,
  );

  const rows = data.days.map((day) => {
    const pct = day.totalCalories / maxCal;
    const width = Math.round(pct * BAR_MAX_WIDTH);
    const isOver = data.goal !== null && day.totalCalories > data.goal;
    const dayLabel = day.date.slice(5); // MM-DD

    return h('div', {
      style: {
        display: 'flex',
        alignItems: 'center',
        gap: '8px',
        height: `${BAR_HEIGHT}px`,
      },
    },
      h('span', {
        style: {
          width: '50px',
          textAlign: 'right',
          fontSize: '13px',
          color: COLORS.label,
          fontFamily: 'monospace',
        },
      }, dayLabel),
      h('div', {
        style: {
          position: 'relative',
          width: `${BAR_MAX_WIDTH}px`,
          height: '100%',
          backgroundColor: '#334155',
          borderRadius: '4px',
          overflow: 'hidden',
        },
      },
        h('div', {
          style: {
            width: `${Math.max(width, 2)}px`,
            height: '100%',
            backgroundColor: isOver ? COLORS.barOver : COLORS.bar,
            borderRadius: '4px',
            transition: 'width 0.3s ease',
          },
        }),
        data.goal !== null
          ? h('div', {
              style: {
                position: 'absolute',
                left: `${Math.round((data.goal / maxCal) * BAR_MAX_WIDTH)}px`,
                top: '0',
                width: '2px',
                height: '100%',
                backgroundColor: COLORS.goalLine,
              },
            })
          : null,
      ),
      h('span', {
        style: {
          fontSize: '13px',
          color: COLORS.value,
          fontFamily: 'monospace',
          minWidth: '60px',
        },
      }, `${day.totalCalories} cal`),
    );
  });

  const legend = data.goal !== null
    ? h('div', {
        style: {
          display: 'flex',
          gap: '16px',
          fontSize: '12px',
          color: COLORS.value,
          marginTop: '8px',
        },
      },
        h('span', {},
          h('span', { style: { color: COLORS.goalLine } }, '\u2502'),
          ` Goal: ${data.goal} cal`,
        ),
        h('span', {},
          h('span', { style: { color: COLORS.bar } }, '\u25A0'),
          ' Under',
        ),
        h('span', {},
          h('span', { style: { color: COLORS.barOver } }, '\u25A0'),
          ' Over',
        ),
      )
    : null;

  return h('div', {
    style: {
      backgroundColor: COLORS.bg,
      padding: '16px',
      borderRadius: '8px',
      display: 'flex',
      flexDirection: 'column',
      gap: `${ROW_GAP}px`,
    },
  },
    h('h3', {
      style: {
        margin: '0 0 8px 0',
        color: COLORS.label,
        fontSize: '15px',
        fontWeight: '600',
      },
    }, 'Weekly Calorie Intake'),
    ...rows,
    legend,
  );
};

import { h, createSSR } from 'plaited';
import type { DailySummary, FoodCategory } from './types';
import { renderWeeklyChart } from './chart';
import { getDailySummary, getWeeklyData } from './tracker';

const CATEGORY_COLORS: Record<FoodCategory, string> = {
  protein: '#60a5fa',
  carbs: '#fbbf24',
  fat: '#f87171',
  fiber: '#34d399',
};

const renderCategoryTag = (category: FoodCategory) =>
  h('span', {
    style: {
      display: 'inline-block',
      padding: '2px 8px',
      borderRadius: '12px',
      fontSize: '11px',
      fontWeight: '600',
      color: '#0f172a',
      backgroundColor: CATEGORY_COLORS[category],
      marginRight: '4px',
    },
  }, category);

const renderMealCard = (meal: DailySummary['meals'][number]) =>
  h('div', {
    style: {
      backgroundColor: '#334155',
      borderRadius: '8px',
      padding: '12px',
      marginBottom: '8px',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        alignItems: 'center',
        marginBottom: '8px',
      },
    },
      h('strong', { style: { color: '#e2e8f0', fontSize: '14px' } }, meal.name),
      h('span', {
        style: { color: '#94a3b8', fontSize: '12px', fontFamily: 'monospace' },
      }, new Date(meal.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })),
    ),
    ...meal.items.map((item) =>
      h('div', {
        style: {
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '4px 0',
          borderBottom: '1px solid #475569',
        },
      },
        h('div', {},
          h('span', { style: { color: '#cbd5e1', fontSize: '13px' } }, item.name),
          h('div', { style: { marginTop: '2px' } },
            ...item.categories.map(renderCategoryTag),
          ),
        ),
        h('span', {
          style: { color: '#94a3b8', fontSize: '13px', fontFamily: 'monospace' },
        }, `${item.calories} cal`),
      ),
    ),
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'flex-end',
        marginTop: '8px',
        paddingTop: '6px',
        borderTop: '1px solid #475569',
      },
    },
      h('span', {
        style: { color: '#4ade80', fontWeight: '700', fontSize: '14px', fontFamily: 'monospace' },
      }, `${meal.totalCalories} cal`),
    ),
  );

const renderGoalProgress = (summary: DailySummary) => {
  if (summary.goal === null) return null;

  const pct = Math.round((summary.goalProgress ?? 0) * 100);
  const isOver = summary.totalCalories > summary.goal;

  return h('div', {
    style: {
      backgroundColor: '#334155',
      borderRadius: '8px',
      padding: '12px',
      marginBottom: '12px',
    },
  },
    h('div', {
      style: {
        display: 'flex',
        justifyContent: 'space-between',
        marginBottom: '6px',
        fontSize: '13px',
      },
    },
      h('span', { style: { color: '#e2e8f0' } }, 'Daily Goal'),
      h('span', {
        style: { color: isOver ? '#f87171' : '#4ade80', fontFamily: 'monospace' },
      }, `${summary.totalCalories} / ${summary.goal} cal (${pct}%)`),
    ),
    h('div', {
      style: {
        width: '100%',
        height: '8px',
        backgroundColor: '#1e293b',
        borderRadius: '4px',
        overflow: 'hidden',
      },
    },
      h('div', {
        style: {
          width: `${Math.min(pct, 100)}%`,
          height: '100%',
          backgroundColor: isOver ? '#f87171' : '#4ade80',
          borderRadius: '4px',
          transition: 'width 0.3s ease',
        },
      }),
    ),
  );
};

const renderCategoryBreakdown = (breakdown: Record<FoodCategory, number>) => {
  const categories = (Object.entries(breakdown) as [FoodCategory, number][])
    .filter(([, cal]) => cal > 0);

  if (categories.length === 0) return null;

  return h('div', {
    style: {
      backgroundColor: '#334155',
      borderRadius: '8px',
      padding: '12px',
      marginBottom: '12px',
    },
  },
    h('h4', {
      style: { margin: '0 0 8px 0', color: '#e2e8f0', fontSize: '13px' },
    }, 'Category Breakdown'),
    ...categories.map(([cat, cal]) =>
      h('div', {
        style: {
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          padding: '4px 0',
        },
      },
        renderCategoryTag(cat),
        h('span', {
          style: { color: '#94a3b8', fontSize: '13px', fontFamily: 'monospace' },
        }, `${cal} cal`),
      ),
    ),
  );
};

export const renderDailyView = async (date?: string): Promise<string> => {
  const summary = await getDailySummary(date);

  const template = h('div', {
    style: {
      backgroundColor: '#0f172a',
      color: '#e2e8f0',
      fontFamily: 'system-ui, -apple-system, sans-serif',
      padding: '16px',
      maxWidth: '480px',
    },
  },
    h('h2', {
      style: { margin: '0 0 12px 0', fontSize: '18px', fontWeight: '700' },
    }, `Diet Log \u2014 ${summary.date}`),
    renderGoalProgress(summary),
    renderCategoryBreakdown(summary.categoryBreakdown),
    h('div', { style: { marginTop: '4px' } },
      summary.meals.length > 0
        ? summary.meals.map(renderMealCard)
        : h('p', { style: { color: '#64748b', fontStyle: 'italic' } }, 'No meals logged today.'),
    ),
    h('div', {
      style: {
        marginTop: '12px',
        padding: '8px 12px',
        backgroundColor: '#1e293b',
        borderRadius: '8px',
        display: 'flex',
        justifyContent: 'space-between',
        fontWeight: '700',
        fontSize: '15px',
      },
    },
      h('span', {}, 'Total'),
      h('span', {
        style: { color: '#4ade80', fontFamily: 'monospace' },
      }, `${summary.totalCalories} cal`),
    ),
  );

  const { render } = createSSR();
  return render(template);
};

export const renderWeeklyView = async (endDate?: string): Promise<string> => {
  const data = await getWeeklyData(endDate);
  const chart = renderWeeklyChart(data);

  const wrapper = h('div', {
    style: {
      backgroundColor: '#0f172a',
      color: '#e2e8f0',
      fontFamily: 'system-ui, -apple-system, sans-serif',
      padding: '16px',
      maxWidth: '520px',
    },
  }, chart);

  const { render } = createSSR();
  return render(wrapper);
};

export type {
  FoodCategory,
  FoodItem,
  Meal,
  DailyGoal,
  DailySummary,
  WeeklyData,
  Settings,
} from './types';

export {
  logMeal,
  removeMeal,
  setDailyGoal,
  getDailyGoal,
  getDailySummary,
  getWeeklyData,
} from './tracker';

export {
  renderDailyView,
  renderWeeklyView,
} from './render';

export { renderWeeklyChart } from './chart';

