{
  "name": "@node/expense-logger",
  "version": "1.0.0",
  "description": "Track expenses by category with monthly summaries, pie charts, filtering, and CSV export",
  "modnet": {
    "contentType": "finance",
    "structure": "collection",
    "mechanics": ["filter", "chart", "track"],
    "boundary": "none",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type Category = 'food' | 'transport' | 'housing' | 'entertainment' | 'utilities' | 'other';

export const CATEGORIES: Category[] = ['food', 'transport', 'housing', 'entertainment', 'utilities', 'other'];

export type Expense = {
  id: string;
  amount: number;
  category: Category;
  date: string; // ISO 8601 date string YYYY-MM-DD
  notes: string;
  createdAt: string; // ISO 8601 datetime
};

export type ExpenseInput = {
  amount: number;
  category: Category;
  date: string;
  notes?: string;
};

export type DateRange = {
  start: string; // YYYY-MM-DD
  end: string;   // YYYY-MM-DD
};

export type ExpenseFilter = {
  dateRange?: DateRange;
  category?: Category;
};

export type CategorySummary = {
  category: Category;
  total: number;
  count: number;
  percentage: number;
};

export type MonthlySummary = {
  month: string; // YYYY-MM
  total: number;
  categories: CategorySummary[];
};

export const CATEGORY_COLORS: Record<Category, string> = {
  food: '#ef4444',
  transport: '#3b82f6',
  housing: '#22c55e',
  entertainment: '#a855f7',
  utilities: '#f59e0b',
  other: '#6b7280',
};

export const CATEGORY_LABELS: Record<Category, string> = {
  food: 'Food',
  transport: 'Transport',
  housing: 'Housing',
  entertainment: 'Entertainment',
  utilities: 'Utilities',
  other: 'Other',
};

import type { Expense } from './types';

const DATA_PATH = new URL('./data/expenses.jsonl', import.meta.url).pathname;

export const readExpenses = async (): Promise<Expense[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];

  const text = await file.text();
  return text
    .split('\n')
    .filter((line) => line.trim().length > 0)
    .map((line) => JSON.parse(line) as Expense);
};

export const appendExpense = async (expense: Expense): Promise<void> => {
  const line = JSON.stringify(expense) + '\n';
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  const existing = exists ? await file.text() : '';
  await Bun.write(DATA_PATH, existing + line);
};

export const writeAllExpenses = async (expenses: Expense[]): Promise<void> => {
  const content = expenses.map((e) => JSON.stringify(e)).join('\n') + (expenses.length > 0 ? '\n' : '');
  await Bun.write(DATA_PATH, content);
};

export const deleteExpense = async (id: string): Promise<boolean> => {
  const expenses = await readExpenses();
  const filtered = expenses.filter((e) => e.id !== id);
  if (filtered.length === expenses.length) return false;
  await writeAllExpenses(filtered);
  return true;
};

import type { Expense, ExpenseInput, ExpenseFilter, MonthlySummary, CategorySummary, Category } from './types';
import { CATEGORIES } from './types';
import { readExpenses, appendExpense, deleteExpense } from './store';

const generateId = (): string => crypto.randomUUID();

export const addExpense = async (input: ExpenseInput): Promise<Expense> => {
  const expense: Expense = {
    id: generateId(),
    amount: Math.round(input.amount * 100) / 100,
    category: input.category,
    date: input.date,
    notes: input.notes ?? '',
    createdAt: new Date().toISOString(),
  };
  await appendExpense(expense);
  return expense;
};

export const removeExpense = async (id: string): Promise<boolean> => {
  return deleteExpense(id);
};

export const getExpenses = async (filter?: ExpenseFilter): Promise<Expense[]> => {
  const all = await readExpenses();
  return applyFilter(all, filter);
};

export const applyFilter = (expenses: Expense[], filter?: ExpenseFilter): Expense[] => {
  if (!filter) return expenses;

  let result = expenses;

  if (filter.category) {
    result = result.filter((e) => e.category === filter.category);
  }

  if (filter.dateRange) {
    const { start, end } = filter.dateRange;
    result = result.filter((e) => e.date >= start && e.date <= end);
  }

  return result;
};

export const getMonthlySummary = (expenses: Expense[], month: string): MonthlySummary => {
  const monthExpenses = expenses.filter((e) => e.date.startsWith(month));
  const total = monthExpenses.reduce((sum, e) => sum + e.amount, 0);

  const categoryTotals = new Map<Category, { total: number; count: number }>();
  for (const cat of CATEGORIES) {
    categoryTotals.set(cat, { total: 0, count: 0 });
  }

  for (const expense of monthExpenses) {
    const entry = categoryTotals.get(expense.category)!;
    entry.total += expense.amount;
    entry.count += 1;
  }

  const categories: CategorySummary[] = CATEGORIES
    .map((category) => {
      const entry = categoryTotals.get(category)!;
      return {
        category,
        total: Math.round(entry.total * 100) / 100,
        count: entry.count,
        percentage: total > 0 ? Math.round((entry.total / total) * 1000) / 10 : 0,
      };
    })
    .filter((c) => c.count > 0);

  return {
    month,
    total: Math.round(total * 100) / 100,
    categories,
  };
};

export const getAvailableMonths = (expenses: Expense[]): string[] => {
  const months = new Set(expenses.map((e) => e.date.substring(0, 7)));
  return [...months].sort().reverse();
};

import { h } from 'plaited';
import type { CategorySummary } from './types';
import { CATEGORY_COLORS, CATEGORY_LABELS } from './types';

type PieSlice = {
  category: CategorySummary['category'];
  percentage: number;
  startAngle: number;
  endAngle: number;
  color: string;
};

const degreesToRadians = (deg: number): number => (deg * Math.PI) / 180;

const describeArc = (cx: number, cy: number, r: number, startAngle: number, endAngle: number): string => {
  const start = {
    x: cx + r * Math.cos(degreesToRadians(startAngle)),
    y: cy + r * Math.sin(degreesToRadians(startAngle)),
  };
  const end = {
    x: cx + r * Math.cos(degreesToRadians(endAngle)),
    y: cy + r * Math.sin(degreesToRadians(endAngle)),
  };
  const largeArc = endAngle - startAngle > 180 ? 1 : 0;
  return `M ${cx} ${cy} L ${start.x} ${start.y} A ${r} ${r} 0 ${largeArc} 1 ${end.x} ${end.y} Z`;
};

const buildSlices = (categories: CategorySummary[]): PieSlice[] => {
  const slices: PieSlice[] = [];
  let currentAngle = -90;

  for (const cat of categories) {
    const sweepAngle = (cat.percentage / 100) * 360;
    slices.push({
      category: cat.category,
      percentage: cat.percentage,
      startAngle: currentAngle,
      endAngle: currentAngle + sweepAngle,
      color: CATEGORY_COLORS[cat.category],
    });
    currentAngle += sweepAngle;
  }

  return slices;
};

export const renderPieChart = (categories: CategorySummary[]): string => {
  if (categories.length === 0) {
    return h(
      'div',
      { style: 'text-align:center;padding:40px;color:#9ca3af;' },
      h('p', {}, 'No expenses to display'),
    ) as unknown as string;
  }

  const cx = 100;
  const cy = 100;
  const r = 90;
  const slices = buildSlices(categories);

  // Handle single-category case (full circle)
  const svgChildren = slices.length === 1
    ? [
        h('circle', {
          cx: String(cx),
          cy: String(cy),
          r: String(r),
          fill: slices[0].color,
        }),
      ]
    : slices.map((slice) =>
        h('path', {
          d: describeArc(cx, cy, r, slice.startAngle, slice.endAngle),
          fill: slice.color,
        }),
      );

  const chart = h(
    'svg',
    {
      viewBox: '0 0 200 200',
      width: '200',
      height: '200',
      style: 'display:block;margin:0 auto;',
    },
    ...svgChildren,
  );

  const legendItems = categories.map((cat) =>
    h(
      'div',
      {
        style: 'display:flex;align-items:center;gap:8px;margin-bottom:4px;',
      },
      h('span', {
        style: `display:inline-block;width:12px;height:12px;border-radius:2px;background:${CATEGORY_COLORS[cat.category]};`,
      }),
      h(
        'span',
        { style: 'font-size:14px;color:#374151;' },
        `${CATEGORY_LABELS[cat.category]}: $${cat.total.toFixed(2)} (${cat.percentage}%)`,
      ),
    ),
  );

  const legend = h(
    'div',
    { style: 'margin-top:16px;' },
    ...legendItems,
  );

  return h(
    'div',
    { style: 'display:flex;flex-direction:column;align-items:center;' },
    chart,
    legend,
  ) as unknown as string;
};

import type { Expense } from './types';
import { CATEGORY_LABELS } from './types';

const escapeCSVField = (value: string): string => {
  if (value.includes(',') || value.includes('"') || value.includes('\n')) {
    return `"${value.replace(/"/g, '""')}"`;
  }
  return value;
};

export const toCSV = (expenses: Expense[]): string => {
  const header = 'Date,Category,Amount,Notes';
  const sorted = [...expenses].sort((a, b) => a.date.localeCompare(b.date));

  const rows = sorted.map((e) =>
    [
      e.date,
      CATEGORY_LABELS[e.category],
      e.amount.toFixed(2),
      escapeCSVField(e.notes),
    ].join(','),
  );

  return [header, ...rows].join('\n');
};

export const exportToFile = async (expenses: Expense[], filename?: string): Promise<string> => {
  const name = filename ?? `expenses-${new Date().toISOString().substring(0, 10)}.csv`;
  const csv = toCSV(expenses);
  const outPath = new URL(`./data/${name}`, import.meta.url).pathname;
  await Bun.write(outPath, csv);
  return outPath;
};

