import { toCSV, exportToFile } from './export';
import {
  renderExpenseForm,
  renderFilterBar,
  renderExpenseList,
  renderMonthlySummary,
  renderExportButton,
} from './views';

export type { Category, Expense, ExpenseInput, ExpenseFilter, MonthlySummary } from './types';
export { CATEGORIES, CATEGORY_LABELS, CATEGORY_COLORS } from './types';
export { addExpense, removeExpense, getExpenses, getMonthlySummary, getAvailableMonths } from './expenses';
export { toCSV, exportToFile } from './export';

const isValidCategory = (value: string): value is Category =>
  CATEGORIES.includes(value as Category);

const parseExpenseInput = (formData: Record<string, string>): ExpenseInput | null => {
  const amount = parseFloat(formData.amount);
  if (isNaN(amount) || amount <= 0) return null;

  const category = formData.category;
  if (!isValidCategory(category)) return null;

  const date = formData.date;
  if (!/^\d{4}-\d{2}-\d{2}$/.test(date)) return null;

  return {
    amount,
    category,
    date,
    notes: formData.notes || undefined,
  };
};

const parseFilter = (formData: Record<string, string>): ExpenseFilter => {
  const filter: ExpenseFilter = {};

  if (formData.category && isValidCategory(formData.category)) {
    filter.category = formData.category;
  }

  if (formData.startDate && formData.endDate) {
    filter.dateRange = {
      start: formData.startDate,
      end: formData.endDate,
    };
  }

  return filter;
};

export const handleAddExpense = async (formData: Record<string, string>) => {
  const input = parseExpenseInput(formData);
  if (!input) {
    return { success: false, error: 'Invalid expense data' };
  }
  const expense = await addExpense(input);
  return { success: true, expense };
};

export const handleDeleteExpense = async (id: string) => {
  const removed = await removeExpense(id);
  return { success: removed };
};

export const handleFilter = async (formData: Record<string, string>) => {
  const filter = parseFilter(formData);
  const expenses = await getExpenses(filter);
  return { expenses, filter };
};

export const handleExport = async (filter?: ExpenseFilter) => {
  const expenses = await getExpenses(filter);
  const filePath = await exportToFile(expenses);
  const csv = toCSV(expenses);
  return { filePath, csv, count: expenses.length };
};

export const renderApp = async (filter?: ExpenseFilter, selectedMonth?: string): Promise<string> => {
  const allExpenses = await getExpenses();
  const filteredExpenses = filter ? applyFilter(allExpenses, filter) : allExpenses;
  const months = getAvailableMonths(allExpenses);
  const currentMonth = selectedMonth ?? months[0] ?? new Date().toISOString().substring(0, 7);
  const summary = getMonthlySummary(filteredExpenses, currentMonth);

  const monthSelector = months.length > 0
    ? h(
        'select',
        {
          name: 'month',
          'p-trigger': 'change:selectMonth',
          style: 'padding:8px;border:1px solid #d1d5db;border-radius:6px;font-size:14px;',
        },
        ...months.map((m) =>
          h(
            'option',
            {
              value: m,
              ...(m === currentMonth ? { selected: 'selected' } : {}),
            },
            new Date(m + '-01').toLocaleDateString('en-US', { year: 'numeric', month: 'long' }),
          ),
        ),
      )
    : '';

  return h(
    'div',
    {
      'p-target': 'expenseApp',
      style: 'max-width:800px;margin:0 auto;padding:24px;font-family:system-ui,-apple-system,sans-serif;display:flex;flex-direction:column;gap:24px;',
    },
    h(
      'header',
      { style: 'display:flex;justify-content:space-between;align-items:center;' },
      h('h1', { style: 'margin:0;font-size:24px;color:#111827;' }, 'Expense Logger'),
      h(
        'div',
        { style: 'display:flex;gap:8px;align-items:center;' },
        monthSelector,
        renderExportButton(),
      ),
    ),
    renderExpenseForm(),
    renderFilterBar(filter),
    h(
      'section',
      {},
      h('h2', { style: 'font-size:16px;color:#6b7280;margin:0 0 12px 0;' }, 'Monthly Summary'),
      renderMonthlySummary(summary),
    ),
    h(
      'section',
      {},
      h(
        'h2',
        { style: 'font-size:16px;color:#6b7280;margin:0 0 12px 0;' },
        `Expenses (${filteredExpenses.length})`,
      ),
      renderExpenseList(filteredExpenses),
    ),
  ) as unknown as string;
};

