import type { InventoryItem, NewItemInput, BulkImportInput } from './types'

const DATA_PATH = `${import.meta.dir}/data/inventory.jsonl`

const generateId = (): string => crypto.randomUUID()

const timestamp = (): string => new Date().toISOString()

export const readAll = async (): Promise<InventoryItem[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) return []
  const text = await file.text()
  if (!text.trim()) return []
  return text
    .trim()
    .split('\n')
    .map((line) => JSON.parse(line) as InventoryItem)
}

const writeAll = async (items: InventoryItem[]): Promise<void> => {
  const content = items.map((item) => JSON.stringify(item)).join('\n')
  await Bun.write(DATA_PATH, content ? content + '\n' : '')
}

export const addItem = async (input: NewItemInput): Promise<InventoryItem> => {
  const items = await readAll()
  const existing = items.find((i) => i.sku === input.sku)
  if (existing) {
    throw new Error(`Item with SKU "${input.sku}" already exists`)
  }
  const now = timestamp()
  const item: InventoryItem = {
    id: generateId(),
    name: input.name,
    sku: input.sku,
    quantity: input.quantity,
    category: input.category,
    reorderThreshold: input.reorderThreshold,
    createdAt: now,
    updatedAt: now,
  }
  items.push(item)
  await writeAll(items)
  return item
}

export const updateItem = async (
  sku: string,
  updates: Partial<Omit<InventoryItem, 'id' | 'sku' | 'createdAt' | 'updatedAt'>>,
): Promise<InventoryItem> => {
  const items = await readAll()
  const index = items.findIndex((i) => i.sku === sku)
  if (index === -1) {
    throw new Error(`Item with SKU "${sku}" not found`)
  }
  items[index] = {
    ...items[index],
    ...updates,
    updatedAt: timestamp(),
  }
  await writeAll(items)
  return items[index]
}

export const removeItem = async (sku: string): Promise<boolean> => {
  const items = await readAll()
  const filtered = items.filter((i) => i.sku !== sku)
  if (filtered.length === items.length) return false
  await writeAll(filtered)
  return true
}

export const adjustQuantity = async (sku: string, delta: number): Promise<InventoryItem> => {
  const items = await readAll()
  const index = items.findIndex((i) => i.sku === sku)
  if (index === -1) {
    throw new Error(`Item with SKU "${sku}" not found`)
  }
  const newQty = items[index].quantity + delta
  if (newQty < 0) {
    throw new Error(`Cannot reduce quantity below 0 (current: ${items[index].quantity}, delta: ${delta})`)
  }
  items[index] = {
    ...items[index],
    quantity: newQty,
    updatedAt: timestamp(),
  }
  await writeAll(items)
  return items[index]
}

export const bulkImport = async (
  inputs: BulkImportInput[],
): Promise<{ created: number; updated: number }> => {
  const items = await readAll()
  const bySku = new Map(items.map((i) => [i.sku, i]))
  let created = 0
  let updated = 0

  for (const input of inputs) {
    const existing = bySku.get(input.sku)
    const now = timestamp()
    if (existing) {
      bySku.set(input.sku, {
        ...existing,
        name: input.name,
        quantity: input.quantity,
        category: input.category,
        reorderThreshold: input.reorderThreshold,
        updatedAt: now,
      })
      updated++
    } else {
      bySku.set(input.sku, {
        id: generateId(),
        name: input.name,
        sku: input.sku,
        quantity: input.quantity,
        category: input.category,
        reorderThreshold: input.reorderThreshold,
        createdAt: now,
        updatedAt: now,
      })
      created++
    }
  }

  await writeAll([...bySku.values()])
  return { created, updated }
}

export const getItemBySku = async (sku: string): Promise<InventoryItem | undefined> => {
  const items = await readAll()
  return items.find((i) => i.sku === sku)
}

import type { InventoryItem, SearchQuery } from './types'
import { readAll } from './store'

export const search = async (query: SearchQuery): Promise<InventoryItem[]> => {
  const items = await readAll()
  const term = query.term.toLowerCase().trim()
  if (!term) return items

  const field = query.field ?? 'all'

  return items.filter((item) => {
    if (field === 'sku') {
      return item.sku.toLowerCase() === term
    }
    if (field === 'name') {
      return item.name.toLowerCase().includes(term)
    }
    return item.name.toLowerCase().includes(term) || item.sku.toLowerCase() === term
  })
}

export const searchByCategory = async (category: string): Promise<InventoryItem[]> => {
  const items = await readAll()
  const lc = category.toLowerCase().trim()
  return items.filter((item) => item.category.toLowerCase() === lc)
}

export const searchByBarcode = async (barcode: string): Promise<InventoryItem | undefined> => {
  const items = await readAll()
  const trimmed = barcode.trim()
  return items.find((item) => item.sku === trimmed)
}

import type { InventoryItem, DashboardStats } from './types'
import { readAll } from './store'

export const getDashboardStats = async (): Promise<DashboardStats> => {
  const items = await readAll()
  return computeStats(items)
}

export const computeStats = (items: InventoryItem[]): DashboardStats => {
  const totalItems = items.length
  const totalQuantity = items.reduce((sum, i) => sum + i.quantity, 0)
  const lowStockItems = items.filter((i) => i.quantity <= i.reorderThreshold)
  const categoryBreakdown: Record<string, number> = {}

  for (const item of items) {
    categoryBreakdown[item.category] = (categoryBreakdown[item.category] ?? 0) + 1
  }

  return { totalItems, totalQuantity, lowStockItems, categoryBreakdown }
}

export const getLowStockItems = async (): Promise<InventoryItem[]> => {
  const items = await readAll()
  return items
    .filter((i) => i.quantity <= i.reorderThreshold)
    .sort((a, b) => a.quantity - a.reorderThreshold - (b.quantity - b.reorderThreshold))
}

