const renderStockBadge = (quantity: number, threshold: number) => {
  if (quantity === 0) {
    return h('span', { style: styles.criticalBadge }, 'OUT OF STOCK')
  }
  if (quantity <= threshold) {
    return h('span', { style: styles.warningBadge }, `Low: ${quantity}/${threshold}`)
  }
  return h('span', {}, `${quantity}`)
}

const renderRowStyle = (quantity: number, threshold: number) => {
  if (quantity === 0) return { ...styles.td, ...styles.rowCritical }
  if (quantity <= threshold) return { ...styles.td, ...styles.rowLow }
  return styles.td
}

