import { readAll, addItem, removeItem, adjustQuantity, bulkImport, getItemBySku } from './store'
import { search, searchByBarcode } from './search'
import { getDashboardStats } from './dashboard'
import { renderDashboard } from './render'
import { createSSR } from 'plaited'
import type { NewItemInput, BulkImportInput } from './types'

const ssr = createSSR()

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => {
  const text = await req.text()
  return JSON.parse(text) as T
}

export const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    // Dashboard HTML
    if (url.pathname === '/' && method === 'GET') {
      const [stats, items] = await Promise.all([getDashboardStats(), readAll()])
      const template = renderDashboard(stats, items)
      const html = ssr(template)
      return htmlResponse(`<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Inventory Manager</title>
</head>
<body style="margin:0;background:#fff">
  ${html}
</body>
</html>`)
    }

    // API: List all items
    if (url.pathname === '/api/items' && method === 'GET') {
      const items = await readAll()
      return jsonResponse(items)
    }

    // API: Add item
    if (url.pathname === '/api/items' && method === 'POST') {
      const body = await parseBody<NewItemInput>(req)
      const item = await addItem(body)
      return jsonResponse(item, 201)
    }

    // API: Search
    if (url.pathname === '/api/search' && method === 'GET') {
      const term = url.searchParams.get('q') ?? ''
      const field = (url.searchParams.get('field') as 'name' | 'sku' | 'all') ?? 'all'
      const results = await search({ term, field })
      return jsonResponse(results)
    }

    // API: Barcode lookup
    if (url.pathname === '/api/barcode' && method === 'GET') {
      const code = url.searchParams.get('code') ?? ''
      const item = await searchByBarcode(code)
      if (!item) return jsonResponse({ error: 'Item not found' }, 404)
      return jsonResponse(item)
    }

    // API: Get single item by SKU
    if (url.pathname.startsWith('/api/items/') && method === 'GET') {
      const sku = decodeURIComponent(url.pathname.slice('/api/items/'.length))
      const item = await getItemBySku(sku)
      if (!item) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse(item)
    }

    // API: Adjust quantity
    if (url.pathname.startsWith('/api/items/') && url.pathname.endsWith('/quantity') && method === 'PATCH') {
      const sku = decodeURIComponent(url.pathname.slice('/api/items/'.length, -'/quantity'.length))
      const { delta } = await parseBody<{ delta: number }>(req)
      const item = await adjustQuantity(sku, delta)
      return jsonResponse(item)
    }

    // API: Remove item
    if (url.pathname.startsWith('/api/items/') && method === 'DELETE') {
      const sku = decodeURIComponent(url.pathname.slice('/api/items/'.length))
      const removed = await removeItem(sku)
      if (!removed) return jsonResponse({ error: 'Not found' }, 404)
      return jsonResponse({ success: true })
    }

    // API: Bulk import
    if (url.pathname === '/api/import' && method === 'POST') {
      const items = await parseBody<BulkImportInput[]>(req)
      const result = await bulkImport(items)
      return jsonResponse(result)
    }

    // API: Dashboard stats
    if (url.pathname === '/api/dashboard' && method === 'GET') {
      const stats = await getDashboardStats()
      return jsonResponse(stats)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

