import type { Book, BookInput, ReadingListData, ReadingStatus, FilterOptions, ReadingStats } from './types'

const DATA_PATH = `${import.meta.dir}/data/reading-list.json`

const generateId = (): string => crypto.randomUUID()

export const loadData = async (): Promise<ReadingListData> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    return { books: [] }
  }
  return file.json()
}

export const saveData = async (data: ReadingListData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const addBook = async (input: BookInput): Promise<Book> => {
  const data = await loadData()
  const book: Book = {
    id: generateId(),
    title: input.title,
    author: input.author,
    genre: input.genre,
    pageCount: input.pageCount,
    currentPage: 0,
    coverUrl: input.coverUrl ?? '',
    status: 'want-to-read',
    dateAdded: new Date().toISOString(),
    dateCompleted: null,
  }
  data.books.push(book)
  await saveData(data)
  return book
}

export const removeBook = async (id: string): Promise<boolean> => {
  const data = await loadData()
  const index = data.books.findIndex((b) => b.id === id)
  if (index === -1) return false
  data.books.splice(index, 1)
  await saveData(data)
  return true
}

export const updateProgress = async (id: string, currentPage: number): Promise<Book | null> => {
  const data = await loadData()
  const book = data.books.find((b) => b.id === id)
  if (!book) return null
  book.currentPage = Math.max(0, Math.min(currentPage, book.pageCount))
  if (book.currentPage === book.pageCount) {
    book.status = 'completed'
    book.dateCompleted = new Date().toISOString()
  } else if (book.currentPage > 0 && book.status === 'want-to-read') {
    book.status = 'reading'
  }
  await saveData(data)
  return book
}

export const updateStatus = async (id: string, status: ReadingStatus): Promise<Book | null> => {
  const data = await loadData()
  const book = data.books.find((b) => b.id === id)
  if (!book) return null
  book.status = status
  if (status === 'completed') {
    book.currentPage = book.pageCount
    book.dateCompleted = new Date().toISOString()
  } else {
    book.dateCompleted = null
  }
  await saveData(data)
  return book
}

export const getFilteredBooks = async (filters: FilterOptions): Promise<Book[]> => {
  const data = await loadData()
  let books = data.books
  if (filters.status) {
    books = books.filter((b) => b.status === filters.status)
  }
  if (filters.genre) {
    books = books.filter((b) => b.genre.toLowerCase() === filters.genre!.toLowerCase())
  }
  return books
}

export const getStats = async (): Promise<ReadingStats> => {
  const data = await loadData()
  const { books } = data
  const totalBooks = books.length
  const booksCompleted = books.filter((b) => b.status === 'completed').length
  const booksReading = books.filter((b) => b.status === 'reading').length
  const booksWantToRead = books.filter((b) => b.status === 'want-to-read').length
  const totalPagesRead = books.reduce((sum, b) => sum + b.currentPage, 0)
  const averageProgress =
    totalBooks > 0
      ? Math.round(books.reduce((sum, b) => sum + (b.pageCount > 0 ? (b.currentPage / b.pageCount) * 100 : 0), 0) / totalBooks)
      : 0
  return { totalBooks, booksCompleted, booksReading, booksWantToRead, totalPagesRead, averageProgress }
}

export const getGenres = async (): Promise<string[]> => {
  const data = await loadData()
  const genres = new Set(data.books.map((b) => b.genre))
  return [...genres].sort()
}

