import { createSSR } from 'plaited'
import {
  loadData,
  addBook,
  removeBook,
  updateProgress,
  updateStatus,
  getFilteredBooks,
  getStats,
  getGenres,
} from './store'
import { renderReadingList } from './render'
import type { BookInput, ReadingStatus, FilterOptions } from './types'

const ssr = createSSR()

const renderPage = async (filters: FilterOptions = {}, showForm = false) => {
  const [books, stats, genres] = await Promise.all([
    getFilteredBooks(filters),
    getStats(),
    getGenres(),
  ])
  const template = renderReadingList(books, stats, genres, {
    showForm,
    activeStatus: filters.status,
    activeGenre: filters.genre,
  })
  return ssr(template)
}

const parseFiltersFromUrl = (url: URL): FilterOptions => {
  const status = url.searchParams.get('status') as ReadingStatus | null
  const genre = url.searchParams.get('genre')
  return {
    ...(status ? { status } : {}),
    ...(genre ? { genre } : {}),
  }
}

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export default {
  port: 3000,

  fetch: async (req: Request): Promise<Response> => {
    const url = new URL(req.url)
    const { pathname } = url
    const method = req.method

    // GET / — render the full reading list page
    if (method === 'GET' && pathname === '/') {
      const filters = parseFiltersFromUrl(url)
      const showForm = url.searchParams.get('add') === 'true'
      const html = await renderPage(filters, showForm)
      return htmlResponse(html)
    }

    // GET /api/books — list books with optional filters
    if (method === 'GET' && pathname === '/api/books') {
      const filters = parseFiltersFromUrl(url)
      const books = await getFilteredBooks(filters)
      return jsonResponse(books)
    }

    // GET /api/stats — get reading stats
    if (method === 'GET' && pathname === '/api/stats') {
      const stats = await getStats()
      return jsonResponse(stats)
    }

    // POST /api/books — add a new book
    if (method === 'POST' && pathname === '/api/books') {
      const body = (await req.json()) as BookInput
      if (!body.title || !body.author || !body.genre || !body.pageCount) {
        return jsonResponse({ error: 'Missing required fields: title, author, genre, pageCount' }, 400)
      }
      const book = await addBook(body)
      return jsonResponse(book, 201)
    }

    // PATCH /api/books/:id/progress — update reading progress
    if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/progress$/)) {
      const id = pathname.split('/')[3]
      const { currentPage } = (await req.json()) as { currentPage: number }
      if (typeof currentPage !== 'number') {
        return jsonResponse({ error: 'currentPage must be a number' }, 400)
      }
      const book = await updateProgress(id, currentPage)
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse(book)
    }

    // PATCH /api/books/:id/status — update reading status
    if (method === 'PATCH' && pathname.match(/^\/api\/books\/[^/]+\/status$/)) {
      const id = pathname.split('/')[3]
      const { status } = (await req.json()) as { status: ReadingStatus }
      const validStatuses: ReadingStatus[] = ['want-to-read', 'reading', 'completed']
      if (!validStatuses.includes(status)) {
        return jsonResponse({ error: 'status must be: want-to-read, reading, or completed' }, 400)
      }
      const book = await updateStatus(id, status)
      if (!book) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse(book)
    }

    // DELETE /api/books/:id — remove a book
    if (method === 'DELETE' && pathname.match(/^\/api\/books\/[^/]+$/)) {
      const id = pathname.split('/')[3]
      const removed = await removeBook(id)
      if (!removed) return jsonResponse({ error: 'Book not found' }, 404)
      return jsonResponse({ success: true })
    }

    // GET /api/genres — list all genres
    if (method === 'GET' && pathname === '/api/genres') {
      const genres = await getGenres()
      return jsonResponse(genres)
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
}

