import { BskyAgent } from '@atproto/api'
import type { LoginCredentials, SessionData } from './types'

const SESSION_PATH = './data/session.json'

export const createAgent = (): BskyAgent => {
  return new BskyAgent({ service: 'https://bsky.social' })
}

export const persistSession = async (session: SessionData): Promise<void> => {
  await Bun.write(SESSION_PATH, JSON.stringify(session, null, 2))
}

export const loadSession = async (): Promise<SessionData | null> => {
  const file = Bun.file(SESSION_PATH)
  if (!(await file.exists())) return null
  try {
    return await file.json() as SessionData
  } catch {
    return null
  }
}

export const login = async (
  agent: BskyAgent,
  credentials: LoginCredentials
): Promise<SessionData> => {
  const response = await agent.login({
    identifier: credentials.identifier,
    password: credentials.password,
  })

  const session: SessionData = {
    did: response.data.did,
    handle: response.data.handle,
    accessJwt: response.data.accessJwt,
    refreshJwt: response.data.refreshJwt,
  }

  await persistSession(session)
  return session
}

export const resumeSession = async (
  agent: BskyAgent
): Promise<SessionData | null> => {
  const session = await loadSession()
  if (!session) return null

  try {
    await agent.resumeSession({
      did: session.did,
      handle: session.handle,
      accessJwt: session.accessJwt,
      refreshJwt: session.refreshJwt,
      active: true,
    })
    return session
  } catch {
    return null
  }
}

export const logout = async (): Promise<void> => {
  const file = Bun.file(SESSION_PATH)
  if (await file.exists()) {
    await Bun.write(SESSION_PATH, '{}')
  }
}

import type { BskyAgent } from '@atproto/api'
import type { TimelineParams, TimelineResponse, FeedPostView } from './types'

export const getTimeline = async (
  agent: BskyAgent,
  params: TimelineParams = {}
): Promise<TimelineResponse> => {
  const response = await agent.getTimeline({
    cursor: params.cursor,
    limit: params.limit ?? 25,
  })

  const posts: FeedPostView[] = response.data.feed.map((item) => {
    const post = item.post
    const record = post.record as { text: string; createdAt: string }

    return {
      uri: post.uri,
      cid: post.cid,
      author: {
        did: post.author.did,
        handle: post.author.handle,
        displayName: post.author.displayName,
        avatar: post.author.avatar,
      },
      record: {
        text: record.text,
        createdAt: record.createdAt,
      },
      likeCount: post.likeCount ?? 0,
      repostCount: post.repostCount ?? 0,
      replyCount: post.replyCount ?? 0,
      viewer: {
        like: post.viewer?.like,
        repost: post.viewer?.repost,
      },
    }
  })

  return {
    cursor: response.data.cursor,
    posts,
  }
}

export const getAuthorFeed = async (
  agent: BskyAgent,
  actor: string,
  params: TimelineParams = {}
): Promise<TimelineResponse> => {
  const response = await agent.getAuthorFeed({
    actor,
    cursor: params.cursor,
    limit: params.limit ?? 25,
  })

  const posts: FeedPostView[] = response.data.feed.map((item) => {
    const post = item.post
    const record = post.record as { text: string; createdAt: string }

    return {
      uri: post.uri,
      cid: post.cid,
      author: {
        did: post.author.did,
        handle: post.author.handle,
        displayName: post.author.displayName,
        avatar: post.author.avatar,
      },
      record: {
        text: record.text,
        createdAt: record.createdAt,
      },
      likeCount: post.likeCount ?? 0,
      repostCount: post.repostCount ?? 0,
      replyCount: post.replyCount ?? 0,
      viewer: {
        like: post.viewer?.like,
        repost: post.viewer?.repost,
      },
    }
  })

  return {
    cursor: response.data.cursor,
    posts,
  }
}

import type { BskyAgent } from '@atproto/api'
import type { CreatePostParams } from './types'

export const createPost = async (
  agent: BskyAgent,
  params: CreatePostParams
): Promise<{ uri: string; cid: string }> => {
  const record: Record<string, unknown> = {
    text: params.text,
    createdAt: new Date().toISOString(),
  }

  if (params.replyTo) {
    record.reply = {
      root: { uri: params.replyTo.uri, cid: params.replyTo.cid },
      parent: { uri: params.replyTo.uri, cid: params.replyTo.cid },
    }
  }

  const response = await agent.post(record as Parameters<typeof agent.post>[0])

  return {
    uri: response.uri,
    cid: response.cid,
  }
}

