import type { Message, Room, ReadReceipt } from './types'

const DATA_DIR = `${import.meta.dir}/data`

const roomsPath = `${DATA_DIR}/rooms.json`
const readReceiptsPath = `${DATA_DIR}/read-receipts.json`

const messagesPath = (roomId: string) => `${DATA_DIR}/messages-${roomId}.jsonl`

// --- Rooms ---

export const loadRooms = async (): Promise<Room[]> => {
  const file = Bun.file(roomsPath)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as Room[]
}

export const saveRooms = async (rooms: Room[]): Promise<void> => {
  await Bun.write(roomsPath, JSON.stringify(rooms, null, 2))
}

// --- Messages ---

export const loadMessages = async (roomId: string): Promise<Message[]> => {
  const file = Bun.file(messagesPath(roomId))
  if (!(await file.exists())) return []
  const text = await file.text()
  return text
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => JSON.parse(line) as Message)
}

export const appendMessage = async (message: Message): Promise<void> => {
  const file = Bun.file(messagesPath(message.roomId))
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(messagesPath(message.roomId), existing + JSON.stringify(message) + '\n')
}

// --- Read Receipts ---

export const loadReadReceipts = async (): Promise<ReadReceipt[]> => {
  const file = Bun.file(readReceiptsPath)
  if (!(await file.exists())) return []
  const text = await file.text()
  return JSON.parse(text) as ReadReceipt[]
}

export const saveReadReceipts = async (receipts: ReadReceipt[]): Promise<void> => {
  await Bun.write(readReceiptsPath, JSON.stringify(receipts, null, 2))
}

import { h } from 'plaited'
import type { TemplateObject } from 'plaited'

/**
 * Parses markdown-style bold (**text**) and italic (*text*) into
 * plaited template nodes. Processes bold first to avoid conflicts.
 */
export const formatMessageText = (text: string): TemplateObject => {
  const segments: (string | TemplateObject)[] = []
  let remaining = text

  const boldRe = /\*\*(.+?)\*\*/g
  const parts = remaining.split(boldRe)

  // split yields: [before, captured, between, captured, after, ...]
  const afterBold: (string | TemplateObject)[] = []
  for (let i = 0; i < parts.length; i++) {
    if (i % 2 === 1) {
      afterBold.push(h('strong', {}, parts[i]))
    } else {
      afterBold.push(parts[i])
    }
  }

  // Now process italic on the string segments
  for (const segment of afterBold) {
    if (typeof segment !== 'string') {
      segments.push(segment)
      continue
    }
    const italicRe = /\*(.+?)\*/g
    const italicParts = segment.split(italicRe)
    for (let i = 0; i < italicParts.length; i++) {
      if (i % 2 === 1) {
        segments.push(h('em', {}, italicParts[i]))
      } else if (italicParts[i]) {
        segments.push(italicParts[i])
      }
    }
  }

  return h('span', {}, ...segments)
}

import type { Room, RoomWithUnread } from './types'
import { loadRooms, saveRooms, loadMessages, loadReadReceipts } from './store'

export const createRoom = async (name: string): Promise<Room> => {
  const rooms = await loadRooms()
  const room: Room = {
    id: crypto.randomUUID(),
    name,
    createdAt: Date.now(),
  }
  rooms.push(room)
  await saveRooms(rooms)
  return room
}

export const getRoom = async (roomId: string): Promise<Room | undefined> => {
  const rooms = await loadRooms()
  return rooms.find((r) => r.id === roomId)
}

export const listRooms = async (userId?: string): Promise<RoomWithUnread[]> => {
  const rooms = await loadRooms()
  const receipts = await loadReadReceipts()

  const result: RoomWithUnread[] = []

  for (const room of rooms) {
    const messages = await loadMessages(room.id)
    const lastMessage = messages.length > 0 ? messages[messages.length - 1] : null

    let unreadCount = 0
    if (userId) {
      const receipt = receipts.find(
        (r) => r.roomId === room.id && r.userId === userId
      )
      const lastRead = receipt?.lastReadTimestamp ?? 0
      unreadCount = messages.filter((m) => m.timestamp > lastRead).length
    }

    result.push({ ...room, unreadCount, lastMessage })
  }

  return result
}

export const deleteRoom = async (roomId: string): Promise<boolean> => {
  const rooms = await loadRooms()
  const filtered = rooms.filter((r) => r.id !== roomId)
  if (filtered.length === rooms.length) return false
  await saveRooms(filtered)
  return true
}

import type { Message, TypingState } from './types'
import { loadMessages, appendMessage, loadReadReceipts, saveReadReceipts } from './store'

// In-memory typing indicators (ephemeral, not persisted)
const typingUsers: Map<string, TypingState[]> = new Map()

const TYPING_TIMEOUT_MS = 5_000

export const postMessage = async (
  roomId: string,
  sender: string,
  text: string
): Promise<Message> => {
  const message: Message = {
    id: crypto.randomUUID(),
    roomId,
    sender,
    text,
    timestamp: Date.now(),
  }
  await appendMessage(message)
  // Clear typing state for this sender
  clearTyping(roomId, sender)
  return message
}

export const getRoomMessages = async (
  roomId: string,
  limit?: number
): Promise<Message[]> => {
  const all = await loadMessages(roomId)
  if (limit && limit > 0) {
    return all.slice(-limit)
  }
  return all
}

export const markRead = async (roomId: string, userId: string): Promise<void> => {
  const receipts = await loadReadReceipts()
  const existing = receipts.find(
    (r) => r.roomId === roomId && r.userId === userId
  )
  if (existing) {
    existing.lastReadTimestamp = Date.now()
  } else {
    receipts.push({ roomId, userId, lastReadTimestamp: Date.now() })
  }
  await saveReadReceipts(receipts)
}

export const setTyping = (roomId: string, userId: string): void => {
  const roomTyping = typingUsers.get(roomId) ?? []
  const existing = roomTyping.find((t) => t.userId === userId)
  const expiresAt = Date.now() + TYPING_TIMEOUT_MS
  if (existing) {
    existing.expiresAt = expiresAt
  } else {
    roomTyping.push({ roomId, userId, expiresAt })
  }
  typingUsers.set(roomId, roomTyping)
}

export const clearTyping = (roomId: string, userId: string): void => {
  const roomTyping = typingUsers.get(roomId) ?? []
  typingUsers.set(
    roomId,
    roomTyping.filter((t) => t.userId !== userId)
  )
}

export const getTypingUsers = (roomId: string): string[] => {
  const now = Date.now()
  const roomTyping = (typingUsers.get(roomId) ?? []).filter(
    (t) => t.expiresAt > now
  )
  typingUsers.set(roomId, roomTyping)
  return roomTyping.map((t) => t.userId)
}

