    "mechanics": ["post", "reply", "vote", "sort", "filter"],
    "boundary": "all",
    "scale": 2
  },
  "dependencies": {
    "plaited": "latest"
  }
}

export type VoteDirection = 1 | -1

export type VoteRecord = {
  visitorId: string
  direction: VoteDirection
}

export type Reply = {
  id: string
  threadId: string
  body: string
  author: string
  createdAt: string
  votes: VoteRecord[]
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  createdAt: string
  votes: VoteRecord[]
  replies: Reply[]
}

export type SortMode = 'newest' | 'top' | 'active'

export type ForumData = {
  threads: Thread[]
}

export type CreateThreadInput = {
  title: string
  body: string
  author: string
}

export type CreateReplyInput = {
  threadId: string
  body: string
  author: string
}

export type VoteInput = {
  targetId: string
  threadId: string
  visitorId: string
  direction: VoteDirection
}

import type {
  ForumData,
  Thread,
  Reply,
  CreateThreadInput,
  CreateReplyInput,
  VoteInput,
  SortMode,
  VoteRecord,
} from './types'

const DATA_PATH = './data/forum.json'

const generateId = (): string => crypto.randomUUID()

const getScore = (votes: VoteRecord[]): number =>
  votes.reduce((sum, v) => sum + v.direction, 0)

const getLatestActivity = (thread: Thread): string => {
  if (thread.replies.length === 0) return thread.createdAt
  return thread.replies.reduce(
    (latest, r) => (r.createdAt > latest ? r.createdAt : latest),
    thread.createdAt,
  )
}

export const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json() as Promise<ForumData>
  }
  return { threads: [] }
}

export const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  data.threads.unshift(thread)
  await saveData(data)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find((t) => t.id === input.threadId)
  if (!thread) return null
  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const vote = async (input: VoteInput): Promise<boolean> => {
  const data = await loadData()
  const thread = data.threads.find((t) => t.id === input.threadId)
  if (!thread) return false

  let votes: VoteRecord[]
  if (input.targetId === input.threadId) {
    votes = thread.votes
  } else {
    const reply = thread.replies.find((r) => r.id === input.targetId)
    if (!reply) return false
    votes = reply.votes
  }

  const existing = votes.findIndex((v) => v.visitorId === input.visitorId)
  if (existing !== -1) {
    if (votes[existing].direction === input.direction) {
      votes.splice(existing, 1)
    } else {
      votes[existing].direction = input.direction
    }
  } else {
    votes.push({ visitorId: input.visitorId, direction: input.direction })
  }

  await saveData(data)
  return true
}

export const getThread = async (threadId: string): Promise<Thread | null> => {
  const data = await loadData()
  return data.threads.find((t) => t.id === threadId) ?? null
}

export const getThreads = async (
  sort: SortMode = 'newest',
  search?: string,
): Promise<Thread[]> => {
  const data = await loadData()
  let threads = data.threads

  if (search && search.trim()) {
    const query = search.trim().toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  const sorted = [...threads]
  switch (sort) {
    case 'newest':
      sorted.sort((a, b) => b.createdAt.localeCompare(a.createdAt))
      break
    case 'top':
      sorted.sort((a, b) => getScore(b.votes) - getScore(a.votes))
      break
    case 'active':
      sorted.sort((a, b) => getLatestActivity(b).localeCompare(getLatestActivity(a)))
      break
  }

  return sorted
}

export const deleteThread = async (threadId: string): Promise<boolean> => {
  const data = await loadData()
  const idx = data.threads.findIndex((t) => t.id === threadId)
  if (idx === -1) return false
  data.threads.splice(idx, 1)
  await saveData(data)
  return true
}

