import type { SortMode, VoteDirection } from './types'
import {
  getThreads,
  getThread,
  createThread,
  createReply,
  vote,
  deleteThread,
} from './data'
import {
  renderThreadList,
  renderThreadDetail,
  renderNewThreadForm,
} from './views'

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // --- HTML views ---

  if (method === 'GET' && path === '/') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('q') || ''
    const threads = await getThreads(sort, search)
    return htmlResponse(renderThreadList(threads, sort, search))
  }

  if (method === 'GET' && path === '/new') {
    return htmlResponse(renderNewThreadForm())
  }

  if (method === 'GET' && path.startsWith('/thread/')) {
    const threadId = path.slice('/thread/'.length)
    const thread = await getThread(threadId)
    if (!thread) return htmlResponse('<p>Thread not found</p>', 404)
    return htmlResponse(renderThreadDetail(thread))
  }

  // --- API endpoints ---

  if (method === 'GET' && path === '/api/threads') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('q') || ''
    const threads = await getThreads(sort, search)
    return jsonResponse(threads)
  }

  if (method === 'GET' && path.startsWith('/api/threads/')) {
    const threadId = path.slice('/api/threads/'.length)
    const thread = await getThread(threadId)
    if (!thread) return jsonResponse({ error: 'Thread not found' }, 404)
    return jsonResponse(thread)
  }

  if (method === 'POST' && path === '/api/threads') {
    const body = await req.json() as { title?: string; body?: string; author?: string }
    if (!body.title?.trim() || !body.body?.trim() || !body.author?.trim()) {
      return jsonResponse({ error: 'title, body, and author are required' }, 400)
    }
    const thread = await createThread({
      title: body.title.trim(),
      body: body.body.trim(),
      author: body.author.trim(),
    })
    return jsonResponse(thread, 201)
  }

  if (method === 'POST' && path === '/api/replies') {
    const body = await req.json() as { threadId?: string; body?: string; author?: string }
    if (!body.threadId?.trim() || !body.body?.trim() || !body.author?.trim()) {
      return jsonResponse({ error: 'threadId, body, and author are required' }, 400)
    }
    const reply = await createReply({
      threadId: body.threadId.trim(),
      body: body.body.trim(),
      author: body.author.trim(),
    })
    if (!reply) return jsonResponse({ error: 'Thread not found' }, 404)
    return jsonResponse(reply, 201)
  }

  if (method === 'POST' && path === '/api/vote') {
    const body = await req.json() as {
      targetId?: string
      threadId?: string
      visitorId?: string
      direction?: VoteDirection
    }
    if (!body.targetId || !body.threadId || !body.visitorId || !body.direction) {
      return jsonResponse({ error: 'targetId, threadId, visitorId, and direction are required' }, 400)
    }
    if (body.direction !== 1 && body.direction !== -1) {
      return jsonResponse({ error: 'direction must be 1 or -1' }, 400)
    }
    const success = await vote({
      targetId: body.targetId,
      threadId: body.threadId,
      visitorId: body.visitorId,
      direction: body.direction,
    })
    if (!success) return jsonResponse({ error: 'Target not found' }, 404)
    return jsonResponse({ ok: true })
  }

  if (method === 'DELETE' && path.startsWith('/api/threads/')) {
    const threadId = path.slice('/api/threads/'.length)
    const success = await deleteThread(threadId)
    if (!success) return jsonResponse({ error: 'Thread not found' }, 404)
    return jsonResponse({ ok: true })
  }

  return jsonResponse({ error: 'Not found' }, 404)
}

