const WEATHER_CONDITIONS = [
  { id: 800, main: 'Clear', description: 'clear sky', icon: '01d' },
  { id: 801, main: 'Clouds', description: 'few clouds', icon: '02d' },
  { id: 802, main: 'Clouds', description: 'scattered clouds', icon: '03d' },
  { id: 500, main: 'Rain', description: 'light rain', icon: '10d' },
  { id: 501, main: 'Rain', description: 'moderate rain', icon: '10d' },
  { id: 600, main: 'Snow', description: 'light snow', icon: '13d' },
  { id: 200, main: 'Thunderstorm', description: 'thunderstorm', icon: '11d' },
] as const

const CITY_SEEDS: Record<string, { lat: number; lon: number; baseTemp: number }> = {
  london: { lat: 51.51, lon: -0.13, baseTemp: 12 },
  'new york': { lat: 40.71, lon: -74.01, baseTemp: 15 },
  tokyo: { lat: 35.68, lon: 139.69, baseTemp: 18 },
  sydney: { lat: -33.87, lon: 151.21, baseTemp: 22 },
  paris: { lat: 48.86, lon: 2.35, baseTemp: 13 },
  berlin: { lat: 52.52, lon: 13.41, baseTemp: 10 },
  mumbai: { lat: 19.08, lon: 72.88, baseTemp: 30 },
  cairo: { lat: 30.04, lon: 31.24, baseTemp: 28 },
  toronto: { lat: 43.65, lon: -79.38, baseTemp: 8 },
  'san francisco': { lat: 37.77, lon: -122.42, baseTemp: 16 },
}

const seededRandom = (seed: number): number => {
  const x = Math.sin(seed) * 10000
  return x - Math.floor(x)
}

const pickCondition = (seed: number) => {
  const idx = Math.floor(seededRandom(seed) * WEATHER_CONDITIONS.length)
  return { ...WEATHER_CONDITIONS[idx] }
}

const generateCurrentWeather = (city: string): CurrentWeather => {
  const key = city.toLowerCase()
  const seed = CITY_SEEDS[key] ?? { lat: 0, lon: 0, baseTemp: 15 }
  const daySeed = Math.floor(Date.now() / 86400000)
  const temp = seed.baseTemp + (seededRandom(daySeed + seed.lat) * 10 - 5)
  const humidity = 40 + Math.floor(seededRandom(daySeed + seed.lon) * 50)
  const windSpeed = 1 + seededRandom(daySeed + seed.lat + seed.lon) * 12

  return {
    coord: { lon: seed.lon, lat: seed.lat },
    weather: [pickCondition(daySeed + seed.lat * 100)],
    main: {
      temp: Math.round(temp * 10) / 10,
      feels_like: Math.round((temp - 2 + seededRandom(daySeed) * 4) * 10) / 10,
      temp_min: Math.round((temp - 3) * 10) / 10,
      temp_max: Math.round((temp + 3) * 10) / 10,
      pressure: 1010 + Math.floor(seededRandom(daySeed + 1) * 20),
      humidity,
    },
    wind: {
      speed: Math.round(windSpeed * 10) / 10,
      deg: Math.floor(seededRandom(daySeed + 2) * 360),
    },
    clouds: { all: Math.floor(seededRandom(daySeed + 3) * 100) },
    dt: Math.floor(Date.now() / 1000),
    name: city.charAt(0).toUpperCase() + city.slice(1),
  }
}

const generateForecast = (city: string): ForecastResponse => {
  const key = city.toLowerCase()
  const seed = CITY_SEEDS[key] ?? { lat: 0, lon: 0, baseTemp: 15 }
  const now = Date.now()
  const list = []

  for (let day = 0; day < 5; day++) {
    for (let hour = 0; hour < 8; hour++) {
      const dt = Math.floor(now / 1000) + day * 86400 + hour * 10800
      const s = day * 8 + hour + seed.lat * 10
      const temp = seed.baseTemp + (seededRandom(s) * 14 - 5) + (hour > 2 && hour < 6 ? 3 : -2)
      const dtDate = new Date(dt * 1000)
      const dtTxt = `${dtDate.getFullYear()}-${String(dtDate.getMonth() + 1).padStart(2, '0')}-${String(dtDate.getDate()).padStart(2, '0')} ${String(dtDate.getHours()).padStart(2, '0')}:00:00`

      list.push({
        dt,
        main: {
          temp: Math.round(temp * 10) / 10,
          feels_like: Math.round((temp - 1) * 10) / 10,
          temp_min: Math.round((temp - 2) * 10) / 10,
          temp_max: Math.round((temp + 2) * 10) / 10,
          pressure: 1013 + Math.floor(seededRandom(s + 100) * 15),
          humidity: 40 + Math.floor(seededRandom(s + 200) * 45),
        },
        weather: [pickCondition(s + 300)],
        wind: {
          speed: Math.round((2 + seededRandom(s + 400) * 10) * 10) / 10,
          deg: Math.floor(seededRandom(s + 500) * 360),
        },
        dt_txt: dtTxt,
      })
    }
  }

  return {
    list,
    city: {
      name: city.charAt(0).toUpperCase() + city.slice(1),
      country: 'XX',
    },
  }
}

const aggregateDailyForecasts = (forecast: ForecastResponse): DailyForecast[] => {
  const dayMap = new Map<string, { temps: number[]; entries: typeof forecast.list }>()

  for (const entry of forecast.list) {
    const date = entry.dt_txt.split(' ')[0]
    if (!dayMap.has(date)) {
      dayMap.set(date, { temps: [], entries: [] })
    }
    const day = dayMap.get(date)!
    day.temps.push(entry.main.temp)
    day.entries.push(entry)
  }

  const days: DailyForecast[] = []
  const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

  for (const [date, data] of dayMap) {
    const d = new Date(date)
    const midEntry = data.entries[Math.floor(data.entries.length / 2)]
    days.push({
      date,
      dayName: dayNames[d.getDay()],
      tempHigh: Math.round(Math.max(...data.temps) * 10) / 10,
      tempLow: Math.round(Math.min(...data.temps) * 10) / 10,
      condition: midEntry.weather[0],
      humidity: midEntry.main.humidity,
      windSpeed: midEntry.wind.speed,
    })
  }

  return days.slice(0, 5)
}

export const getWeatherData = (city: string): DashboardData => {
  const current = generateCurrentWeather(city)
  const forecastResponse = generateForecast(city)
  const forecast = aggregateDailyForecasts(forecastResponse)

  return {
    city: current.name,
    current,
    forecast,
  }
}

export const celsiusToFahrenheit = (c: number): number =>
  Math.round((c * 9) / 5 + 32)

export const weatherIconUrl = (icon: string): string =>
  `https://openweathermap.org/img/wn/${icon}@2x.png`

import { h } from 'plaited'
import type { DailyForecast } from './types'

const CHART_WIDTH = 500
const CHART_HEIGHT = 180
const PADDING = { top: 20, right: 30, bottom: 40, left: 45 }

const plotWidth = CHART_WIDTH - PADDING.left - PADDING.right
const plotHeight = CHART_HEIGHT - PADDING.top - PADDING.bottom

const lerp = (value: number, min: number, max: number, outMin: number, outMax: number): number =>
  max === min ? (outMin + outMax) / 2 : outMin + ((value - min) / (max - min)) * (outMax - outMin)

export const renderTemperatureChart = (forecast: DailyForecast[]) => {
  const highs = forecast.map((d) => d.tempHigh)
  const lows = forecast.map((d) => d.tempLow)
  const allTemps = [...highs, ...lows]
  const minTemp = Math.floor(Math.min(...allTemps)) - 2
  const maxTemp = Math.ceil(Math.max(...allTemps)) + 2

  const xPoints = forecast.map((_, i) =>
    PADDING.left + (i / Math.max(forecast.length - 1, 1)) * plotWidth
  )

  const highPoints = highs.map((t, i) => ({
    x: xPoints[i],
    y: PADDING.top + plotHeight - lerp(t, minTemp, maxTemp, 0, plotHeight),
  }))

  const lowPoints = lows.map((t, i) => ({
    x: xPoints[i],
    y: PADDING.top + plotHeight - lerp(t, minTemp, maxTemp, 0, plotHeight),
  }))

  const highLine = highPoints.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join(' ')
  const lowLine = lowPoints.map((p, i) => `${i === 0 ? 'M' : 'L'}${p.x},${p.y}`).join(' ')

  const gridLines = 5
  const gridElements = []
  for (let i = 0; i <= gridLines; i++) {
    const y = PADDING.top + (i / gridLines) * plotHeight
    const temp = Math.round(maxTemp - (i / gridLines) * (maxTemp - minTemp))
    gridElements.push(
      h('line', {
        x1: String(PADDING.left),
        y1: String(y),
        x2: String(CHART_WIDTH - PADDING.right),
        y2: String(y),
        stroke: '#e0e0e0',
        'stroke-width': '1',
      }),
      h('text', {
        x: String(PADDING.left - 8),
        y: String(y + 4),
        'text-anchor': 'end',
        fill: '#666',
        'font-size': '11',
      }, `${temp}°`)
    )
  }

  const dayLabels = forecast.map((d, i) =>
    h('text', {
      x: String(xPoints[i]),
      y: String(CHART_HEIGHT - 8),
      'text-anchor': 'middle',
      fill: '#666',
      'font-size': '11',
    }, d.dayName)
  )

  const highDots = highPoints.map((p, i) =>
    h('circle', {
      cx: String(p.x),
      cy: String(p.y),
      r: '4',
      fill: '#e74c3c',
      stroke: '#fff',
      'stroke-width': '2',
    })
  )

  const lowDots = lowPoints.map((p, i) =>
    h('circle', {
      cx: String(p.x),
      cy: String(p.y),
      r: '4',
      fill: '#3498db',
      stroke: '#fff',
      'stroke-width': '2',
    })
  )

  return h('div', { style: 'margin-top:16px' },
    h('h3', { style: 'margin:0 0 8px;font-size:14px;color:#555' }, 'Temperature Trend'),
    h('svg', {
      viewBox: `0 0 ${CHART_WIDTH} ${CHART_HEIGHT}`,
      width: String(CHART_WIDTH),
      height: String(CHART_HEIGHT),
      style: 'background:#fafafa;border-radius:8px;border:1px solid #eee',
    },
      ...gridElements,
      h('path', { d: highLine, fill: 'none', stroke: '#e74c3c', 'stroke-width': '2.5' }),
      h('path', { d: lowLine, fill: 'none', stroke: '#3498db', 'stroke-width': '2.5' }),
      ...highDots,
      ...lowDots,
      ...dayLabels,
    ),
    h('div', { style: 'display:flex;gap:16px;margin-top:6px;font-size:12px;color:#666' },
      h('span', {},
        h('span', { style: 'display:inline-block;width:12px;height:3px;background:#e74c3c;margin-right:4px;vertical-align:middle' }),
        'High'
      ),
      h('span', {},
        h('span', { style: 'display:inline-block;width:12px;height:3px;background:#3498db;margin-right:4px;vertical-align:middle' }),
        'Low'
      ),
    )
  )
}

