import { createSSR } from 'plaited'
import { getWeatherData, celsiusToFahrenheit, weatherIconUrl } from './weather'
import { renderDashboard } from './render'
import type { DashboardData } from './types'

export type { DashboardData, CurrentWeather, ForecastEntry, DailyForecast } from './types'
export { celsiusToFahrenheit, weatherIconUrl } from './weather'
export { getWeatherData } from './weather'

const DATA_PATH = './data/cache.json'

const loadCache = async (): Promise<Record<string, { data: DashboardData; ts: number }>> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return {}
}

const saveCache = async (cache: Record<string, { data: DashboardData; ts: number }>) => {
  await Bun.write(DATA_PATH, JSON.stringify(cache, null, 2))
}

const CACHE_TTL_MS = 10 * 60 * 1000

export const getWeatherDashboard = async (city: string): Promise<string> => {
  const key = city.toLowerCase().trim()
  const cache = await loadCache()
  const now = Date.now()

  let data: DashboardData

  if (cache[key] && now - cache[key].ts < CACHE_TTL_MS) {
    data = cache[key].data
  } else {
    data = getWeatherData(city)
    cache[key] = { data, ts: now }
    await saveCache(cache)
  }

  const template = renderDashboard(data, city)
  const ssr = createSSR()
  return ssr(template)
}

const serve = () => {
  const defaultCity = 'London'

  Bun.serve({
    port: 3000,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/api/weather') {
        const city = url.searchParams.get('city') ?? defaultCity
        const data = getWeatherData(city)
        return new Response(JSON.stringify(data), {
          headers: { 'Content-Type': 'application/json' },
        })
      }

      const city = url.searchParams.get('city') ?? defaultCity
      const html = await getWeatherDashboard(city)

      const page = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <title>${city} Weather Dashboard</title>
  <style>
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #f5f6fa; min-height: 100vh; padding: 20px; }
  </style>
</head>
<body>
  ${html}
  <script>
    document.querySelector('form')?.addEventListener('submit', (e) => {
      e.preventDefault()
      const city = e.target.querySelector('input[name="city"]').value
      if (city) window.location.href = '/?city=' + encodeURIComponent(city)
    })
  </script>
</body>
</html>`

      return new Response(page, {
        headers: { 'Content-Type': 'text/html' },
      })
    },
  })

  console.log('Weather Dashboard running at http://localhost:3000')
}

if (import.meta.main) {
  serve()
}

