export type FieldKind = 'numeric' | 'categorical'

export type FieldInfo = {
  name: string
  kind: FieldKind
}

export type ChartType = 'bar' | 'line' | 'pie'

export type ChartConfig = {
  type: ChartType
  title: string
  xLabel: string
  yLabel: string
  categoryField: string
  valueFields: string[]
  colors: string[]
  width: number
  height: number
}

export type DataRow = Record<string, string | number>

export type DetectedSchema = {
  fields: FieldInfo[]
  numericFields: string[]
  categoricalFields: string[]
}

export type ChartRequest = {
  data: DataRow[]
  config: ChartConfig
}

export type SvgResult = {
  svg: string
  error?: string
}

import type { DataRow, DetectedSchema, FieldInfo, FieldKind } from './types'

const isNumericValue = (value: unknown): boolean => {
  if (typeof value === 'number') return true
  if (typeof value === 'string') {
    const trimmed = value.trim()
    return trimmed !== '' && !Number.isNaN(Number(trimmed))
  }
  return false
}

export const detectFields = (data: DataRow[]): DetectedSchema => {
  if (data.length === 0) {
    return { fields: [], numericFields: [], categoricalFields: [] }
  }

  const allKeys = [...new Set(data.flatMap(Object.keys))]

  const fields: FieldInfo[] = allKeys.map((name) => {
    const values = data.map((row) => row[name]).filter((v) => v !== undefined && v !== null)
    const numericCount = values.filter(isNumericValue).length
    const threshold = values.length * 0.8
    const kind: FieldKind = numericCount >= threshold && values.length > 0 ? 'numeric' : 'categorical'
    return { name, kind }
  })

  const numericFields = fields.filter((f) => f.kind === 'numeric').map((f) => f.name)
  const categoricalFields = fields.filter((f) => f.kind === 'categorical').map((f) => f.name)

  return { fields, numericFields, categoricalFields }
}

export const coerceNumeric = (value: unknown): number => {
  if (typeof value === 'number') return value
  if (typeof value === 'string') {
    const n = Number(value.trim())
    return Number.isNaN(n) ? 0 : n
  }
  return 0
}

import type { ChartConfig, DataRow, SvgResult } from './types'
import { coerceNumeric } from './field-detector'

const DEFAULT_COLORS = [
  '#4e79a7', '#f28e2b', '#e15759', '#76b7b2',
  '#59a14f', '#edc948', '#b07aa1', '#ff9da7',
  '#9c755f', '#bab0ac',
]

const escapeXml = (str: string): string =>
  String(str)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')

const resolveColors = (config: ChartConfig): string[] => {
  const needed = config.valueFields.length || 1
  const palette = config.colors.length > 0 ? config.colors : DEFAULT_COLORS
  return Array.from({ length: needed }, (_, i) => palette[i % palette.length])
}

// ── Bar Chart ──────────────────────────────────────────────────────────

const renderBarChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, categoryField, valueFields, title, xLabel, yLabel } = config
  const colors = resolveColors(config)

  const margin = { top: 50, right: 30, bottom: 70, left: 70 }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const categories = data.map((row) => String(row[categoryField] ?? ''))
  const allValues = data.flatMap((row) => valueFields.map((f) => coerceNumeric(row[f])))
  const maxVal = Math.max(...allValues, 0) * 1.1 || 1

  const groupWidth = plotW / categories.length
  const barWidth = (groupWidth * 0.7) / valueFields.length
  const barGap = groupWidth * 0.3 / (valueFields.length + 1)

  const yScale = (v: number) => plotH - (v / maxVal) * plotH

  const gridLines = Array.from({ length: 5 }, (_, i) => {
    const val = (maxVal / 5) * (i + 1)
    const y = yScale(val)
    return `<line x1="0" y1="${y}" x2="${plotW}" y2="${y}" stroke="#e0e0e0" stroke-width="0.5"/>
    <text x="-8" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${Math.round(val)}</text>`
  }).join('\n')

  const bars = data.flatMap((row, di) =>
    valueFields.map((field, fi) => {
      const val = coerceNumeric(row[field])
      const barH = (val / maxVal) * plotH
      const x = di * groupWidth + barGap * (fi + 1) + barWidth * fi
      const y = plotH - barH
      return `<rect x="${x}" y="${y}" width="${barWidth}" height="${barH}" fill="${colors[fi]}" rx="2">
        <title>${escapeXml(field)}: ${val}</title>
      </rect>`
    }),
  ).join('\n')

  const xTicks = categories
    .map((cat, i) => {
      const x = i * groupWidth + groupWidth / 2
      return `<text x="${x}" y="${plotH + 20}" text-anchor="middle" font-size="11" fill="#333">${escapeXml(cat)}</text>`
    })
    .join('\n')

  const legend = valueFields
    .map((field, i) => {
      const lx = i * 130
      return `<rect x="${lx}" y="0" width="12" height="12" fill="${colors[i]}" rx="2"/>
      <text x="${lx + 16}" y="11" font-size="11" fill="#333">${escapeXml(field)}</text>`
    })
    .join('\n')

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui, sans-serif">
  <rect width="${width}" height="${height}" fill="white"/>
  ${title ? `<text x="${width / 2}" y="30" text-anchor="middle" font-size="16" font-weight="bold" fill="#222">${escapeXml(title)}</text>` : ''}
  <g transform="translate(${margin.left},${margin.top})">
    ${gridLines}
    <line x1="0" y1="${plotH}" x2="${plotW}" y2="${plotH}" stroke="#333" stroke-width="1"/>
    <line x1="0" y1="0" x2="0" y2="${plotH}" stroke="#333" stroke-width="1"/>
    ${bars}
    ${xTicks}
    ${xLabel ? `<text x="${plotW / 2}" y="${plotH + 50}" text-anchor="middle" font-size="13" fill="#444">${escapeXml(xLabel)}</text>` : ''}
    ${yLabel ? `<text transform="rotate(-90)" x="${-plotH / 2}" y="-50" text-anchor="middle" font-size="13" fill="#444">${escapeXml(yLabel)}</text>` : ''}
    <g transform="translate(${plotW / 2 - (valueFields.length * 130) / 2}, ${plotH + 55})">${legend}</g>
  </g>
</svg>`
}

// ── Line Chart ─────────────────────────────────────────────────────────

const renderLineChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, categoryField, valueFields, title, xLabel, yLabel } = config
  const colors = resolveColors(config)

  const margin = { top: 50, right: 30, bottom: 70, left: 70 }
  const plotW = width - margin.left - margin.right
  const plotH = height - margin.top - margin.bottom

  const categories = data.map((row) => String(row[categoryField] ?? ''))
  const allValues = data.flatMap((row) => valueFields.map((f) => coerceNumeric(row[f])))
  const maxVal = Math.max(...allValues, 0) * 1.1 || 1

  const xScale = (i: number) => (categories.length > 1 ? (i / (categories.length - 1)) * plotW : plotW / 2)
  const yScale = (v: number) => plotH - (v / maxVal) * plotH

  const gridLines = Array.from({ length: 5 }, (_, i) => {
    const val = (maxVal / 5) * (i + 1)
    const y = yScale(val)
    return `<line x1="0" y1="${y}" x2="${plotW}" y2="${y}" stroke="#e0e0e0" stroke-width="0.5"/>
    <text x="-8" y="${y + 4}" text-anchor="end" font-size="11" fill="#666">${Math.round(val)}</text>`
  }).join('\n')

  const lines = valueFields
    .map((field, fi) => {
      const points = data.map((row, di) => {
        const x = xScale(di)
        const y = yScale(coerceNumeric(row[field]))
        return `${x},${y}`
      })
      const dots = data
        .map((row, di) => {
          const x = xScale(di)
          const y = yScale(coerceNumeric(row[field]))
          return `<circle cx="${x}" cy="${y}" r="4" fill="${colors[fi]}" stroke="white" stroke-width="1.5">
          <title>${escapeXml(field)}: ${coerceNumeric(row[field])}</title>
        </circle>`
        })
        .join('\n')
      return `<polyline points="${points.join(' ')}" fill="none" stroke="${colors[fi]}" stroke-width="2.5" stroke-linejoin="round"/>
      ${dots}`
    })
    .join('\n')

  const xTicks = categories
    .map((cat, i) => {
      const x = xScale(i)
      return `<text x="${x}" y="${plotH + 20}" text-anchor="middle" font-size="11" fill="#333">${escapeXml(cat)}</text>`
    })
    .join('\n')

  const legend = valueFields
    .map((field, i) => {
      const lx = i * 130
      return `<line x1="${lx}" y1="6" x2="${lx + 12}" y2="6" stroke="${colors[i]}" stroke-width="2.5"/>
      <text x="${lx + 16}" y="11" font-size="11" fill="#333">${escapeXml(field)}</text>`
    })
    .join('\n')

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui, sans-serif">
  <rect width="${width}" height="${height}" fill="white"/>
  ${title ? `<text x="${width / 2}" y="30" text-anchor="middle" font-size="16" font-weight="bold" fill="#222">${escapeXml(title)}</text>` : ''}
  <g transform="translate(${margin.left},${margin.top})">
    ${gridLines}
    <line x1="0" y1="${plotH}" x2="${plotW}" y2="${plotH}" stroke="#333" stroke-width="1"/>
    <line x1="0" y1="0" x2="0" y2="${plotH}" stroke="#333" stroke-width="1"/>
    ${lines}
    ${xTicks}
    ${xLabel ? `<text x="${plotW / 2}" y="${plotH + 50}" text-anchor="middle" font-size="13" fill="#444">${escapeXml(xLabel)}</text>` : ''}
    ${yLabel ? `<text transform="rotate(-90)" x="${-plotH / 2}" y="-50" text-anchor="middle" font-size="13" fill="#444">${escapeXml(yLabel)}</text>` : ''}
    <g transform="translate(${plotW / 2 - (valueFields.length * 130) / 2}, ${plotH + 55})">${legend}</g>
  </g>
</svg>`
}

// ── Pie Chart ──────────────────────────────────────────────────────────

const renderPieChart = (data: DataRow[], config: ChartConfig): string => {
  const { width, height, categoryField, valueFields, title } = config
  const colors = resolveColors(config)
  const valueField = valueFields[0]
  if (!valueField) return '<svg xmlns="http://www.w3.org/2000/svg"><text>No value field selected</text></svg>'

  const slices = data.map((row) => ({
    label: String(row[categoryField] ?? ''),
    value: Math.max(0, coerceNumeric(row[valueField])),
  }))

  const total = slices.reduce((sum, s) => sum + s.value, 0)
  if (total === 0) return '<svg xmlns="http://www.w3.org/2000/svg"><text>All values are zero</text></svg>'

  const cx = width / 2
  const cy = height / 2 + 10
  const radius = Math.min(width, height) / 2 - 60

  let currentAngle = -Math.PI / 2
  const paths = slices
    .map((slice, i) => {
      const angle = (slice.value / total) * 2 * Math.PI
      const startX = cx + radius * Math.cos(currentAngle)
      const startY = cy + radius * Math.sin(currentAngle)
      const endX = cx + radius * Math.cos(currentAngle + angle)
      const endY = cy + radius * Math.sin(currentAngle + angle)
      const largeArc = angle > Math.PI ? 1 : 0

      const midAngle = currentAngle + angle / 2
      const labelR = radius + 20
      const labelX = cx + labelR * Math.cos(midAngle)
      const labelY = cy + labelR * Math.sin(midAngle)
      const pct = ((slice.value / total) * 100).toFixed(1)

      const path =
        angle >= 2 * Math.PI - 0.001
          ? `<circle cx="${cx}" cy="${cy}" r="${radius}" fill="${colors[i % colors.length]}">
              <title>${escapeXml(slice.label)}: ${slice.value} (${pct}%)</title>
            </circle>`
          : `<path d="M${cx},${cy} L${startX},${startY} A${radius},${radius} 0 ${largeArc} 1 ${endX},${endY} Z" fill="${colors[i % colors.length]}">
              <title>${escapeXml(slice.label)}: ${slice.value} (${pct}%)</title>
            </path>`

      const label = `<text x="${labelX}" y="${labelY}" text-anchor="${labelX > cx ? 'start' : 'end'}" font-size="11" fill="#333">${escapeXml(slice.label)} (${pct}%)</text>`

      currentAngle += angle
      return `${path}\n${label}`
    })
    .join('\n')

  return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" font-family="system-ui, sans-serif">
  <rect width="${width}" height="${height}" fill="white"/>
  ${title ? `<text x="${width / 2}" y="30" text-anchor="middle" font-size="16" font-weight="bold" fill="#222">${escapeXml(title)}</text>` : ''}
  ${paths}
</svg>`
}

// ── Public API ─────────────────────────────────────────────────────────

export const renderChart = (data: DataRow[], config: ChartConfig): SvgResult => {
  try {
    if (!data.length) return { svg: '', error: 'No data provided' }
    if (!config.categoryField) return { svg: '', error: 'No category field selected' }
    if (!config.valueFields.length) return { svg: '', error: 'No value fields selected' }

    const renderers: Record<string, (d: DataRow[], c: ChartConfig) => string> = {
      bar: renderBarChart,
      line: renderLineChart,
      pie: renderPieChart,
    }

    const render = renderers[config.type]
    if (!render) return { svg: '', error: `Unknown chart type: ${config.type}` }

    return { svg: render(data, config) }
  } catch (err) {
    return { svg: '', error: String(err) }
  }
}

