const clientScript = `
const DEFAULT_COLORS = ['#4e79a7','#f28e2b','#e15759','#76b7b2','#59a14f','#edc948','#b07aa1','#ff9da7','#9c755f','#bab0ac'];

const syntaxHighlight = (json) => {
  return json
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/("(\\\\u[a-fA-F0-9]{4}|\\\\[^u]|[^\\\\"])*")(\\s*:)?/g, (match, str, _, colon) => {
      if (colon) return '<span class="syn-key">' + str + '</span>' + colon;
      return '<span class="syn-str">' + str + '</span>';
    })
    .replace(/\\b(-?\\d+\\.?\\d*([eE][+-]?\\d+)?)\\b/g, '<span class="syn-num">$1</span>')
    .replace(/\\b(true|false|null)\\b/g, '<span class="syn-bool">$1</span>')
    .replace(/([{}\\[\\],])/g, '<span class="syn-brace">$1</span>');
};

const textarea = document.getElementById('json-editor');
const backdrop = document.getElementById('editor-backdrop');
const updateHighlight = () => { backdrop.innerHTML = syntaxHighlight(textarea.value); };
textarea.addEventListener('input', updateHighlight);
textarea.addEventListener('scroll', () => { backdrop.scrollTop = textarea.scrollTop; backdrop.scrollLeft = textarea.scrollLeft; });
updateHighlight();

const detectFields = (data) => {
  if (!Array.isArray(data) || !data.length) return { numeric: [], categorical: [] };
  const keys = [...new Set(data.flatMap(Object.keys))];
  const numeric = [], categorical = [];
  keys.forEach(key => {
    const vals = data.map(r => r[key]).filter(v => v !== undefined && v !== null);
    const numCount = vals.filter(v => typeof v === 'number' || (typeof v === 'string' && v.trim() !== '' && !isNaN(Number(v)))).length;
    (numCount >= vals.length * 0.8 && vals.length > 0 ? numeric : categorical).push(key);
  });
  return { numeric, categorical };
};

const updateFieldSelectors = () => {
  try {
    const data = JSON.parse(textarea.value);
    const { numeric, categorical } = detectFields(data);
    const catSelect = document.getElementById('category-field');
    const valList = document.getElementById('value-fields');
    const colorBox = document.getElementById('color-inputs');
    const detected = document.getElementById('detected-info');

    catSelect.innerHTML = categorical.map(f => '<option value="' + f + '">' + f + '</option>').join('');
    if (!categorical.length && numeric.length) {
      catSelect.innerHTML = numeric.map(f => '<option value="' + f + '">' + f + ' (numeric)</option>').join('');
    }

    valList.innerHTML = numeric.map((f, i) =>
      '<label><input type="checkbox" name="valueField" value="' + f + '"' + (i < 3 ? ' checked' : '') + '> ' + f + '</label>'
    ).join('');

    const count = Math.min(numeric.length, 10);
    colorBox.innerHTML = Array.from({length: count}, (_, i) =>
      '<input type="color" value="' + DEFAULT_COLORS[i % DEFAULT_COLORS.length] + '" title="' + (numeric[i] || 'Series ' + (i+1)) + '">'
    ).join('');

    detected.textContent = 'Detected: ' + categorical.length + ' categorical, ' + numeric.length + ' numeric fields';
  } catch(e) {
    document.getElementById('detected-info').textContent = 'Invalid JSON';
  }
};

textarea.addEventListener('input', () => { updateHighlight(); updateFieldSelectors(); });
updateFieldSelectors();

document.querySelectorAll('.chart-type-btns button').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.chart-type-btns button').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
  });
});

const generateChart = async () => {
  const chartType = document.querySelector('.chart-type-btns button.active')?.dataset.type || 'bar';
  const title = document.getElementById('chart-title').value;
  const xLabel = document.getElementById('x-label').value;
  const yLabel = document.getElementById('y-label').value;
  const categoryField = document.getElementById('category-field').value;
  const valueFields = [...document.querySelectorAll('input[name="valueField"]:checked')].map(el => el.value);
  const colors = [...document.querySelectorAll('#color-inputs input[type="color"]')].map(el => el.value);

  let data;
  try { data = JSON.parse(textarea.value); }
  catch(e) { document.getElementById('chart-result').innerHTML = '<div class="error-msg">Invalid JSON: ' + e.message + '</div>'; return; }

  const res = await fetch('/api/chart', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      data,
      config: { type: chartType, title, xLabel, yLabel, categoryField, valueFields, colors, width: 700, height: 420 }
    })
  });

  const result = await res.json();
  if (result.error) {
    document.getElementById('chart-result').innerHTML = '<div class="error-msg">' + result.error + '</div>';
  } else {
    document.getElementById('chart-result').innerHTML = result.svg;
    document.getElementById('download-btn').style.display = 'inline-flex';
    document.getElementById('download-btn').onclick = () => {
      const blob = new Blob([result.svg], { type: 'image/svg+xml' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url; a.download = (title || 'chart') + '.svg'; a.click();
      URL.revokeObjectURL(url);
    };
  }
};

document.getElementById('generate-btn').addEventListener('click', generateChart);
`

