import { renderChart } from './chart-engine'
import { detectFields } from './field-detector'
import { renderPage } from './ui'
import type { ChartRequest } from './types'

const DATA_DIR = new URL('./data/', import.meta.url).pathname
const SAMPLE_PATH = `${DATA_DIR}sample.json`

const loadSampleData = async (): Promise<string> => {
  const file = Bun.file(SAMPLE_PATH)
  if (await file.exists()) {
    return await file.text()
  }
  return '[\n  { "label": "A", "value": 10 },\n  { "label": "B", "value": 25 },\n  { "label": "C", "value": 15 }\n]'
}

const handleChartRequest = async (req: Request): Promise<Response> => {
  const body = (await req.json()) as ChartRequest
  const { data, config } = body

  if (!Array.isArray(data)) {
    return Response.json({ error: 'Data must be an array of objects' }, { status: 400 })
  }

  const result = renderChart(data, config)
  return Response.json(result)
}

const handleDetectRequest = async (req: Request): Promise<Response> => {
  const { data } = (await req.json()) as { data: unknown[] }

  if (!Array.isArray(data)) {
    return Response.json({ error: 'Data must be an array' }, { status: 400 })
  }

  const schema = detectFields(data as Record<string, string | number>[])
  return Response.json(schema)
}

const handleSaveData = async (req: Request): Promise<Response> => {
  const { name, data } = (await req.json()) as { name: string; data: unknown }
  const safeName = name.replace(/[^a-zA-Z0-9_-]/g, '_')
  const filePath = `${DATA_DIR}${safeName}.json`
  await Bun.write(filePath, JSON.stringify(data, null, 2))
  return Response.json({ saved: filePath })
}

const server = Bun.serve({
  port: Number(process.env.PORT) || 3000,

  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' && req.method === 'GET') {
      const sampleData = await loadSampleData()
      const html = renderPage(sampleData.trim())
      return new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })
    }

    if (url.pathname === '/api/chart' && req.method === 'POST') {
      return handleChartRequest(req)
    }

    if (url.pathname === '/api/detect' && req.method === 'POST') {
      return handleDetectRequest(req)
    }

    if (url.pathname === '/api/save' && req.method === 'POST') {
      return handleSaveData(req)
    }

    return new Response('Not Found', { status: 404 })
  },
})

