        });
        searchResults.classList.add('open');
      });
  }

  document.addEventListener('click', function(e) {
    if (!e.target.closest('.search-wrap')) searchResults.classList.remove('open');
  });

  // Add Marker flow
  var pendingMarkerLatLng = null;
  var markerModal = document.getElementById('marker-modal');

  document.getElementById('add-marker-btn').addEventListener('click', function() {
    pendingMarkerLatLng = null;
    document.getElementById('modal-title').value = '';
    document.getElementById('modal-desc').value = '';
    document.getElementById('modal-latlng').textContent = 'Click on the map to set location';
    markerModal.classList.add('open');
  });

  document.getElementById('modal-cancel').addEventListener('click', function() {
    markerModal.classList.remove('open');
  });

  document.getElementById('modal-save').addEventListener('click', function() {
    if (!pendingMarkerLatLng) { alert('Click on the map to set a location first.'); return; }
    var title = document.getElementById('modal-title').value.trim();
    if (!title) { alert('Please enter a title.'); return; }
