export type Category = 'length' | 'weight' | 'temperature' | 'volume' | 'time'

export type UnitDef = {
  symbol: string
  name: string
  toBase: number
}

export type TemperatureUnit = 'C' | 'F' | 'K'

export type ConversionResult = {
  value: number
  formula: string
  fromUnit: string
  toUnit: string
}

export type CategoryConfig = {
  label: string
  units: UnitDef[]
  baseUnit: string
}

export type ConverterState = {
  category: Category
  inputValue: number
  fromUnit: string
  toUnit: string
}

import type { Category, CategoryConfig, ConversionResult, TemperatureUnit } from './types'

const CATEGORIES: Record<Category, CategoryConfig> = {
  length: {
    label: 'Length',
    baseUnit: 'm',
    units: [
      { symbol: 'mm', name: 'Millimeter', toBase: 0.001 },
      { symbol: 'cm', name: 'Centimeter', toBase: 0.01 },
