    baseUnit: 'ml',
    units: [
      { symbol: 'ml', name: 'Milliliter', toBase: 1 },
      { symbol: 'l', name: 'Liter', toBase: 1000 },
      { symbol: 'gal', name: 'Gallon', toBase: 3785.41 },
      { symbol: 'qt', name: 'Quart', toBase: 946.353 },
      { symbol: 'pt', name: 'Pint', toBase: 473.176 },
      { symbol: 'cup', name: 'Cup', toBase: 236.588 },
      { symbol: 'tbsp', name: 'Tablespoon', toBase: 14.7868 },
      { symbol: 'tsp', name: 'Teaspoon', toBase: 4.92892 },
    ],
  },
  time: {
    label: 'Time',
    baseUnit: 's',
    units: [
      { symbol: 'ms', name: 'Millisecond', toBase: 0.001 },
      { symbol: 's', name: 'Second', toBase: 1 },
      { symbol: 'min', name: 'Minute', toBase: 60 },
      { symbol: 'hr', name: 'Hour', toBase: 3600 },
      { symbol: 'day', name: 'Day', toBase: 86400 },
      { symbol: 'week', name: 'Week', toBase: 604800 },
    ],
  },
}

const TEMP_FORMULAS: Record<string, { convert: (v: number) => number; formula: string }> = {
  'C->F': { convert: (v) => v * 9 / 5 + 32, formula: '(°C × 9/5) + 32' },
  'C->K': { convert: (v) => v + 273.15, formula: '°C + 273.15' },
  'F->C': { convert: (v) => (v - 32) * 5 / 9, formula: '(°F − 32) × 5/9' },
  'F->K': { convert: (v) => (v - 32) * 5 / 9 + 273.15, formula: '(°F − 32) × 5/9 + 273.15' },
  'K->C': { convert: (v) => v - 273.15, formula: '°K − 273.15' },
  'K->F': { convert: (v) => (v - 273.15) * 9 / 5 + 32, formula: '(°K − 273.15) × 9/5 + 32' },
}

const formatNumber = (n: number): number => {
  const rounded = Math.round(n * 1e10) / 1e10
  return Number(rounded.toPrecision(12))
}

const convertTemperature = (value: number, from: TemperatureUnit, to: TemperatureUnit): ConversionResult => {
  if (from === to) {
    return { value, formula: `${value} °${from} = ${value} °${to}`, fromUnit: from, toUnit: to }
  }
  const key = `${from}->${to}`
  const entry = TEMP_FORMULAS[key]
  if (!entry) {
    return { value: NaN, formula: 'Unknown conversion', fromUnit: from, toUnit: to }
  }
  const result = formatNumber(entry.convert(value))
  return {
    value: result,
    formula: `${entry.formula} → ${value} °${from} = ${result} °${to}`,
    fromUnit: from,
    toUnit: to,
  }
}

const convertLinear = (
  value: number,
  from: string,
  to: string,
  category: CategoryConfig,
): ConversionResult => {
  if (from === to) {
    return { value, formula: `${value} ${from} = ${value} ${to}`, fromUnit: from, toUnit: to }
  }
  const fromDef = category.units.find((u) => u.symbol === from)
  const toDef = category.units.find((u) => u.symbol === to)
  if (!fromDef || !toDef) {
    return { value: NaN, formula: 'Unknown unit', fromUnit: from, toUnit: to }
  }
  const factor = fromDef.toBase / toDef.toBase
  const result = formatNumber(value * factor)
  const formulaFactor = formatNumber(factor)
  return {
    value: result,
    formula: `1 ${from} = ${formulaFactor} ${to} → ${value} ${from} × ${formulaFactor} = ${result} ${to}`,
    fromUnit: from,
    toUnit: to,
  }
}

export const convert = (category: Category, value: number, from: string, to: string): ConversionResult => {
  if (category === 'temperature') {
    return convertTemperature(value, from as TemperatureUnit, to as TemperatureUnit)
  }
  const config = CATEGORIES[category]
  return convertLinear(value, from, to, config)
}

export const getCategories = (): Record<Category, CategoryConfig> => CATEGORIES

export const getCategoryList = (): { key: Category; label: string }[] =>
  (Object.keys(CATEGORIES) as Category[]).map((key) => ({ key, label: CATEGORIES[key].label }))

export const getUnitsForCategory = (category: Category): CategoryConfig['units'] =>
  CATEGORIES[category].units

