import { createSSR } from 'plaited'
import type { Category } from './types'
import { convert, getUnitsForCategory, getCategoryList } from './converter'
import { renderConverter } from './ui'

export type { Category, ConversionResult, ConverterState } from './types'
export { convert, getUnitsForCategory, getCategoryList } from './converter'

const DEFAULT_UNITS: Record<Category, { from: string; to: string }> = {
  length: { from: 'm', to: 'ft' },
  weight: { from: 'kg', to: 'lb' },
  temperature: { from: 'C', to: 'F' },
  volume: { from: 'l', to: 'gal' },
  time: { from: 'hr', to: 'min' },
}

export const createConverterPage = (
  category: Category = 'length',
  inputValue = '1',
  fromUnit?: string,
  toUnit?: string,
): string => {
  const defaults = DEFAULT_UNITS[category]
  const from = fromUnit ?? defaults.from
  const to = toUnit ?? defaults.to

  const template = renderConverter({ category, inputValue, fromUnit: from, toUnit: to })
  const ssr = createSSR()
  return ssr(template)
}

const handleRequest = (req: Request): Response => {
  const url = new URL(req.url)
  const params = url.searchParams

  const category = (params.get('category') ?? 'length') as Category
  const validCategories = getCategoryList().map((c) => c.key)
  const safeCategory = validCategories.includes(category) ? category : 'length'

  const inputValue = params.get('value') ?? '1'
  const fromUnit = params.get('from') ?? undefined
  const toUnit = params.get('to') ?? undefined

  if (url.pathname === '/api/convert') {
    const numValue = parseFloat(inputValue)
    if (isNaN(numValue)) {
      return Response.json({ error: 'Invalid value' }, { status: 400 })
    }
    const units = getUnitsForCategory(safeCategory)
    const from = fromUnit ?? units[0].symbol
    const to = toUnit ?? units[1].symbol
    const result = convert(safeCategory, numValue, from, to)
    return Response.json(result)
  }

  const html = createConverterPage(safeCategory, inputValue, fromUnit, toUnit)
  return new Response(html, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })
}

export default {
  fetch: handleRequest,
}

