import type { CalendarEvent } from './types'

const DATA_PATH = './data/events.json'

export const loadEvents = async (): Promise<CalendarEvent[]> => {
  const file = Bun.file(DATA_PATH)
  const exists = await file.exists()
  if (!exists) {
    await Bun.write(DATA_PATH, '[]')
    return []
  }
  const text = await file.text()
  return JSON.parse(text) as CalendarEvent[]
}

export const saveEvents = async (events: CalendarEvent[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(events, null, 2))
}

export const generateId = (): string => {
  return crypto.randomUUID()
}

export const addEvent = async (event: Omit<CalendarEvent, 'id'>): Promise<CalendarEvent> => {
  const events = await loadEvents()
  const newEvent: CalendarEvent = { id: generateId(), ...event }
  events.push(newEvent)
  await saveEvents(events)
  return newEvent
}

export const updateEvent = async (
  id: string,
  updates: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  const index = events.findIndex((e) => e.id === id)
  if (index === -1) return null
  events[index] = { ...events[index], ...updates }
  await saveEvents(events)
  return events[index]
}

export const deleteEvent = async (id: string): Promise<boolean> => {
  const events = await loadEvents()
  const filtered = events.filter((e) => e.id !== id)
  if (filtered.length === events.length) return false
  await saveEvents(filtered)
  return true
}

export const getEventById = async (id: string): Promise<CalendarEvent | null> => {
  const events = await loadEvents()
  return events.find((e) => e.id === id) ?? null
}

import type { CalendarEvent, DayCell, EventCategory, MonthGrid, RecurrenceRule } from './types'
import { loadEvents } from './store'

const MONTH_NAMES = [
  'January', 'February', 'March', 'April', 'May', 'June',
  'July', 'August', 'September', 'October', 'November', 'December',
]

const DAY_NAMES = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat']

const formatDate = (year: number, month: number, day: number): string => {
  const m = String(month + 1).padStart(2, '0')
  const d = String(day).padStart(2, '0')
  return `${year}-${m}-${d}`
}

const parseDate = (dateStr: string): { year: number; month: number; day: number } => {
  const [year, month, day] = dateStr.split('-').map(Number)
  return { year, month: month - 1, day }
}

const todayString = (): string => {
  const now = new Date()
  return formatDate(now.getFullYear(), now.getMonth(), now.getDate())
}

const matchesRecurrence = (event: CalendarEvent, targetDate: string): boolean => {
  if (!event.recurrence) return event.date === targetDate

  const eventParsed = parseDate(event.date)
  const targetParsed = parseDate(targetDate)
  const eventD = new Date(eventParsed.year, eventParsed.month, eventParsed.day)
  const targetD = new Date(targetParsed.year, targetParsed.month, targetParsed.day)

  // Recurrence only applies on or after the original event date
  if (targetD < eventD) return false

  switch (event.recurrence) {
    case 'daily':
      return true
    case 'weekly': {
      return eventD.getDay() === targetD.getDay()
    }
    case 'monthly': {
      return eventParsed.day === targetParsed.day
    }
    default:
      return event.date === targetDate
  }
}

export const getEventsForDate = async (
  date: string,
  categoryFilter?: EventCategory[]
): Promise<CalendarEvent[]> => {
  const events = await loadEvents()
  return events
    .filter((e) => matchesRecurrence(e, date))
    .filter((e) => !categoryFilter || categoryFilter.length === 0 || categoryFilter.includes(e.category))
    .sort((a, b) => a.startTime.localeCompare(b.startTime))
}

export const buildMonthGrid = async (
  year: number,
  month: number,
  categoryFilter?: EventCategory[]
): Promise<MonthGrid> => {
  const firstDay = new Date(year, month, 1)
  const startDow = firstDay.getDay()
  const daysInMonth = new Date(year, month + 1, 0).getDate()
  const today = todayString()

  // Get previous month padding days
  const prevMonthDays = new Date(year, month, 0).getDate()

  const allEvents = await loadEvents()
  const filteredEvents = categoryFilter && categoryFilter.length > 0
    ? allEvents.filter((e) => categoryFilter.includes(e.category))
    : allEvents

  const weeks: DayCell[][] = []
  let currentWeek: DayCell[] = []

  // Fill leading days from previous month
  for (let i = startDow - 1; i >= 0; i--) {
    const day = prevMonthDays - i
    const prevMonth = month === 0 ? 11 : month - 1
    const prevYear = month === 0 ? year - 1 : year
    const dateStr = formatDate(prevYear, prevMonth, day)
    currentWeek.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: false,
      isToday: dateStr === today,
      events: filteredEvents.filter((e) => matchesRecurrence(e, dateStr)),
    })
  }

  // Fill current month days
  for (let day = 1; day <= daysInMonth; day++) {
    const dateStr = formatDate(year, month, day)
    currentWeek.push({
      date: dateStr,
      dayOfMonth: day,
      isCurrentMonth: true,
      isToday: dateStr === today,
      events: filteredEvents.filter((e) => matchesRecurrence(e, dateStr)),
    })

    if (currentWeek.length === 7) {
      weeks.push(currentWeek)
      currentWeek = []
    }
  }

  // Fill trailing days from next month
  if (currentWeek.length > 0) {
    let nextDay = 1
    const nextMonth = month === 11 ? 0 : month + 1
    const nextYear = month === 11 ? year + 1 : year
    while (currentWeek.length < 7) {
      const dateStr = formatDate(nextYear, nextMonth, nextDay)
      currentWeek.push({
        date: dateStr,
        dayOfMonth: nextDay,
        isCurrentMonth: false,
        isToday: dateStr === today,
        events: filteredEvents.filter((e) => matchesRecurrence(e, dateStr)),
      })
      nextDay++
    }
    weeks.push(currentWeek)
  }

  return {
    year,
    month,
    label: `${MONTH_NAMES[month]} ${year}`,
    weeks,
  }
}

export const getPrevMonth = (year: number, month: number): { year: number; month: number } => {
  return month === 0 ? { year: year - 1, month: 11 } : { year, month: month - 1 }
}

export const getNextMonth = (year: number, month: number): { year: number; month: number } => {
  return month === 11 ? { year: year + 1, month: 0 } : { year, month: month + 1 }
}

