const toStyleString = (obj: Record<string, string | number>): string =>
  Object.entries(obj)
    .map(([key, value]) => {
      const cssKey = key.replace(/[A-Z]/g, (m) => `-${m.toLowerCase()}`)
      return `${cssKey}: ${typeof value === 'number' ? `${value}px` : value}`
    })
    .join('; ')

export const renderEventDots = (events: CalendarEvent[]): ReturnType<typeof h> => {
  const categories = [...new Set(events.map((e) => e.category))]
  if (categories.length === 0) return h(Fragment, {})

  return h(
    'div',
    { style: toStyleString(styles.eventDotsRow) },
    ...categories.map((cat) =>
      h('span', {
        style: toStyleString({
          ...styles.eventDot,
          backgroundColor: CATEGORY_COLORS[cat],
        }),
      })
    )
  )
}

export const renderEventIndicators = (events: CalendarEvent[]): ReturnType<typeof h> => {
  const shown = events.slice(0, 2)
  const overflow = events.length - shown.length

  return h(
    Fragment,
    {},
    ...shown.map((evt) =>
      h(
        'div',
        {
          style: toStyleString({
            ...styles.eventIndicator,
            backgroundColor: CATEGORY_COLORS[evt.category],
          }),
        },
        evt.title
      )
    ),
    ...(overflow > 0
      ? [
          h(
            'div',
            { style: 'font-size: 11px; color: #6b7280; padding-left: 4px;' },
            `+${overflow} more`
          ),
        ]
      : [])
  )
}

