        { style: toStyleString(styles.formRow) },
        h(
          'div',
          { style: toStyleString(styles.formField) },
          h('label', { style: toStyleString(styles.formLabel) }, 'Description'),
          h('textarea', {
            name: 'description',
            placeholder: 'Optional description',
            style: toStyleString(styles.formTextarea),
          }, existing?.description ?? '')
        )
      ),
      // Actions
      h(
        'div',
        { style: 'display: flex; gap: 8px; margin-top: 8px;' },
        h(
          'button',
          { type: 'submit', style: toStyleString(styles.submitButton) },
          isEdit ? 'Save Changes' : 'Create Event'
        ),
        h(
          'button',
          {
            type: 'button',
            style: toStyleString(styles.cancelButton),
            'p-trigger': 'click:cancelForm',
          },
          'Cancel'
        )
      )
    )
  )
}

export const renderToString = (template: ReturnType<typeof h>): string => {
  const ssr = createSSR()
  return ssr(template)
}

import type { CalendarEvent, CalendarState, EventCategory, RecurrenceRule } from './types'
import { addEvent, deleteEvent, getEventById, updateEvent } from './store'
import { buildMonthGrid, getEventsForDate, todayString, parseDate } from './calendar'
import {
  renderMonthView,
  renderDayView,
  renderEventForm,
  renderToString,
} from './views'

// --- State ---

const createInitialState = (): CalendarState => {
  const now = new Date()
  return {
    view: 'month',
    selectedDate: todayString(),
    currentMonth: now.getMonth(),
    currentYear: now.getFullYear(),
    categoryFilter: [],
  }
}

let state = createInitialState()

// --- Actions ---

export const navigateToMonth = (year: number, month: number): void => {
  state = { ...state, currentYear: year, currentMonth: month, view: 'month' }
}

export const navigatePrevMonth = (): void => {
  const m = state.currentMonth === 0 ? 11 : state.currentMonth - 1
  const y = state.currentMonth === 0 ? state.currentYear - 1 : state.currentYear
  navigateToMonth(y, m)
}

export const navigateNextMonth = (): void => {
  const m = state.currentMonth === 11 ? 0 : state.currentMonth + 1
  const y = state.currentMonth === 11 ? state.currentYear + 1 : state.currentYear
  navigateToMonth(y, m)
}

export const selectDay = (date: string): void => {
  const parsed = parseDate(date)
  state = {
    ...state,
    view: 'day',
    selectedDate: date,
    currentYear: parsed.year,
    currentMonth: parsed.month,
  }
}

export const backToMonth = (): void => {
  state = { ...state, view: 'month' }
}

export const toggleCategoryFilter = (category: EventCategory): void => {
  const current = state.categoryFilter
  const updated = current.includes(category)
    ? current.filter((c) => c !== category)
    : [...current, category]
  state = { ...state, categoryFilter: updated }
}

export const createEvent = async (data: {
  title: string
  date: string
  startTime: string
  endTime: string
  description: string
  category: EventCategory
  recurrence?: RecurrenceRule
}): Promise<CalendarEvent> => {
  const event = await addEvent({
    title: data.title,
    date: data.date,
    startTime: data.startTime,
    endTime: data.endTime,
    description: data.description,
    category: data.category,
    recurrence: data.recurrence,
  })
  return event
}

export const editEvent = async (
  id: string,
  data: Partial<Omit<CalendarEvent, 'id'>>
): Promise<CalendarEvent | null> => {
  return updateEvent(id, data)
}

export const removeEvent = async (id: string): Promise<boolean> => {
  return deleteEvent(id)
}

// --- Rendering ---

export const renderCurrentView = async (): Promise<string> => {
  if (state.view === 'month') {
    const grid = await buildMonthGrid(
      state.currentYear,
      state.currentMonth,
      state.categoryFilter.length > 0 ? state.categoryFilter : undefined
    )
    return renderToString(renderMonthView(grid, state.categoryFilter))
  }

  const events = await getEventsForDate(
    state.selectedDate,
    state.categoryFilter.length > 0 ? state.categoryFilter : undefined
  )
  return renderToString(renderDayView(state.selectedDate, events))
}

export const renderNewEventForm = (date?: string): string => {
  return renderToString(renderEventForm(date ?? state.selectedDate))
}

export const renderEditEventForm = async (eventId: string): Promise<string | null> => {
  const event = await getEventById(eventId)
  if (!event) return null
  return renderToString(renderEventForm(event.date, event))
}

export const getState = (): CalendarState => ({ ...state })

// --- Main ---

const main = async (): Promise<void> => {
  const html = await renderCurrentView()
  console.log(html)
}

main()

