export type Document = {
  id: string;
  title: string;
  content: string;
  createdAt: string;
  updatedAt: string;
};

export type DocumentListItem = {
  id: string;
  title: string;
  updatedAt: string;
};

export type SaveDocumentRequest = {
  title: string;
  content: string;
  id?: string;
};

import type { Document, DocumentListItem, SaveDocumentRequest } from "./types";

const DATA_PATH = `${import.meta.dir}/data/documents.json`;

const readDocuments = async (): Promise<Document[]> => {
  const file = Bun.file(DATA_PATH);
  const exists = await file.exists();
  if (!exists) return [];
  const text = await file.text();
  return text.trim() ? JSON.parse(text) : [];
};

const writeDocuments = async (docs: Document[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(docs, null, 2));
};

const generateId = (): string => {
  return `doc_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
};

export const saveDocument = async (req: SaveDocumentRequest): Promise<Document> => {
  const docs = await readDocuments();
  const now = new Date().toISOString();

  if (req.id) {
    const idx = docs.findIndex((d) => d.id === req.id);
    if (idx !== -1) {
      docs[idx] = {
        ...docs[idx],
        title: req.title,
        content: req.content,
        updatedAt: now,
      };
      await writeDocuments(docs);
      return docs[idx];
    }
  }

  const doc: Document = {
    id: generateId(),
    title: req.title,
    content: req.content,
    createdAt: now,
    updatedAt: now,
  };
  docs.push(doc);
  await writeDocuments(docs);
  return doc;
};

export const listDocuments = async (): Promise<DocumentListItem[]> => {
  const docs = await readDocuments();
  return docs
    .map(({ id, title, updatedAt }) => ({ id, title, updatedAt }))
    .sort((a, b) => b.updatedAt.localeCompare(a.updatedAt));
};

export const getDocument = async (id: string): Promise<Document | null> => {
  const docs = await readDocuments();
  return docs.find((d) => d.id === id) ?? null;
};

export const deleteDocument = async (id: string): Promise<boolean> => {
  const docs = await readDocuments();
  const filtered = docs.filter((d) => d.id !== id);
  if (filtered.length === docs.length) return false;
  await writeDocuments(filtered);
  return true;
};

const escapeHtml = (text: string): string =>
  text
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");

const parseInline = (text: string): string => {
  let result = text;

  // Images (must come before links)
  result = result.replace(
    /!\[([^\]]*)\]\(([^)]+)\)/g,
    '<img src="$2" alt="$1" style="max-width:100%;" />'
  );

  // Links
  result = result.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    '<a href="$2" target="_blank" rel="noopener">$1</a>'
  );

  // Bold + italic
  result = result.replace(
    /\*\*\*(.+?)\*\*\*/g,
    "<strong><em>$1</em></strong>"
  );

  // Bold
  result = result.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  // Italic
  result = result.replace(/\*(.+?)\*/g, "<em>$1</em>");

  // Strikethrough
  result = result.replace(/~~(.+?)~~/g, "<del>$1</del>");

  // Inline code
  result = result.replace(/`([^`]+)`/g, "<code>$1</code>");

  return result;
};

const parseTable = (lines: string[]): string => {
  if (lines.length < 2) return "";

  const parseRow = (line: string): string[] =>
    line
      .replace(/^\|/, "")
      .replace(/\|$/, "")
      .split("|")
      .map((cell) => cell.trim());

  const headers = parseRow(lines[0]);
  const alignRow = parseRow(lines[1]);

  const aligns = alignRow.map((cell) => {
    const left = cell.startsWith(":");
    const right = cell.endsWith(":");
    if (left && right) return "center";
    if (right) return "right";
    return "left";
  });

  let html = '<table style="border-collapse:collapse;width:100%;">\n<thead>\n<tr>\n';
  for (let i = 0; i < headers.length; i++) {
    const align = aligns[i] ?? "left";
    html += `<th style="border:1px solid #444;padding:6px 12px;text-align:${align};background:#2a2a2a;">${parseInline(headers[i])}</th>\n`;
  }
  html += "</tr>\n</thead>\n<tbody>\n";

  for (let r = 2; r < lines.length; r++) {
    const cells = parseRow(lines[r]);
    html += "<tr>\n";
    for (let i = 0; i < headers.length; i++) {
      const align = aligns[i] ?? "left";
      const content = cells[i] ?? "";
      html += `<td style="border:1px solid #444;padding:6px 12px;text-align:${align};">${parseInline(content)}</td>\n`;
    }
    html += "</tr>\n";
  }

  html += "</tbody>\n</table>";
  return html;
};

export const renderMarkdown = (source: string): string => {
  const lines = source.replace(/\r\n/g, "\n").split("\n");
  const output: string[] = [];
  let i = 0;

  const flushParagraph = (text: string) => {
    const trimmed = text.trim();
    if (trimmed) {
      output.push(`<p>${parseInline(trimmed)}</p>`);
    }
  };

  while (i < lines.length) {
    const line = lines[i];

    // Fenced code block
    if (line.startsWith("```")) {
      const lang = line.slice(3).trim();
      const codeLines: string[] = [];
      i++;
      while (i < lines.length && !lines[i].startsWith("```")) {
        codeLines.push(escapeHtml(lines[i]));
        i++;
      }
      i++; // skip closing ```
      const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : "";
      output.push(
        `<pre style="background:#1e1e1e;padding:12px;border-radius:6px;overflow-x:auto;"><code${langAttr}>${codeLines.join("\n")}</code></pre>`
      );
      continue;
    }

    // Table (detect: line with pipes, followed by separator row)
    if (
      line.includes("|") &&
      i + 1 < lines.length &&
      /^\|?\s*:?-+:?\s*(\|\s*:?-+:?\s*)*\|?\s*$/.test(lines[i + 1])
    ) {
      const tableLines: string[] = [line];
      i++;
      while (i < lines.length && lines[i].includes("|")) {
        tableLines.push(lines[i]);
        i++;
      }
      output.push(parseTable(tableLines));
      continue;
    }

    // Horizontal rule
    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
      output.push('<hr style="border:none;border-top:1px solid #555;margin:16px 0;" />');
      i++;
      continue;
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.+)$/);
    if (headingMatch) {
      const level = headingMatch[1].length;
      output.push(`<h${level}>${parseInline(headingMatch[2])}</h${level}>`);
      i++;
      continue;
    }

    // Blockquote
    if (line.startsWith(">")) {
      const quoteLines: string[] = [];
      while (i < lines.length && lines[i].startsWith(">")) {
        quoteLines.push(lines[i].replace(/^>\s?/, ""));
        i++;
      }
      output.push(
        `<blockquote style="border-left:4px solid #555;margin:8px 0;padding:4px 16px;color:#aaa;">${renderMarkdown(quoteLines.join("\n"))}</blockquote>`
      );
      continue;
    }

    // Unordered list
    if (/^\s*[-*+]\s+/.test(line)) {
      output.push("<ul>");
      while (i < lines.length && /^\s*[-*+]\s+/.test(lines[i])) {
        const content = lines[i].replace(/^\s*[-*+]\s+/, "");
        output.push(`<li>${parseInline(content)}</li>`);
        i++;
      }
      output.push("</ul>");
      continue;
    }

    // Ordered list
    if (/^\s*\d+\.\s+/.test(line)) {
      output.push("<ol>");
      while (i < lines.length && /^\s*\d+\.\s+/.test(lines[i])) {
        const content = lines[i].replace(/^\s*\d+\.\s+/, "");
        output.push(`<li>${parseInline(content)}</li>`);
        i++;
      }
      output.push("</ol>");
      continue;
    }

    // Blank line
    if (line.trim() === "") {
      i++;
      continue;
    }

    // Paragraph — collect consecutive non-empty, non-special lines
    const paraLines: string[] = [line];
    i++;
    while (
      i < lines.length &&
      lines[i].trim() !== "" &&
      !lines[i].startsWith("#") &&
      !lines[i].startsWith(">") &&
      !lines[i].startsWith("```") &&
      !/^\s*[-*+]\s+/.test(lines[i]) &&
      !/^\s*\d+\.\s+/.test(lines[i]) &&
      !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i])
    ) {
      paraLines.push(lines[i]);
      i++;
    }
    flushParagraph(paraLines.join("\n"));
  }

  return output.join("\n");
};

