const formatDate = (iso: string): string => {
  const d = new Date(iso);
  return d.toLocaleDateString("en-US", {
    month: "short",
    day: "numeric",
    hour: "2-digit",
    minute: "2-digit",
  });
};

export const renderPage = (
  documents: DocumentListItem[],
  currentContent?: string,
  currentTitle?: string,
  currentId?: string,
  previewHtml?: string
): string => {
  const title = currentTitle ?? "Untitled";
  const content = currentContent ?? "";
  const preview = previewHtml ?? "";
  const docId = currentId ?? "";

  const ssr = createSSR();

  const template = h("html", { lang: "en" },
    h("head", {},
      h("meta", { charset: "utf-8" }),
      h("meta", { name: "viewport", content: "width=device-width, initial-scale=1" }),
      h("title", {}, "Markdown Editor"),
    ),
    h("body", { style: styleToStr(styles.page) },
      // Toolbar
      h("div", { style: styleToStr(styles.toolbar) },
        ...toolbarButtons.map((btn) => {
          if (btn.label === "|sep|") {
            return h("div", { style: styleToStr(styles.toolbarSep) });
          }
          return h("button", {
            style: styleToStr(styles.toolbarBtn),
            title: btn.title,
            "data-action": btn.action,
            onclick: `insertFormat('${btn.action}')`,
          }, btn.label);
        })
      ),

      // Title bar
      h("div", { style: styleToStr(styles.titleBar) },
        h("input", {
          type: "text",
          id: "doc-title",
          placeholder: "Document title...",
          value: title,
          style: styleToStr(styles.titleInput),
        }),
        h("input", { type: "hidden", id: "doc-id", value: docId }),
        h("button", {
          style: styleToStr(styles.saveBtn),
          onclick: "saveDocument()",
        }, "Save"),
        h("button", {
          style: styleToStr(styles.newBtn),
          onclick: "newDocument()",
        }, "New"),
      ),

      // Main area
      h("div", { style: styleToStr(styles.mainArea) },
        // Sidebar
        h("div", { style: styleToStr(styles.sidebar) },
          h("div", { style: styleToStr(styles.sidebarHeader) }, "Saved Documents"),
          h("div", { id: "doc-list", style: styleToStr(styles.docList) },
            ...documents.map((doc) =>
              h("div", {
                style: styleToStr(styles.docItem),
                onclick: `loadDocument('${doc.id}')`,
                onmouseover: "this.style.background='#222'",
                onmouseout: "this.style.background='transparent'",
              },
                h("div", { style: styleToStr(styles.docItemTitle) }, doc.title),
                h("div", { style: styleToStr(styles.docItemDate) }, formatDate(doc.updatedAt)),
              )
            )
          ),
        ),

        // Split pane editor + preview
        h("div", { style: styleToStr(styles.splitPane) },
          // Editor
          h("div", { style: styleToStr(styles.editorPane) },
            h("div", { style: styleToStr(styles.paneLabel) }, "Editor"),
            h("textarea", {
              id: "editor",
              style: styleToStr(styles.textarea),
              placeholder: "Start writing markdown...",
              oninput: "updatePreview()",
              spellcheck: "false",
            }, content),
          ),

          // Preview
          h("div", { style: styleToStr(styles.previewPane) },
            h("div", { style: styleToStr(styles.paneLabel) }, "Preview"),
            h("div", { id: "preview", style: styleToStr(styles.previewBody) }),
          ),
        ),
      ),

      // Client-side JS
      h("script", {}, `
        const editor = document.getElementById('editor');
        const preview = document.getElementById('preview');
        const titleInput = document.getElementById('doc-title');
        const docIdInput = document.getElementById('doc-id');

        // Initial preview
        const initialPreview = ${JSON.stringify(preview)};
        if (initialPreview) {
          preview.innerHTML = initialPreview;
        } else {
          updatePreview();
        }

        let debounceTimer;
        function updatePreview() {
          clearTimeout(debounceTimer);
          debounceTimer = setTimeout(async () => {
            const res = await fetch('/preview', {
              method: 'POST',
              headers: { 'Content-Type': 'text/plain' },
              body: editor.value,
            });
            if (res.ok) {
              preview.innerHTML = await res.text();
            }
          }, 150);
        }

        function insertFormat(action) {
          const start = editor.selectionStart;
          const end = editor.selectionEnd;
          const selected = editor.value.substring(start, end);
          let before = '', after = '', replacement = '';

          switch (action) {
            case 'h1': before = '# '; break;
            case 'h2': before = '## '; break;
            case 'h3': before = '### '; break;
            case 'bold': before = '**'; after = '**'; break;
            case 'italic': before = '*'; after = '*'; break;
            case 'strikethrough': before = '~~'; after = '~~'; break;
            case 'code': before = '\`'; after = '\`'; break;
            case 'link':
              replacement = '[' + (selected || 'text') + '](url)';
              break;
            case 'image':
              replacement = '![' + (selected || 'alt text') + '](url)';
              break;
            case 'codeblock':
              before = '\`\`\`\\n'; after = '\\n\`\`\`';
              break;
            case 'ul':
              replacement = selected
                ? selected.split('\\n').map(l => '- ' + l).join('\\n')
                : '- item';
              break;
            case 'ol':
              replacement = selected
                ? selected.split('\\n').map((l, i) => (i+1) + '. ' + l).join('\\n')
                : '1. item';
              break;
            case 'blockquote':
              replacement = selected
                ? selected.split('\\n').map(l => '> ' + l).join('\\n')
                : '> quote';
              break;
            case 'hr':
              replacement = '\\n---\\n';
              break;
            case 'table':
              replacement = '| Header 1 | Header 2 | Header 3 |\\n| --- | --- | --- |\\n| Cell 1 | Cell 2 | Cell 3 |';
              break;
          }

          if (replacement) {
            editor.value = editor.value.substring(0, start) + replacement + editor.value.substring(end);
            editor.selectionStart = start;
            editor.selectionEnd = start + replacement.length;
          } else {
            const insert = before + (selected || 'text') + after;
            editor.value = editor.value.substring(0, start) + insert + editor.value.substring(end);
            editor.selectionStart = start + before.length;
            editor.selectionEnd = start + before.length + (selected || 'text').length;
          }

          editor.focus();
          updatePreview();
        }

        async function saveDocument() {
          const title = titleInput.value.trim() || 'Untitled';
          const content = editor.value;
          const id = docIdInput.value || undefined;

          const res = await fetch('/documents', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title, content, id }),
          });

          if (res.ok) {
            const doc = await res.json();
            docIdInput.value = doc.id;
            refreshDocList();
          }
        }

        async function loadDocument(id) {
          const res = await fetch('/documents/' + id);
          if (res.ok) {
            const doc = await res.json();
            editor.value = doc.content;
            titleInput.value = doc.title;
            docIdInput.value = doc.id;
            updatePreview();
          }
        }

        function newDocument() {
          editor.value = '';
          titleInput.value = '';
          docIdInput.value = '';
          preview.innerHTML = '';
        }

        async function refreshDocList() {
          const res = await fetch('/documents');
          if (!res.ok) return;
          const docs = await res.json();
          const list = document.getElementById('doc-list');
          list.innerHTML = docs.map(doc =>
            '<div style="${styleToStr(styles.docItem)}" onclick="loadDocument(\\'' + doc.id + '\\')" onmouseover="this.style.background=\\'#222\\'" onmouseout="this.style.background=\\'transparent\\'">' +
              '<div style="${styleToStr(styles.docItemTitle)}">' + escapeStr(doc.title) + '</div>' +
              '<div style="${styleToStr(styles.docItemDate)}">' + new Date(doc.updatedAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit' }) + '</div>' +
            '</div>'
          ).join('');
        }

        function escapeStr(s) {
          const d = document.createElement('div');
          d.textContent = s;
          return d.innerHTML;
        }
      `),
    ),
  );

  return ssr(template);
};

export const renderPreviewOnly = (html: string): string => html;

import { renderMarkdown } from "./markdown";
import { renderPage } from "./render";
import { saveDocument, listDocuments, getDocument, deleteDocument } from "./store";
import type { SaveDocumentRequest } from "./types";

const PORT = 3000;

const jsonResponse = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { "Content-Type": "application/json" },
  });

const htmlResponse = (html: string, status = 200): Response =>
  new Response(html, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const textResponse = (text: string, status = 200): Response =>
  new Response(text, {
    status,
    headers: { "Content-Type": "text/html; charset=utf-8" },
  });

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url);
    const { pathname } = url;
    const method = req.method;

    // Main page
    if (pathname === "/" && method === "GET") {
      const docs = await listDocuments();
      const html = renderPage(docs);
      return htmlResponse(html);
    }

    // Live preview endpoint
    if (pathname === "/preview" && method === "POST") {
      const markdown = await req.text();
      const rendered = renderMarkdown(markdown);
      return textResponse(rendered);
    }

    // Save / create document
    if (pathname === "/documents" && method === "POST") {
      const body = (await req.json()) as SaveDocumentRequest;
      if (!body.title && !body.content) {
        return jsonResponse({ error: "Title or content required" }, 400);
      }
      const doc = await saveDocument({
        title: body.title || "Untitled",
        content: body.content ?? "",
        id: body.id,
      });
      return jsonResponse(doc, 201);
    }

    // List documents
    if (pathname === "/documents" && method === "GET") {
      const docs = await listDocuments();
      return jsonResponse(docs);
    }

    // Get single document
    const docMatch = pathname.match(/^\/documents\/([^/]+)$/);
    if (docMatch && method === "GET") {
      const doc = await getDocument(docMatch[1]);
      if (!doc) return jsonResponse({ error: "Not found" }, 404);
      return jsonResponse(doc);
    }

    // Delete document
    if (docMatch && method === "DELETE") {
      const deleted = await deleteDocument(docMatch[1]);
      if (!deleted) return jsonResponse({ error: "Not found" }, 404);
      return jsonResponse({ ok: true });
    }

    return jsonResponse({ error: "Not found" }, 404);
  },
});

