export type RGB = { r: number; g: number; b: number }
export type HSL = { h: number; s: number; l: number }

export type PaletteColor = {
  hex: string
  rgb: RGB
  hsl: HSL
}

export type HarmonyRule =
  | 'complementary'
  | 'analogous'
  | 'triadic'
  | 'split-complementary'
  | 'tetradic'

const clamp = (n: number, min: number, max: number): number =>
  Math.min(max, Math.max(min, n))

const round = (n: number, decimals = 1): number =>
  Math.round(n * 10 ** decimals) / 10 ** decimals

export const hexToRgb = (hex: string): RGB => {
  const cleaned = hex.replace(/^#/, '')
  const expanded =
    cleaned.length === 3
      ? cleaned
          .split('')
          .map((c) => c + c)
          .join('')
      : cleaned
  const num = parseInt(expanded, 16)
  return {
    r: (num >> 16) & 255,
    g: (num >> 8) & 255,
    b: num & 255,
  }
}

export const rgbToHex = (rgb: RGB): string => {
  const toHex = (n: number) =>
    clamp(Math.round(n), 0, 255).toString(16).padStart(2, '0')
  return `#${toHex(rgb.r)}${toHex(rgb.g)}${toHex(rgb.b)}`
}

export const rgbToHsl = (rgb: RGB): HSL => {
  const r = rgb.r / 255
  const g = rgb.g / 255
  const b = rgb.b / 255
  const max = Math.max(r, g, b)
  const min = Math.min(r, g, b)
  const delta = max - min
  const l = (max + min) / 2

  if (delta === 0) {
    return { h: 0, s: 0, l: round(l * 100) }
  }

  const s = delta / (1 - Math.abs(2 * l - 1))
  let h: number
  if (max === r) {
    h = ((g - b) / delta + (g < b ? 6 : 0)) * 60
  } else if (max === g) {
    h = ((b - r) / delta + 2) * 60
  } else {
    h = ((r - g) / delta + 4) * 60
  }

  return {
    h: round(h % 360),
    s: round(clamp(s * 100, 0, 100)),
    l: round(clamp(l * 100, 0, 100)),
  }
}

export const hslToRgb = (hsl: HSL): RGB => {
  const h = hsl.h
  const s = hsl.s / 100
  const l = hsl.l / 100
  const c = (1 - Math.abs(2 * l - 1)) * s
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = l - c / 2

  let r1: number, g1: number, b1: number
  if (h < 60) {
    ;[r1, g1, b1] = [c, x, 0]
  } else if (h < 120) {
    ;[r1, g1, b1] = [x, c, 0]
  } else if (h < 180) {
    ;[r1, g1, b1] = [0, c, x]
  } else if (h < 240) {
    ;[r1, g1, b1] = [0, x, c]
  } else if (h < 300) {
    ;[r1, g1, b1] = [x, 0, c]
  } else {
    ;[r1, g1, b1] = [c, 0, x]
  }

  return {
    r: Math.round((r1 + m) * 255),
    g: Math.round((g1 + m) * 255),
    b: Math.round((b1 + m) * 255),
  }
}

export const hexToHsl = (hex: string): HSL => rgbToHsl(hexToRgb(hex))

export const hslToHex = (hsl: HSL): string => rgbToHex(hslToRgb(hsl))

const rotateHue = (h: number, degrees: number): number =>
  (h + degrees + 360) % 360

const hslToPaletteColor = (hsl: HSL): PaletteColor => {
  const rgb = hslToRgb(hsl)
  return {
    hex: rgbToHex(rgb),
    rgb,
    hsl,
  }
}

export const isValidHex = (hex: string): boolean =>
  /^#?([0-9a-fA-F]{3}|[0-9a-fA-F]{6})$/.test(hex)

export const generatePalette = (
  baseHex: string,
  rule: HarmonyRule
): PaletteColor[] => {
  const baseHsl = hexToHsl(baseHex)
  const { h, s, l } = baseHsl
  const base = hslToPaletteColor(baseHsl)

  const make = (hue: number): PaletteColor =>
    hslToPaletteColor({ h: rotateHue(h, hue), s, l })

  switch (rule) {
    case 'complementary':
      return [base, make(180)]

    case 'analogous':
      return [make(-30), base, make(30)]

    case 'triadic':
      return [base, make(120), make(240)]

    case 'split-complementary':
      return [base, make(150), make(210)]

    case 'tetradic':
      return [base, make(90), make(180), make(270)]
  }
}

export const formatRgb = (rgb: RGB): string =>
  `rgb(${rgb.r}, ${rgb.g}, ${rgb.b})`

export const formatHsl = (hsl: HSL): string =>
  `hsl(${hsl.h}, ${hsl.s}%, ${hsl.l}%)`

import type { RGB } from './color-utils'

export type WCAGLevel = 'AA' | 'AAA'
export type TextSize = 'normal' | 'large'

export type ContrastResult = {
  ratio: number
  ratioLabel: string
  aa: { normal: boolean; large: boolean }
  aaa: { normal: boolean; large: boolean }
}

const srgbToLinear = (channel: number): number => {
  const c = channel / 255
  return c <= 0.04045 ? c / 12.92 : ((c + 0.055) / 1.055) ** 2.4
}

export const relativeLuminance = (rgb: RGB): number =>
  0.2126 * srgbToLinear(rgb.r) +
  0.7152 * srgbToLinear(rgb.g) +
  0.0722 * srgbToLinear(rgb.b)

export const contrastRatio = (rgb1: RGB, rgb2: RGB): number => {
  const l1 = relativeLuminance(rgb1)
  const l2 = relativeLuminance(rgb2)
  const lighter = Math.max(l1, l2)
  const darker = Math.min(l1, l2)
  return (lighter + 0.05) / (darker + 0.05)
}

export const checkContrast = (rgb1: RGB, rgb2: RGB): ContrastResult => {
  const ratio = contrastRatio(rgb1, rgb2)
  const rounded = Math.round(ratio * 100) / 100
  return {
    ratio: rounded,
    ratioLabel: `${rounded.toFixed(2)}:1`,
    aa: {
      normal: ratio >= 4.5,
      large: ratio >= 3,
    },
    aaa: {
      normal: ratio >= 7,
      large: ratio >= 4.5,
    },
  }
}

