import {
  generatePalette,
  isValidHex,
  formatRgb,
  formatHsl,
} from './color-utils'
import type { HarmonyRule, PaletteColor } from './color-utils'
import { checkContrast } from './contrast'
import type { ContrastResult } from './contrast'
import { renderToString } from './render'

type AppState = {
  baseHex: string
  rule: HarmonyRule
  colors: PaletteColor[]
  fgIndex: number
  bgIndex: number
  contrastResult: ContrastResult | null
}

const DATA_PATH = './data/palettes.jsonl'

const DEFAULT_BASE = '#3a86ff'
const DEFAULT_RULE: HarmonyRule = 'complementary'

const createState = (
  baseHex = DEFAULT_BASE,
  rule: HarmonyRule = DEFAULT_RULE
): AppState => {
  const colors = generatePalette(baseHex, rule)
  return {
    baseHex,
    rule,
    colors,
    fgIndex: 0,
    bgIndex: colors.length > 1 ? 1 : 0,
    contrastResult: null,
  }
}

const savePalette = async (state: AppState): Promise<void> => {
  const entry = {
    timestamp: new Date().toISOString(),
    baseHex: state.baseHex,
    rule: state.rule,
    colors: state.colors.map((c) => c.hex),
  }
  const file = Bun.file(DATA_PATH)
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(DATA_PATH, existing + JSON.stringify(entry) + '\n')
}

const handleGenerate = async (
  baseHex: string,
  rule: HarmonyRule
): Promise<AppState> => {
  const hex = isValidHex(baseHex)
    ? baseHex.startsWith('#')
      ? baseHex
      : `#${baseHex}`
    : DEFAULT_BASE
  const state = createState(hex, rule)
  await savePalette(state)
  return state
}

const handleContrastCheck = (state: AppState): AppState => {
  const fg = state.colors[state.fgIndex]
  const bg = state.colors[state.bgIndex]
  if (!fg || !bg) return state
  return {
    ...state,
    contrastResult: checkContrast(fg.rgb, bg.rgb),
  }
}

const copyToClipboard = async (value: string): Promise<boolean> => {
  try {
    const proc = Bun.spawn(['pbcopy'], {
      stdin: 'pipe',
    })
    proc.stdin.write(value)
    proc.stdin.end()
    await proc.exited
    return true
  } catch {
    return false
  }
}

export const serve = () => {
  let state = createState()

  return Bun.serve({
    port: 3100,
    fetch: async (req) => {
      const url = new URL(req.url)

      if (url.pathname === '/' && req.method === 'GET') {
        const html = await renderToString(
          state.baseHex,
          state.rule,
          state.colors,
          state.contrastResult,
          state.fgIndex,
          state.bgIndex
        )
        return new Response(wrapHtml(html), {
          headers: { 'Content-Type': 'text/html; charset=utf-8' },
        })
      }

      if (url.pathname === '/api/generate' && req.method === 'POST') {
        const body = (await req.json()) as {
          baseHex?: string
          rule?: HarmonyRule
        }
        state = await handleGenerate(
          body.baseHex ?? state.baseHex,
          body.rule ?? state.rule
        )
        return Response.json({
          colors: state.colors,
          baseHex: state.baseHex,
          rule: state.rule,
        })
      }

      if (url.pathname === '/api/contrast' && req.method === 'POST') {
        const body = (await req.json()) as {
          fgIndex?: number
          bgIndex?: number
        }
        state.fgIndex = body.fgIndex ?? state.fgIndex
        state.bgIndex = body.bgIndex ?? state.bgIndex
        state = handleContrastCheck(state)
        return Response.json({
          result: state.contrastResult,
          fgColor: state.colors[state.fgIndex],
          bgColor: state.colors[state.bgIndex],
        })
      }

      if (url.pathname === '/api/copy' && req.method === 'POST') {
        const body = (await req.json()) as { value: string }
        const ok = await copyToClipboard(body.value)
        return Response.json({ ok })
      }

      if (url.pathname === '/api/palette' && req.method === 'GET') {
        return Response.json({
          baseHex: state.baseHex,
          rule: state.rule,
          colors: state.colors,
          contrastResult: state.contrastResult,
          fgIndex: state.fgIndex,
          bgIndex: state.bgIndex,
        })
      }

      return new Response('Not Found', { status: 404 })
    },
  })
}

const wrapHtml = (body: string): string => `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1" />
  <title>Color Palette Generator</title>
  <style>
    *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
    body { background: #fafafa; }
    select:focus, input:focus { border-color: #4a4aff !important; }
    button:hover { opacity: 0.9; }
    [p-trigger="copy-value:click"]:hover { background-color: #f0f0f8; }
  </style>
</head>
<body>
  ${body}
  <script>
    const api = async (path, body) => {
      const res = await fetch(path, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(body),
      });
      return res.json();
    };

    const showToast = (msg) => {
      const toast = document.querySelector('[p-target="copy-toast"]');
      if (!toast) return;
      toast.textContent = msg;
      toast.style.opacity = '1';
      setTimeout(() => { toast.style.opacity = '0'; }, 1500);
    };

    const reload = () => location.reload();

    document.addEventListener('click', async (e) => {
      const copyEl = e.target.closest('[p-trigger="copy-value:click"]');
      if (copyEl) {
        const val = copyEl.dataset.value || copyEl.textContent.trim();
        try {
          await navigator.clipboard.writeText(val);
          showToast('Copied ' + val);
        } catch {
          await api('/api/copy', { value: val });
          showToast('Copied ' + val);
        }
        return;
      }

      const genBtn = e.target.closest('[p-trigger="generate:click"]');
      if (genBtn) {
        const hex = document.querySelector('[p-target="hex-input"]').value;
        const rule = document.querySelector('[p-target="rule-select"]').value;
        await api('/api/generate', { baseHex: hex, rule });
        reload();
        return;
      }

      const checkBtn = e.target.closest('[p-trigger="check-contrast:click"]');
      if (checkBtn) {
        const fg = parseInt(document.querySelector('[p-target="fg-select"]').value);
        const bg = parseInt(document.querySelector('[p-target="bg-select"]').value);
        await api('/api/contrast', { fgIndex: fg, bgIndex: bg });
        reload();
        return;
      }
    });

    document.addEventListener('input', (e) => {
      const picker = e.target.closest('[p-trigger="color-pick:input"]');
      if (picker) {
        const hexInput = document.querySelector('[p-target="hex-input"]');
        if (hexInput) hexInput.value = picker.value;
      }

      const hexInput = e.target.closest('[p-trigger="hex-input:input"]');
      if (hexInput) {
        const picker = document.querySelector('[p-target="color-picker"]');
        if (picker && /^#[0-9a-fA-F]{6}$/.test(hexInput.value)) {
          picker.value = hexInput.value;
        }
      }
    });
  </script>
</body>
</html>`;

// Auto-start when run directly
const server = serve()
console.log('Color Palette Generator running at http://localhost:' + server.port)

