import type { Project, GalleryFilters, GalleryState, SortField, SortDirection } from './types'

const DATA_PATH = './data/projects.json'

export const loadProjects = async (): Promise<Project[]> => {
  const file = Bun.file(DATA_PATH)
  const raw = await file.json()
  return raw as Project[]
}

export const saveProjects = async (projects: Project[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(projects, null, 2))
}

export const filterByTag = (projects: Project[], tag: string | null): Project[] => {
  if (!tag) return projects
  const lower = tag.toLowerCase()
  return projects.filter((p) => p.tags.some((t) => t.toLowerCase() === lower))
}

export const searchByTitle = (projects: Project[], query: string): Project[] => {
  if (!query.trim()) return projects
  const lower = query.toLowerCase()
  return projects.filter((p) => p.title.toLowerCase().includes(lower))
}

export const sortProjects = (
  projects: Project[],
  field: SortField,
  direction: SortDirection,
): Project[] => {
  const sorted = [...projects]
  sorted.sort((a, b) => {
    const compare =
      field === 'title'
        ? a.title.localeCompare(b.title)
        : a.dateAdded.localeCompare(b.dateAdded)
    return direction === 'asc' ? compare : -compare
  })
  return sorted
}

export const applyFilters = (projects: Project[], filters: GalleryFilters): Project[] => {
  let result = projects
  result = searchByTitle(result, filters.search)
  result = filterByTag(result, filters.tag)
  result = sortProjects(result, filters.sortField, filters.sortDirection)
  return result
}

export const getAllTags = (projects: Project[]): string[] => {
  const tagSet = new Set<string>()
  for (const p of projects) {
    for (const t of p.tags) {
      tagSet.add(t)
    }
  }
  return [...tagSet].sort()
}

export const findProject = (projects: Project[], id: string): Project | undefined =>
  projects.find((p) => p.id === id)

