  if (!(await marker.exists())) {
    await Bun.write(marker, '')
  }
}

export const saveDrawing = async (drawing: Drawing): Promise<void> => {
  await ensureDataDir()
  const filePath = `${DATA_DIR}/${drawing.id}.json`
  await Bun.write(filePath, JSON.stringify(drawing, null, 2))
}

export const loadDrawing = async (id: string): Promise<Drawing | null> => {
  const filePath = `${DATA_DIR}/${id}.json`
  const file = Bun.file(filePath)
  if (!(await file.exists())) return null
  return file.json()
}

export const deleteDrawing = async (id: string): Promise<boolean> => {
  const filePath = `${DATA_DIR}/${id}.json`
  const file = Bun.file(filePath)
  if (!(await file.exists())) return false
  const { rm } = await import('node:fs/promises')
  await rm(filePath)
  return true
}

export const listDrawings = async (): Promise<DrawingMeta[]> => {
  await ensureDataDir()
  const glob = new Bun.Glob('*.json')
  const drawings: DrawingMeta[] = []

  for await (const path of glob.scan(DATA_DIR)) {
    const file = Bun.file(`${DATA_DIR}/${path}`)
    const data: Drawing = await file.json()
    drawings.push({
      id: data.id,
      name: data.name,
      thumbnailUrl: null,
      updatedAt: data.updatedAt,
    })
  }

  return drawings.sort(
    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
  )
}

