const clientScript = `(()=>{
const W=800,H=600;
const mc=document.getElementById('main-canvas');
const mctx=mc.getContext('2d');
const lp=document.getElementById('layers-panel');

let layers=[];
let aIdx=0;
let tool='pen';
let color='#000000';
let sz=5;
let isDraw=false;
let sx=0,sy=0,lx=0,ly=0;
let undoSt=[],redoSt=[];
let pvC=null,pvCtx=null;
let projectId=null;

const mkCanvas=()=>{const c=document.createElement('canvas');c.width=W;c.height=H;return c};

const addLayer=(name)=>{
  const c=mkCanvas();
  layers.push({canvas:c,ctx:c.getContext('2d'),visible:true,name,id:crypto.randomUUID()});
  composite();updateUI();
};

const rmLayer=(i)=>{
  if(layers.length<=1)return;
  layers.splice(i,1);
  if(aIdx>=layers.length)aIdx=layers.length-1;
  composite();updateUI();
};

const togVis=(i)=>{layers[i].visible=!layers[i].visible;composite();updateUI()};
const setActive=(i)=>{aIdx=i;updateUI()};

const composite=()=>{
  mctx.clearRect(0,0,W,H);
  mctx.fillStyle='#ffffff';
  mctx.fillRect(0,0,W,H);
  for(const l of layers){if(l.visible)mctx.drawImage(l.canvas,0,0)}
};

const updateUI=()=>{
  lp.innerHTML='';
  layers.forEach((l,i)=>{
    const d=document.createElement('div');
    d.className='layer-item'+(i===aIdx?' active':'');

    const th=document.createElement('canvas');
    th.width=60;th.height=45;th.className='layer-thumb';
    const tc=th.getContext('2d');
    tc.fillStyle='#fff';tc.fillRect(0,0,60,45);
    tc.drawImage(l.canvas,0,0,60,45);

    const vb=document.createElement('button');
    vb.className='vis-btn';vb.textContent=l.visible?'ON':'--';
    vb.onclick=(e)=>{e.stopPropagation();togVis(i)};

    const nm=document.createElement('span');
    nm.className='layer-name';nm.textContent=l.name;

    const db=document.createElement('button');
    db.className='del-btn';db.textContent='x';
    db.onclick=(e)=>{e.stopPropagation();rmLayer(i)};

    d.onclick=()=>setActive(i);
    d.appendChild(th);d.appendChild(vb);d.appendChild(nm);
    if(layers.length>1)d.appendChild(db);
    lp.appendChild(d);
  });
  updUndoRedo();
};

const capState=()=>layers.map(l=>({id:l.id,data:l.canvas.toDataURL()}));

const restState=(st)=>{
  let pending=st.length;
  st.forEach(s=>{
    const l=layers.find(x=>x.id===s.id);
    if(!l){pending--;if(!pending){composite();updateUI()}return}
    const img=new Image();
    img.onload=()=>{l.ctx.clearRect(0,0,W,H);l.ctx.drawImage(img,0,0);pending--;if(!pending){composite();updateUI()}};
    img.src=s.data;
  });
};

const pushUndo=()=>{undoSt.push(capState());if(undoSt.length>50)undoSt.shift();redoSt=[];updUndoRedo()};
const undo=()=>{if(!undoSt.length)return;redoSt.push(capState());restState(undoSt.pop())};
const redo=()=>{if(!redoSt.length)return;undoSt.push(capState());restState(redoSt.pop())};
const updUndoRedo=()=>{
  const ub=document.getElementById('btn-undo');
  const rb=document.getElementById('btn-redo');
  if(ub)ub.disabled=!undoSt.length;
  if(rb)rb.disabled=!redoSt.length;
};

const getPos=(e)=>{const r=mc.getBoundingClientRect();return{x:e.clientX-r.left,y:e.clientY-r.top}};

const onDown=(e)=>{
  isDraw=true;
  const p=getPos(e);sx=lx=p.x;sy=ly=p.y;

  if(tool==='pen'||tool==='eraser'){
    pushUndo();
    const ctx=layers[aIdx].ctx;
    ctx.beginPath();ctx.moveTo(p.x,p.y);
    if(tool==='eraser')ctx.globalCompositeOperation='destination-out';
    ctx.lineCap='round';ctx.lineJoin='round';ctx.lineWidth=sz;
    ctx.strokeStyle=tool==='eraser'?'rgba(0,0,0,1)':color;
  } else {
    pushUndo();
    pvC=mkCanvas();pvCtx=pvC.getContext('2d');
  }
};

const onMove=(e)=>{
  if(!isDraw)return;
  const p=getPos(e);

  if(tool==='pen'||tool==='eraser'){
    const ctx=layers[aIdx].ctx;
    ctx.lineTo(p.x,p.y);ctx.stroke();
    lx=p.x;ly=p.y;composite();
  } else if(pvCtx){
    pvCtx.clearRect(0,0,W,H);
    pvCtx.strokeStyle=color;pvCtx.lineWidth=sz;pvCtx.lineCap='round';

    if(tool==='rectangle'){
      pvCtx.strokeRect(sx,sy,p.x-sx,p.y-sy);
    } else if(tool==='circle'){
      const rx=Math.abs(p.x-sx)/2,ry=Math.abs(p.y-sy)/2;
      const cx=sx+(p.x-sx)/2,cy=sy+(p.y-sy)/2;
      pvCtx.beginPath();pvCtx.ellipse(cx,cy,rx,ry,0,0,Math.PI*2);pvCtx.stroke();
    } else if(tool==='line'){
      pvCtx.beginPath();pvCtx.moveTo(sx,sy);pvCtx.lineTo(p.x,p.y);pvCtx.stroke();
    }
    composite();mctx.drawImage(pvC,0,0);
  }
};

const onUp=()=>{
  if(!isDraw)return;isDraw=false;
  if(tool==='pen'||tool==='eraser'){
    layers[aIdx].ctx.globalCompositeOperation='source-over';
  } else if(pvC){
    layers[aIdx].ctx.drawImage(pvC,0,0);
    pvC=null;pvCtx=null;
  }
  composite();updateUI();
};

const clearAll=()=>{pushUndo();layers.forEach(l=>l.ctx.clearRect(0,0,W,H));composite();updateUI()};

const savePng=()=>{
  composite();
  const a=document.createElement('a');a.download='drawing.png';
  a.href=mc.toDataURL('image/png');a.click();
};

const saveProject=async()=>{
  const data={
    id:projectId||crypto.randomUUID(),
    name:document.getElementById('drawing-name').value||'Untitled',
    width:W,height:H,
    layers:layers.map(l=>({id:l.id,name:l.name,visible:l.visible,opacity:1,dataUrl:l.canvas.toDataURL()})),
    activeLayerId:layers[aIdx].id,
    createdAt:new Date().toISOString(),
    updatedAt:new Date().toISOString(),
  };
  const r=await fetch('/api/drawings',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if(r.ok){const j=await r.json();projectId=j.id}
};

const loadImage=()=>{
  const inp=document.createElement('input');inp.type='file';inp.accept='image/png,image/jpeg';
  inp.onchange=(e)=>{
    const f=e.target.files[0];if(!f)return;
    const rd=new FileReader();
    rd.onload=(ev)=>{
      const img=new Image();
      img.onload=()=>{pushUndo();layers[aIdx].ctx.drawImage(img,0,0,W,H);composite();updateUI()};
      img.src=ev.target.result;
    };
    rd.readAsDataURL(f);
  };
  inp.click();
};

const selectTool=(t)=>{
  tool=t;
  document.querySelectorAll('.tool-btn').forEach(b=>b.classList.remove('active'));
  const el=document.querySelector('[data-tool="'+t+'"]');
  if(el)el.classList.add('active');
  mc.style.cursor='crosshair';
};

const loadProject=(d)=>{
  if(!d||!d.layers)return;
  projectId=d.id;
  document.getElementById('drawing-name').value=d.name||'Untitled';
  layers=[];
  let pending=d.layers.length;
  d.layers.forEach((ld)=>{
    const c=mkCanvas();
    const ctx=c.getContext('2d');
    const layer={canvas:c,ctx,visible:ld.visible,name:ld.name,id:ld.id};
    layers.push(layer);
    if(ld.dataUrl){
      const img=new Image();
      img.onload=()=>{ctx.drawImage(img,0,0);pending--;if(!pending){aIdx=Math.max(0,layers.findIndex(x=>x.id===d.activeLayerId));composite();updateUI()}};
      img.src=ld.dataUrl;
    } else {pending--;if(!pending){aIdx=0;composite();updateUI()}}
  });
};

// Init
if(typeof INIT_DRAWING!=='undefined'&&INIT_DRAWING){
  loadProject(INIT_DRAWING);
} else {
  addLayer('Background');addLayer('Layer 1');aIdx=1;composite();updateUI();
}

// Canvas events
mc.addEventListener('mousedown',onDown);
mc.addEventListener('mousemove',onMove);
mc.addEventListener('mouseup',onUp);
mc.addEventListener('mouseleave',onUp);
mc.addEventListener('touchstart',(e)=>{e.preventDefault();onDown(e.touches[0])},{passive:false});
mc.addEventListener('touchmove',(e)=>{e.preventDefault();onMove(e.touches[0])},{passive:false});
mc.addEventListener('touchend',(e)=>{e.preventDefault();onUp()},{passive:false});

// Keyboard shortcuts
document.addEventListener('keydown',(e)=>{
  if(e.ctrlKey||e.metaKey){
    if(e.key==='z'){e.preventDefault();e.shiftKey?redo():undo()}
    if(e.key==='s'){e.preventDefault();saveProject()}
  }
});

// Toolbar events
document.querySelectorAll('.tool-btn').forEach(b=>b.addEventListener('click',()=>selectTool(b.dataset.tool)));
document.getElementById('color-picker').addEventListener('input',(e)=>{color=e.target.value});
document.getElementById('brush-size').addEventListener('input',(e)=>{
  sz=parseInt(e.target.value);document.getElementById('size-display').textContent=sz+'px';
});
document.getElementById('btn-undo').addEventListener('click',undo);
document.getElementById('btn-redo').addEventListener('click',redo);
document.getElementById('btn-clear').addEventListener('click',clearAll);
document.getElementById('btn-add-layer').addEventListener('click',()=>addLayer('Layer '+(layers.length+1)));
document.getElementById('btn-save-png').addEventListener('click',savePng);
document.getElementById('btn-save').addEventListener('click',saveProject);
document.getElementById('btn-load').addEventListener('click',loadImage);
})();`

