import { renderPage } from './render'
import { saveDrawing, loadDrawing, listDrawings, deleteDrawing, savePng, loadPng } from './storage'
import type { Drawing } from './types'

const PORT = 3000

const jsonResponse = (data: unknown, status = 200) =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const htmlResponse = (html: string) =>
  new Response(html, { headers: { 'Content-Type': 'text/html; charset=utf-8' } })

Bun.serve({
  port: PORT,

  fetch: async (req) => {
    const url = new URL(req.url)
    const path = url.pathname
    const method = req.method

    // --- API: list drawings ---
    if (path === '/api/drawings' && method === 'GET') {
      const list = await listDrawings()
      return jsonResponse(list)
    }

    // --- API: save drawing ---
    if (path === '/api/drawings' && method === 'POST') {
      const drawing: Drawing = await req.json()
      drawing.updatedAt = new Date().toISOString()
      if (!drawing.createdAt) drawing.createdAt = drawing.updatedAt
      await saveDrawing(drawing)
      return jsonResponse({ id: drawing.id })
    }

    // --- API: single drawing ---
    const drawingApiMatch = path.match(/^\/api\/drawings\/([^/]+)$/)
    if (drawingApiMatch) {
      const id = drawingApiMatch[1]

      if (method === 'GET') {
        const drawing = await loadDrawing(id)
        if (!drawing) return jsonResponse({ error: 'Not found' }, 404)
        return jsonResponse(drawing)
      }

      if (method === 'DELETE') {
        const ok = await deleteDrawing(id)
        return jsonResponse({ ok })
      }
    }

    // --- API: PNG export ---
    const pngMatch = path.match(/^\/api\/drawings\/([^/]+)\/png$/)
    if (pngMatch) {
      const id = pngMatch[1]

      if (method === 'POST') {
        const buffer = Buffer.from(await req.arrayBuffer())
        await savePng(id, buffer)
        return jsonResponse({ ok: true })
      }

      if (method === 'GET') {
        const png = await loadPng(id)
        if (!png) return jsonResponse({ error: 'Not found' }, 404)
        return new Response(png, { headers: { 'Content-Type': 'image/png' } })
      }
    }

    // --- Page: load saved drawing ---
    const pageMatch = path.match(/^\/drawings\/([^/]+)$/)
    if (pageMatch) {
      const drawing = await loadDrawing(pageMatch[1])
      return htmlResponse(renderPage(drawing))
    }

    // --- Page: new canvas ---
    if (path === '/' || path === '/new') {
      return htmlResponse(renderPage())
    }

    return jsonResponse({ error: 'Not found' }, 404)
  },
})

