import type { Playlist, Song } from './types'

const DATA_PATH = `${import.meta.dir}/data/playlists.json`

const generateId = (): string => crypto.randomUUID()

const readPlaylists = async (): Promise<Playlist[]> => {
  const file = Bun.file(DATA_PATH)
  if (!(await file.exists())) return []
  return file.json()
}

const writePlaylists = async (playlists: Playlist[]): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(playlists, null, 2))
}

export const getAllPlaylists = async (): Promise<Playlist[]> => {
  return readPlaylists()
}

export const getPlaylist = async (id: string): Promise<Playlist | undefined> => {
  const playlists = await readPlaylists()
  return playlists.find((p) => p.id === id)
}

export const createPlaylist = async (name: string): Promise<Playlist> => {
  const playlists = await readPlaylists()
  const playlist: Playlist = {
    id: generateId(),
    name,
    songs: [],
    createdAt: new Date().toISOString(),
  }
  playlists.push(playlist)
  await writePlaylists(playlists)
  return playlist
}

export const deletePlaylist = async (id: string): Promise<boolean> => {
  const playlists = await readPlaylists()
  const idx = playlists.findIndex((p) => p.id === id)
  if (idx === -1) return false
  playlists.splice(idx, 1)
  await writePlaylists(playlists)
  return true
}

export const addSong = async (
  playlistId: string,
  song: Omit<Song, 'id'>,
): Promise<Song | null> => {
  const playlists = await readPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return null
  const newSong: Song = { id: generateId(), ...song }
  playlist.songs.push(newSong)
  await writePlaylists(playlists)
  return newSong
}

export const removeSong = async (playlistId: string, songId: string): Promise<boolean> => {
  const playlists = await readPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const idx = playlist.songs.findIndex((s) => s.id === songId)
  if (idx === -1) return false
  playlist.songs.splice(idx, 1)
  await writePlaylists(playlists)
  return true
}

export const reorderSong = async (
  playlistId: string,
  songId: string,
  newIndex: number,
): Promise<boolean> => {
  const playlists = await readPlaylists()
  const playlist = playlists.find((p) => p.id === playlistId)
  if (!playlist) return false
  const oldIndex = playlist.songs.findIndex((s) => s.id === songId)
  if (oldIndex === -1) return false
  const clamped = Math.max(0, Math.min(newIndex, playlist.songs.length - 1))
  const [song] = playlist.songs.splice(oldIndex, 1)
  playlist.songs.splice(clamped, 0, song)
  await writePlaylists(playlists)
  return true
}

import type { PlaybackState, RepeatMode, Song } from './types'
import { getPlaylist } from './store'

let state: PlaybackState = {
  currentPlaylistId: null,
  currentSongId: null,
  isPlaying: false,
  positionSeconds: 0,
  shuffle: false,
  repeat: 'off',
  shuffleOrder: [],
  shuffleIndex: 0,
}

const shuffleArray = (arr: string[]): string[] => {
  const shuffled = [...arr]
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]]
  }
  return shuffled
}

const buildShuffleOrder = (songs: Song[], currentSongId: string | null): string[] => {
  const ids = songs.map((s) => s.id)
  const shuffled = shuffleArray(ids)
  if (currentSongId) {
    const idx = shuffled.indexOf(currentSongId)
    if (idx > 0) {
      ;[shuffled[0], shuffled[idx]] = [shuffled[idx], shuffled[0]]
    }
  }
  return shuffled
}

const getCurrentSongIndex = (songs: Song[]): number => {
  if (!state.currentSongId) return -1
  if (state.shuffle) {
    return state.shuffleIndex
  }
  return songs.findIndex((s) => s.id === state.currentSongId)
}

const getNextSongId = (songs: Song[]): string | null => {
  if (songs.length === 0) return null

  if (state.repeat === 'one') {
    return state.currentSongId
  }

  if (state.shuffle) {
    const nextIdx = state.shuffleIndex + 1
    if (nextIdx >= state.shuffleOrder.length) {
      if (state.repeat === 'all') {
        state.shuffleOrder = buildShuffleOrder(songs, null)
        state.shuffleIndex = 0
        return state.shuffleOrder[0] ?? null
      }
      return null
    }
    state.shuffleIndex = nextIdx
    return state.shuffleOrder[nextIdx] ?? null
  }

  const currentIdx = songs.findIndex((s) => s.id === state.currentSongId)
  const nextIdx = currentIdx + 1
  if (nextIdx >= songs.length) {
    if (state.repeat === 'all') return songs[0]?.id ?? null
    return null
  }
  return songs[nextIdx]?.id ?? null
}

const getPreviousSongId = (songs: Song[]): string | null => {
  if (songs.length === 0) return null

  if (state.repeat === 'one') {
    return state.currentSongId
  }

  if (state.shuffle) {
    const prevIdx = state.shuffleIndex - 1
    if (prevIdx < 0) {
      if (state.repeat === 'all') {
        state.shuffleIndex = state.shuffleOrder.length - 1
        return state.shuffleOrder[state.shuffleIndex] ?? null
      }
      return state.currentSongId
    }
    state.shuffleIndex = prevIdx
    return state.shuffleOrder[prevIdx] ?? null
  }

  const currentIdx = songs.findIndex((s) => s.id === state.currentSongId)
  const prevIdx = currentIdx - 1
  if (prevIdx < 0) {
    if (state.repeat === 'all') return songs[songs.length - 1]?.id ?? null
    return state.currentSongId
  }
  return songs[prevIdx]?.id ?? null
}

export const getPlaybackState = (): PlaybackState => ({ ...state })

export const play = async (playlistId?: string, songId?: string): Promise<PlaybackState> => {
  if (playlistId && songId) {
    const playlist = await getPlaylist(playlistId)
    if (!playlist) return state
    const song = playlist.songs.find((s) => s.id === songId)
    if (!song) return state

    state.currentPlaylistId = playlistId
    state.currentSongId = songId
    state.positionSeconds = 0
    state.isPlaying = true

    if (state.shuffle) {
      state.shuffleOrder = buildShuffleOrder(playlist.songs, songId)
      state.shuffleIndex = 0
    }
  } else {
    state.isPlaying = true
  }
  return { ...state }
}

export const pause = (): PlaybackState => {
  state.isPlaying = false
  return { ...state }
}

export const skip = async (): Promise<PlaybackState> => {
  if (!state.currentPlaylistId) return state
  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist) return state

  const nextId = getNextSongId(playlist.songs)
  if (nextId) {
    state.currentSongId = nextId
    state.positionSeconds = 0
    state.isPlaying = true
  } else {
    state.isPlaying = false
    state.positionSeconds = 0
  }
  return { ...state }
}

export const previous = async (): Promise<PlaybackState> => {
  if (!state.currentPlaylistId) return state

  if (state.positionSeconds > 3) {
    state.positionSeconds = 0
    return { ...state }
  }

  const playlist = await getPlaylist(state.currentPlaylistId)
  if (!playlist) return state

  const prevId = getPreviousSongId(playlist.songs)
  if (prevId) {
    state.currentSongId = prevId
    state.positionSeconds = 0
    state.isPlaying = true
  }
  return { ...state }
}

export const seek = (position: number): PlaybackState => {
  state.positionSeconds = Math.max(0, position)
  return { ...state }
}

export const toggleShuffle = async (): Promise<PlaybackState> => {
  state.shuffle = !state.shuffle
  if (state.shuffle && state.currentPlaylistId) {
    const playlist = await getPlaylist(state.currentPlaylistId)
    if (playlist) {
      state.shuffleOrder = buildShuffleOrder(playlist.songs, state.currentSongId)
      state.shuffleIndex = 0
    }
  }
  return { ...state }
}

export const cycleRepeat = (): PlaybackState => {
  const modes: RepeatMode[] = ['off', 'all', 'one']
  const currentIdx = modes.indexOf(state.repeat)
  state.repeat = modes[(currentIdx + 1) % modes.length]
  return { ...state }
}

