const renderNowPlaying = (
  playback: PlaybackState,
  currentSong: Song | null,
): string => {
  if (!currentSong) {
    return h('div', { style: styleAttr(styles.nowPlaying) },
      h('div', { style: styleAttr(styles.emptyState) }, 'No song playing'),
    )
  }

  const progress = currentSong.durationSeconds > 0
    ? (playback.positionSeconds / currentSong.durationSeconds) * 100
    : 0

  const shuffleStyle = {
    ...styles.controlBtn,
    ...(playback.shuffle ? styles.activeMode : {}),
  }

  const repeatStyle = {
    ...styles.controlBtn,
    ...(playback.repeat !== 'off' ? styles.activeMode : {}),
  }

  const repeatLabel = playback.repeat === 'one' ? '\uD83D\uDD02' : '\uD83D\uDD01'

  return h('div', { style: styleAttr(styles.nowPlaying) },
    currentSong.albumArtUrl
      ? h('img', {
          src: currentSong.albumArtUrl,
          alt: currentSong.album,
          style: styleAttr(styles.nowPlayingArt),
        })
      : h('div', { style: styleAttr(styles.nowPlayingArt) }),
    h('div', { style: styleAttr(styles.nowPlayingInfo) },
      h('div', { style: styleAttr(styles.nowPlayingTitle) }, currentSong.title),
      h('div', { style: styleAttr(styles.nowPlayingArtist) },
        `${currentSong.artist} \u2014 ${currentSong.album}`),
    ),
    h('div', { style: styleAttr(styles.controls) },
      h('div', { style: styleAttr(styles.controlButtons) },
        h('button', {
          style: styleAttr(shuffleStyle),
          'p-trigger': 'click:onToggleShuffle',
          title: `Shuffle: ${playback.shuffle ? 'on' : 'off'}`,
        }, '\uD83D\uDD00'),
        h('button', {
          style: styleAttr(styles.controlBtn),
          'p-trigger': 'click:onPrevious',
          title: 'Previous',
        }, '\u23EE'),
        h('button', {
          style: styleAttr(styles.playBtn),
          'p-trigger': 'click:onPlayPause',
          title: playback.isPlaying ? 'Pause' : 'Play',
        }, playback.isPlaying ? '\u23F8' : '\u25B6'),
        h('button', {
          style: styleAttr(styles.controlBtn),
          'p-trigger': 'click:onSkip',
          title: 'Next',
        }, '\u23ED'),
        h('button', {
          style: styleAttr(repeatStyle),
          'p-trigger': 'click:onCycleRepeat',
          title: `Repeat: ${playback.repeat}`,
        }, repeatLabel),
      ),
      h('div', { style: styleAttr(styles.progressContainer) },
        h('span', { style: styleAttr(styles.progressTime) },
          formatDuration(playback.positionSeconds)),
        h('div', {
          style: styleAttr(styles.progressBar),
          'p-trigger': 'click:onSeek',
          'p-target': 'progressBar',
          'data-duration': String(currentSong.durationSeconds),
        },
          h('div', {
            style: styleAttr({
              ...styles.progressFill,
              width: `${Math.min(100, progress)}%`,
            }),
          }),
        ),
        h('span', {
          style: styleAttr({ ...styles.progressTime, textAlign: 'right' }),
        }, formatDuration(currentSong.durationSeconds)),
      ),
    ),
    h('audio', {
      id: 'audio-player',
      'p-target': 'audioPlayer',
      preload: 'none',
    }),
  )
}

