const clientScript = (): string => `
  const api = async (method, path, body) => {
    const opts = { method, headers: { 'Content-Type': 'application/json' } };
    if (body) opts.body = JSON.stringify(body);
    const res = await fetch(path, opts);
    return res.json();
  };

  document.addEventListener('submit', async (e) => {
    e.preventDefault();
    const form = e.target;
    const trigger = form.getAttribute('p-trigger') || '';

    if (trigger.includes('onCreatePlaylist')) {
      const name = form.querySelector('[name=playlistName]').value.trim();
      if (!name) return;
      await api('POST', '/api/playlists', { name });
      location.reload();
    }

    if (trigger.includes('onAddSong')) {
      const playlistId = form.getAttribute('data-playlist-id');
      const data = {
        title: form.querySelector('[name=title]').value,
        artist: form.querySelector('[name=artist]').value,
        album: form.querySelector('[name=album]').value,
        durationSeconds: Number(form.querySelector('[name=durationSeconds]').value),
        albumArtUrl: form.querySelector('[name=albumArtUrl]')?.value || '',
      };
      await api('POST', '/api/playlists/' + playlistId + '/songs', data);
      location.reload();
    }
  });

  document.addEventListener('click', async (e) => {
    const btn = e.target.closest('button');
    if (!btn) return;
    const trigger = btn.getAttribute('p-trigger') || '';

    if (trigger.includes('onDeletePlaylist')) {
      const id = btn.getAttribute('data-playlist-id');
      if (confirm('Delete this playlist?')) {
        await api('DELETE', '/api/playlists/' + id);
        location.href = '/';
      }
    }

    if (trigger.includes('onPlaySong')) {
      const songId = btn.getAttribute('data-song-id');
      const playlistId = btn.getAttribute('data-playlist-id');
      await api('POST', '/api/playback/play', { playlistId, songId });
      location.reload();
    }

    if (trigger.includes('onRemoveSong')) {
      const songId = btn.getAttribute('data-song-id');
      const playlistId = btn.getAttribute('data-playlist-id');
      await api('DELETE', '/api/playlists/' + playlistId + '/songs/' + songId);
      location.reload();
    }

    if (trigger.includes('onPlayPause')) {
      const isPlaying = btn.textContent.trim() === '\u23F8';
      if (isPlaying) {
        await api('POST', '/api/playback/pause');
      } else {
        await api('POST', '/api/playback/play');
      }
      location.reload();
    }

    if (trigger.includes('onSkip')) {
      await api('POST', '/api/playback/skip');
      location.reload();
    }

    if (trigger.includes('onPrevious')) {
      await api('POST', '/api/playback/previous');
      location.reload();
    }

    if (trigger.includes('onToggleShuffle')) {
      await api('POST', '/api/playback/shuffle');
      location.reload();
    }

    if (trigger.includes('onCycleRepeat')) {
      await api('POST', '/api/playback/repeat');
      location.reload();
    }
  });

  document.addEventListener('click', async (e) => {
    const bar = e.target.closest('[p-target="progressBar"]');
    if (!bar) return;
    const duration = Number(bar.getAttribute('data-duration'));
    const rect = bar.getBoundingClientRect();
    const ratio = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
    const position = ratio * duration;
    await api('POST', '/api/playback/seek', { position });
    location.reload();
  });

  let dragSongId = null;
  let dragPlaylistId = null;

  document.addEventListener('dragstart', (e) => {
    const row = e.target.closest('[draggable="true"]');
    if (!row) return;
    dragSongId = row.getAttribute('data-song-id');
    dragPlaylistId = row.getAttribute('data-playlist-id');
    e.dataTransfer.effectAllowed = 'move';
    row.style.opacity = '0.5';
  });

  document.addEventListener('dragend', (e) => {
    const row = e.target.closest('[draggable="true"]');
    if (row) row.style.opacity = '1';
  });

  document.addEventListener('dragover', (e) => {
    const row = e.target.closest('[draggable="true"]');
    if (row) {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
    }
  });

  document.addEventListener('drop', async (e) => {
    e.preventDefault();
    const row = e.target.closest('[draggable="true"]');
    if (!row || !dragSongId) return;
    const newIndex = Number(row.getAttribute('data-index'));
    await api('PUT', '/api/playlists/' + dragPlaylistId + '/reorder', {
      songId: dragSongId,
      newIndex,
    });
    dragSongId = null;
    dragPlaylistId = null;
    location.reload();
  });

  // Simulated playback progress ticker
  let tickInterval = null;
  const startTick = () => {
    if (tickInterval) clearInterval(tickInterval);
    tickInterval = setInterval(async () => {
      const state = await api('GET', '/api/playback');
      if (state.isPlaying) {
        await api('POST', '/api/playback/seek', { position: state.positionSeconds + 1 });
      }
    }, 1000);
  };
  startTick();
`

import {
  getAllPlaylists,
  getPlaylist,
  createPlaylist,
  deletePlaylist,
  addSong,
  removeSong,
  reorderSong,
} from './store'
import {
  getPlaybackState,
  play,
  pause,
  skip,
  previous,
  seek,
  toggleShuffle,
  cycleRepeat,
} from './playback'
import { renderPage } from './ui'

type RouteHandler = (req: Request, params: Record<string, string>) => Promise<Response>

const json = (data: unknown, status = 200): Response =>
  new Response(JSON.stringify(data), {
    status,
    headers: { 'Content-Type': 'application/json' },
  })

const html = (content: string): Response =>
  new Response(content, {
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const parseBody = async <T>(req: Request): Promise<T> => req.json() as Promise<T>

const extractParams = (
  pattern: string,
  pathname: string,
): Record<string, string> | null => {
  const patternParts = pattern.split('/')
  const pathParts = pathname.split('/')
  if (patternParts.length !== pathParts.length) return null
  const params: Record<string, string> = {}
  for (let i = 0; i < patternParts.length; i++) {
    if (patternParts[i].startsWith(':')) {
      params[patternParts[i].slice(1)] = pathParts[i]
    } else if (patternParts[i] !== pathParts[i]) {
      return null
    }
  }
  return params
}

const routes: { method: string; pattern: string; handler: RouteHandler }[] = [
  {
    method: 'GET',
    pattern: '/',
    handler: async (req) => {
      const url = new URL(req.url)
      const activePlaylistId = url.searchParams.get('playlist')
      const playlists = await getAllPlaylists()
      const playback = getPlaybackState()
      return html(renderPage(playlists, activePlaylistId, playback))
    },
  },
  {
    method: 'GET',
    pattern: '/api/playlists',
    handler: async () => json(await getAllPlaylists()),
  },
  {
    method: 'POST',
    pattern: '/api/playlists',
    handler: async (req) => {
      const { name } = await parseBody<{ name: string }>(req)
      if (!name?.trim()) return json({ error: 'Name is required' }, 400)
      const playlist = await createPlaylist(name.trim())
      return json(playlist, 201)
    },
  },
  {
    method: 'DELETE',
    pattern: '/api/playlists/:id',
    handler: async (_req, params) => {
      const ok = await deletePlaylist(params.id)
      return ok ? json({ ok: true }) : json({ error: 'Not found' }, 404)
    },
  },
  {
    method: 'POST',
    pattern: '/api/playlists/:id/songs',
    handler: async (req, params) => {
      const body = await parseBody<{
        title: string
        artist: string
        album: string
        durationSeconds: number
        albumArtUrl?: string
      }>(req)
      if (!body.title || !body.artist || !body.album || !body.durationSeconds) {
        return json({ error: 'Missing required fields' }, 400)
      }
      const song = await addSong(params.id, {
        title: body.title,
        artist: body.artist,
        album: body.album,
        durationSeconds: body.durationSeconds,
        albumArtUrl: body.albumArtUrl ?? '',
      })
      return song ? json(song, 201) : json({ error: 'Playlist not found' }, 404)
    },
  },
  {
    method: 'DELETE',
    pattern: '/api/playlists/:id/songs/:songId',
    handler: async (_req, params) => {
      const ok = await removeSong(params.id, params.songId)
      return ok ? json({ ok: true }) : json({ error: 'Not found' }, 404)
    },
  },
  {
    method: 'PUT',
    pattern: '/api/playlists/:id/reorder',
    handler: async (req, params) => {
      const { songId, newIndex } = await parseBody<{ songId: string; newIndex: number }>(req)
      const ok = await reorderSong(params.id, songId, newIndex)
      return ok ? json({ ok: true }) : json({ error: 'Not found' }, 404)
    },
  },
  {
    method: 'GET',
    pattern: '/api/playback',
    handler: async () => json(getPlaybackState()),
  },
  {
    method: 'POST',
    pattern: '/api/playback/play',
    handler: async (req) => {
      const text = await req.text()
      if (text) {
        const { playlistId, songId } = JSON.parse(text)
        return json(await play(playlistId, songId))
      }
      return json(await play())
    },
  },
  {
    method: 'POST',
    pattern: '/api/playback/pause',
    handler: async () => json(pause()),
  },
  {
    method: 'POST',
    pattern: '/api/playback/skip',
    handler: async () => json(await skip()),
  },
  {
    method: 'POST',
    pattern: '/api/playback/previous',
    handler: async () => json(await previous()),
  },
  {
    method: 'POST',
    pattern: '/api/playback/seek',
    handler: async (req) => {
      const { position } = await parseBody<{ position: number }>(req)
      return json(seek(position))
    },
  },
  {
    method: 'POST',
    pattern: '/api/playback/shuffle',
    handler: async () => json(await toggleShuffle()),
  },
  {
    method: 'POST',
    pattern: '/api/playback/repeat',
    handler: async () => json(cycleRepeat()),
  },
]

export const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const method = req.method

  for (const route of routes) {
    if (route.method !== method) continue
    const params = extractParams(route.pattern, url.pathname)
    if (params !== null) {
      return route.handler(req, params)
    }
  }

  return json({ error: 'Not found' }, 404)
}

