import type {
  PendulumParams,
  PendulumState,
  ProjectileParams,
  ProjectileState,
  SpringParams,
  SpringState,
  Vec2,
} from './types'

const DEG_TO_RAD = Math.PI / 180

// --- Pendulum ---

export const createPendulumState = (params: PendulumParams): PendulumState => {
  const theta = params.initialAngle * DEG_TO_RAD
  const alpha = -(params.gravity / params.length) * Math.sin(theta)
  const L = params.length
  return {
    theta,
    omega: 0,
    alpha,
    time: 0,
    position: { x: L * Math.sin(theta), y: -L * Math.cos(theta) },
    velocity: { x: 0, y: 0 },
    acceleration: { x: 0, y: 0 },
  }
}

export const stepPendulum = (
  state: PendulumState,
  params: PendulumParams,
  dt: number,
): PendulumState => {
  const { theta, omega } = state
  const { gravity, length: L } = params

  // RK4 integration for theta'' = -(g/L)*sin(theta)
  const f = (th: number, om: number): { dTheta: number; dOmega: number } => ({
    dTheta: om,
    dOmega: -(gravity / L) * Math.sin(th),
  })

  const k1 = f(theta, omega)
  const k2 = f(theta + 0.5 * dt * k1.dTheta, omega + 0.5 * dt * k1.dOmega)
  const k3 = f(theta + 0.5 * dt * k2.dTheta, omega + 0.5 * dt * k2.dOmega)
  const k4 = f(theta + dt * k3.dTheta, omega + dt * k3.dOmega)

  const newTheta =
    theta + (dt / 6) * (k1.dTheta + 2 * k2.dTheta + 2 * k3.dTheta + k4.dTheta)
  const newOmega =
    omega + (dt / 6) * (k1.dOmega + 2 * k2.dOmega + 2 * k3.dOmega + k4.dOmega)
  const newAlpha = -(gravity / L) * Math.sin(newTheta)

  const px = L * Math.sin(newTheta)
  const py = -L * Math.cos(newTheta)
  const vx = L * newOmega * Math.cos(newTheta)
  const vy = L * newOmega * Math.sin(newTheta)

  const tangentialAcc = L * newAlpha
  const centripetalAcc = L * newOmega * newOmega
  const ax =
    tangentialAcc * Math.cos(newTheta) + centripetalAcc * Math.sin(newTheta)
  const ay =
    tangentialAcc * Math.sin(newTheta) - centripetalAcc * Math.cos(newTheta)

  return {
    theta: newTheta,
    omega: newOmega,
    alpha: newAlpha,
    time: state.time + dt,
    position: { x: px, y: py },
    velocity: { x: vx, y: vy },
    acceleration: { x: ax, y: ay },
  }
}

// --- Projectile ---

export const createProjectileState = (
  params: ProjectileParams,
): ProjectileState => {
  const angle = params.launchAngle * DEG_TO_RAD
  const vx = params.initialVelocity * Math.cos(angle)
  const vy = params.initialVelocity * Math.sin(angle)
  const origin: Vec2 = { x: 0, y: 0 }
  return {
    time: 0,
    position: { ...origin },
    velocity: { x: vx, y: vy },
    acceleration: { x: 0, y: -params.gravity },
    trajectory: [{ ...origin }],
    landed: false,
  }
}

export const stepProjectile = (
  state: ProjectileState,
  params: ProjectileParams,
  dt: number,
): ProjectileState => {
  if (state.landed) return state

  const newTime = state.time + dt
  const angle = params.launchAngle * DEG_TO_RAD
  const v0 = params.initialVelocity
  const g = params.gravity

  const vx = v0 * Math.cos(angle)
  const vy = v0 * Math.sin(angle) - g * newTime

  const px = v0 * Math.cos(angle) * newTime
  const py = v0 * Math.sin(angle) * newTime - 0.5 * g * newTime * newTime

  const landed = py <= 0 && newTime > 0
  const clampedY = Math.max(0, py)

  const newPos: Vec2 = { x: px, y: clampedY }
  const newTrajectory = [...state.trajectory, { ...newPos }]

  return {
    time: newTime,
    position: newPos,
    velocity: { x: vx, y: landed ? 0 : vy },
    acceleration: { x: 0, y: landed ? 0 : -g },
    trajectory: newTrajectory,
    landed,
  }
}

// --- Spring-Mass ---

export const createSpringState = (params: SpringParams): SpringState => {
  const x0 = params.initialDisplacement
  const acc = -(params.springConstant / params.mass) * x0
  return {
    displacement: x0,
    velocity: 0,
    accelerationScalar: acc,
    time: 0,
    position: { x: x0, y: 0 },
    velocityVec: { x: 0, y: 0 },
    acceleration: { x: acc, y: 0 },
  }
}

export const stepSpring = (
  state: SpringState,
  params: SpringParams,
  dt: number,
): SpringState => {
  const { displacement: x, velocity: v } = state
  const { springConstant: k, mass: m, damping: c } = params

  // RK4 for x'' = -(k/m)*x - (c/m)*x'
  const f = (
    pos: number,
    vel: number,
  ): { dx: number; dv: number } => ({
    dx: vel,
    dv: -(k / m) * pos - (c / m) * vel,
  })

  const k1 = f(x, v)
  const k2 = f(x + 0.5 * dt * k1.dx, v + 0.5 * dt * k1.dv)
  const k3 = f(x + 0.5 * dt * k2.dx, v + 0.5 * dt * k2.dv)
  const k4 = f(x + dt * k3.dx, v + dt * k3.dv)

  const newX = x + (dt / 6) * (k1.dx + 2 * k2.dx + 2 * k3.dx + k4.dx)
  const newV = v + (dt / 6) * (k1.dv + 2 * k2.dv + 2 * k3.dv + k4.dv)
  const newA = -(k / m) * newX - (c / m) * newV

  return {
    displacement: newX,
    velocity: newV,
    accelerationScalar: newA,
    time: state.time + dt,
    position: { x: newX, y: 0 },
    velocityVec: { x: newV, y: 0 },
    acceleration: { x: newA, y: 0 },
  }
}

