const renderPendulumSVG = (state: PendulumState, params: PendulumParams) => {
  const cx = 450
  const cy = 60
  const scale = 80
  const bobX = cx + state.position.x * scale
  const bobY = cy - state.position.y * scale
  const bobRadius = 14

  // Trail arc
  const arcRadius = params.length * scale
  const arcStartAngle = -Math.PI / 2 - (params.initialAngle * Math.PI) / 180
  const arcEndAngle = -Math.PI / 2 + (params.initialAngle * Math.PI) / 180
  const arcX1 = cx + arcRadius * Math.cos(arcStartAngle)
  const arcY1 = cy - arcRadius * Math.sin(arcStartAngle)
  const arcX2 = cx + arcRadius * Math.cos(arcEndAngle)
  const arcY2 = cy - arcRadius * Math.sin(arcEndAngle)

  return h(
    'svg',
    {
      viewBox: '0 0 900 400',
      style: styles.svg,
      preserveAspectRatio: 'xMidYMid meet',
    },
    // Background grid
    ...renderGrid(),
    // Arc path
    h('path', {
      d: `M ${arcX1} ${arcY1} A ${arcRadius} ${arcRadius} 0 0 0 ${arcX2} ${arcY2}`,
      fill: 'none',
      stroke: '#334155',
      'stroke-width': '1',
      'stroke-dasharray': '4,4',
    }),
    // Pivot
    h('circle', { cx: String(cx), cy: String(cy), r: '6', fill: '#64748b' }),
    // Rod
    h('line', {
      x1: String(cx),
      y1: String(cy),
      x2: String(bobX),
      y2: String(bobY),
      stroke: '#94a3b8',
      'stroke-width': '2',
    }),
    // Bob
    h('circle', {
      cx: String(bobX),
      cy: String(bobY),
      r: String(bobRadius),
      fill: '#3b82f6',
    }),
    // Bob highlight
    h('circle', {
      cx: String(bobX - 3),
      cy: String(bobY - 3),
      r: '4',
      fill: '#60a5fa',
      opacity: '0.6',
    }),
    // Velocity vector
    ...renderVector(bobX, bobY, state.velocity.x * 8, -state.velocity.y * 8, '#22c55e'),
    // Acceleration vector
    ...renderVector(bobX, bobY, state.acceleration.x * 3, -state.acceleration.y * 3, '#f59e0b'),
  )
}

const renderProjectileSVG = (state: ProjectileState, params: ProjectileParams) => {
  const originX = 80
  const originY = 350
  const maxRange =
    (params.initialVelocity * params.initialVelocity * Math.sin((2 * params.launchAngle * Math.PI) / 180)) /
    params.gravity
  const maxHeight =
    (params.initialVelocity * params.initialVelocity * Math.sin((params.launchAngle * Math.PI) / 180) ** 2) /
    (2 * params.gravity)
  const scaleX = Math.min(750 / Math.max(maxRange, 1), 40)
  const scaleY = Math.min(300 / Math.max(maxHeight, 1), 40)
  const scale = Math.min(scaleX, scaleY)

  const trajectoryPoints = state.trajectory
    .map((p) => `${originX + p.x * scale},${originY - p.y * scale}`)
    .join(' ')

  const px = originX + state.position.x * scale
  const py = originY - state.position.y * scale

  return h(
    'svg',
    {
      viewBox: '0 0 900 400',
      style: styles.svg,
      preserveAspectRatio: 'xMidYMid meet',
    },
    ...renderGrid(),
    // Ground line
    h('line', {
      x1: '40',
      y1: String(originY),
      x2: '860',
      y2: String(originY),
      stroke: '#475569',
      'stroke-width': '2',
    }),
    // Trajectory path
    state.trajectory.length > 1
      ? h('polyline', {
          points: trajectoryPoints,
          fill: 'none',
          stroke: '#3b82f680',
          'stroke-width': '2',
        })
      : h('g', {}),
    // Launch angle indicator
    h('path', {
      d: `M ${originX + 40} ${originY} A 40 40 0 0 0 ${originX + 40 * Math.cos((params.launchAngle * Math.PI) / 180)} ${originY - 40 * Math.sin((params.launchAngle * Math.PI) / 180)}`,
      fill: 'none',
      stroke: '#64748b',
      'stroke-width': '1',
    }),
    // Projectile
    h('circle', {
      cx: String(px),
      cy: String(py),
      r: '10',
      fill: '#ef4444',
    }),
    h('circle', {
      cx: String(px - 2),
      cy: String(py - 2),
      r: '3',
      fill: '#fca5a5',
      opacity: '0.6',
    }),
    // Velocity vector
    ...renderVector(px, py, state.velocity.x * 2, -state.velocity.y * 2, '#22c55e'),
    // Acceleration vector
    ...renderVector(px, py, 0, state.acceleration.y > 0 ? -20 : 20, '#f59e0b'),
  )
}

