      fill: '#a78bfa',
      opacity: '0.3',
    }),
    // Surface line
    h('line', {
      x1: '80',
      y1: String(cy + massSize + 2),
      x2: '860',
      y2: String(cy + massSize + 2),
      stroke: '#475569',
      'stroke-width': '1',
      'stroke-dasharray': '6,3',
    }),
    // Velocity vector
    ...renderVector(massX, cy, state.velocityVec.x * 15, 0, '#22c55e'),
    // Acceleration vector
    ...renderVector(massX, cy + 40, state.acceleration.x * 5, 0, '#f59e0b'),
  )
}

const renderGrid = () =>
  [1, 2, 3, 4, 5, 6, 7, 8].flatMap((i) => [
    h('line', {
      x1: String(i * 100),
      y1: '0',
      x2: String(i * 100),
      y2: '400',
      stroke: '#1e293b',
      'stroke-width': '1',
    }),
    h('line', {
      x1: '0',
      y1: String(i * 50),
      x2: '900',
      y2: String(i * 50),
      stroke: '#1e293b',
      'stroke-width': '1',
    }),
  ])

const renderVector = (
  x: number,
  y: number,
  dx: number,
  dy: number,
  color: string,
) => {
  const len = Math.sqrt(dx * dx + dy * dy)
  if (len < 2) return []
  const capDx = len > 60 ? (dx / len) * 60 : dx
  const capDy = len > 60 ? (dy / len) * 60 : dy
  const ex = x + capDx
  const ey = y + capDy
  const angle = Math.atan2(capDy, capDx)
  const headLen = 8
  const h1x = ex - headLen * Math.cos(angle - 0.4)
  const h1y = ey - headLen * Math.sin(angle - 0.4)
  const h2x = ex - headLen * Math.cos(angle + 0.4)
  const h2y = ey - headLen * Math.sin(angle + 0.4)
  return [
    h('line', {
      x1: String(x),
      y1: String(y),
      x2: String(ex),
      y2: String(ey),
      stroke: color,
      'stroke-width': '2',
    }),
    h('polygon', {
      points: `${ex},${ey} ${h1x},${h1y} ${h2x},${h2y}`,
      fill: color,
    }),
  ]
}

const generateSpringPath = (
  x1: number,
  y1: number,
  x2: number,
  _y2: number,
  coils: number,
): string => {
  const dx = x2 - x1
  const amplitude = 14
  const points: string[] = [`${x1},${y1}`]
  const segments = coils * 2
  for (let i = 1; i <= segments; i++) {
    const t = i / segments
    const px = x1 + dx * t
    const py = y1 + (i % 2 === 1 ? -amplitude : amplitude)
    points.push(`${px},${py}`)
  }
  points.push(`${x2},${y1}`)
  return points.join(' ')
}

