import { createSSR } from 'plaited'
import { renderPage } from './renderer'
import {
  createPendulumState,
  stepPendulum,
  createProjectileState,
  stepProjectile,
  createSpringState,
  stepSpring,
} from './physics'
import type {
  SimulationType,
  PendulumParams,
  ProjectileParams,
  SpringParams,
  PendulumState,
  ProjectileState,
  SpringState,
  PlaybackState,
  SimulationSnapshot,
} from './types'

// --- Default parameters ---

const defaultPendulumParams: PendulumParams = {
  length: 2,
  gravity: 9.81,
  initialAngle: 30,
}

const defaultProjectileParams: ProjectileParams = {
  launchAngle: 45,
  initialVelocity: 20,
  gravity: 9.81,
}

const defaultSpringParams: SpringParams = {
  springConstant: 5,
  mass: 1,
  damping: 0.1,
  initialDisplacement: 2,
}

// --- State ---

let simType: SimulationType = 'pendulum'
let pendulumParams = { ...defaultPendulumParams }
let projectileParams = { ...defaultProjectileParams }
let springParams = { ...defaultSpringParams }
let pendulumState: PendulumState = createPendulumState(pendulumParams)
let projectileState: ProjectileState = createProjectileState(projectileParams)
let springState: SpringState = createSpringState(springParams)
let playback: PlaybackState = { running: false, speed: 1 }

const DT = 1 / 60

// --- Simulation tick ---

const tick = () => {
  if (!playback.running) return

  const steps = Math.max(1, Math.round(playback.speed * 2))
  const stepDt = (DT * playback.speed) / steps

  for (let i = 0; i < steps; i++) {
    switch (simType) {
      case 'pendulum':
        pendulumState = stepPendulum(pendulumState, pendulumParams, stepDt)
        break
      case 'projectile':
        projectileState = stepProjectile(projectileState, projectileParams, stepDt)
        if (projectileState.landed) playback.running = false
        break
      case 'spring':
        springState = stepSpring(springState, springParams, stepDt)
        break
    }
  }
}

// --- Snapshot persistence ---

const saveSnapshot = async () => {
  const snapshot: SimulationSnapshot = {
    type: simType,
    params:
      simType === 'pendulum'
        ? pendulumParams
        : simType === 'projectile'
          ? projectileParams
          : springParams,
    timestamp: new Date().toISOString(),
  }
  const file = Bun.file('./data/snapshots.jsonl')
  const existing = (await file.exists()) ? await file.text() : ''
  await Bun.write(file, existing + JSON.stringify(snapshot) + '\n')
}

// --- Client script (animation loop) ---

const clientScript = `
(() => {
  let animFrame = null;
  let running = false;

  const fetchAndRender = async () => {
    const res = await fetch('/state');
    const html = await res.text();
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    const newContainer = doc.querySelector('[style*="max-width"]');
    const currentContainer = document.querySelector('[style*="max-width"]');
    if (newContainer && currentContainer) {
      currentContainer.innerHTML = newContainer.innerHTML;
      attachListeners();
    }
  };

  const loop = async () => {
    if (!running) return;
    await fetch('/tick', { method: 'POST' });
    await fetchAndRender();
    animFrame = requestAnimationFrame(loop);
  };

  const sendAction = async (action, body = {}) => {
    await fetch('/action', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ action, ...body }),
    });
    await fetchAndRender();
  };

  const attachListeners = () => {
    document.querySelectorAll('[p-trigger^="tab-"]').forEach(btn => {
      btn.onclick = async () => {
        const sim = btn.getAttribute('data-sim');
        await sendAction('switch-tab', { sim });
        running = false;
      };
    });

    const playBtn = document.querySelector('[p-trigger="toggle-play"]');
    if (playBtn) {
      playBtn.onclick = async () => {
        await sendAction('toggle-play');
        const res = await fetch('/playback');
        const pb = await res.json();
        running = pb.running;
        if (running && !animFrame) loop();
      };
    }

    const resetBtn = document.querySelector('[p-trigger="reset"]');
    if (resetBtn) {
      resetBtn.onclick = async () => {
        running = false;
        if (animFrame) { cancelAnimationFrame(animFrame); animFrame = null; }
        await sendAction('reset');
      };
    }

    const speedSlider = document.querySelector('[p-trigger="speed-change"]');
    if (speedSlider) {
      speedSlider.oninput = async (e) => {
        await sendAction('speed', { value: parseFloat(e.target.value) });
        await fetchAndRender();
      };
    }

    const paramSliders = document.querySelectorAll('[p-trigger^="param-"]');
    paramSliders.forEach(slider => {
      slider.oninput = async (e) => {
        const param = slider.getAttribute('p-trigger').replace('param-', '');
        await sendAction('param', { param, value: parseFloat(e.target.value) });
      };
    });
  };

  attachListeners();
})();
`

// --- HTTP Server ---

const renderHTML = (): string => {
  const ssr = createSSR()
  const vdom = renderPage(
    simType,
    pendulumState,
    projectileState,
    springState,
    pendulumParams,
    projectileParams,
    springParams,
    playback,
  )
  return '<!DOCTYPE html>' + ssr(vdom)
}

const handleAction = async (body: Record<string, unknown>) => {
  const action = body.action as string

  switch (action) {
    case 'switch-tab': {
      const sim = body.sim as SimulationType
      playback.running = false
      simType = sim
      break
    }
    case 'toggle-play':
      playback.running = !playback.running
      if (playback.running) await saveSnapshot()
      break
    case 'reset':
      playback.running = false
      switch (simType) {
        case 'pendulum':
          pendulumState = createPendulumState(pendulumParams)
          break
        case 'projectile':
          projectileState = createProjectileState(projectileParams)
          break
        case 'spring':
          springState = createSpringState(springParams)
          break
      }
      break
    case 'speed':
      playback.speed = body.value as number
      break
    case 'param': {
      const param = body.param as string
      const value = body.value as number
      playback.running = false
      switch (simType) {
        case 'pendulum':
          if (param === 'length') pendulumParams.length = value
          else if (param === 'gravity') pendulumParams.gravity = value
          else if (param === 'angle') pendulumParams.initialAngle = value
          pendulumState = createPendulumState(pendulumParams)
          break
        case 'projectile':
          if (param === 'launch-angle') projectileParams.launchAngle = value
          else if (param === 'velocity') projectileParams.initialVelocity = value
          else if (param === 'gravity') projectileParams.gravity = value
          projectileState = createProjectileState(projectileParams)
          break
        case 'spring':
          if (param === 'spring-k') springParams.springConstant = value
          else if (param === 'mass') springParams.mass = value
          else if (param === 'damping') springParams.damping = value
          else if (param === 'displacement') springParams.initialDisplacement = value
          springState = createSpringState(springParams)
          break
      }
      break
    }
  }
}

const server = Bun.serve({
  port: 3000,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' && req.method === 'GET') {
      return new Response(renderHTML(), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/state' && req.method === 'GET') {
      return new Response(renderHTML(), {
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      })
    }

    if (url.pathname === '/playback' && req.method === 'GET') {
      return Response.json(playback)
    }

    if (url.pathname === '/tick' && req.method === 'POST') {
      tick()
      return new Response('ok')
    }

    if (url.pathname === '/action' && req.method === 'POST') {
      const body = (await req.json()) as Record<string, unknown>
      await handleAction(body)
      return new Response('ok')
    }

    if (url.pathname === '/client.js' && req.method === 'GET') {
      return new Response(clientScript, {
        headers: { 'Content-Type': 'application/javascript' },
      })
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Newton's Laws Simulator running at http://localhost:${server.port}`)

