import type { Element } from './types'
import elementsJson from '../data/elements.json'

export const elements: Element[] = elementsJson as Element[]

export const getElementById = (atomicNumber: number): Element | undefined =>
  elements.find((el) => el.atomicNumber === atomicNumber)

export const searchElements = (query: string): Element[] => {
  const q = query.toLowerCase().trim()
  if (!q) return elements
  return elements.filter(
    (el) =>
      el.name.toLowerCase().includes(q) ||
      el.symbol.toLowerCase() === q ||
      String(el.atomicNumber) === q
  )
}

export const filterByCategory = (category: string): Element[] => {
  if (category === 'all') return elements
  return elements.filter((el) => el.category === category)
}

