/**
 * Parse a user-provided string into an array of numbers.
 * Accepts comma-separated values ("1, 2, 3") or JSON arrays ("[1, 2, 3]").
 */
export const parseDataset = (input: string): number[] => {
  const trimmed = input.trim()
  if (trimmed.length === 0) return []

  // Try JSON array first
  if (trimmed.startsWith('[')) {
    try {
      const parsed = JSON.parse(trimmed)
      if (!Array.isArray(parsed)) throw new Error('Input is not an array')
      return parsed.map((v, i) => {
        const n = Number(v)
        if (!Number.isFinite(n)) throw new Error(`Non-numeric value at index ${i}: ${v}`)
        return n
      })
    } catch (e) {
      throw new Error(`Invalid JSON array: ${(e as Error).message}`)
    }
  }

  // Comma-separated or whitespace-separated
  const parts = trimmed.split(/[,\s]+/).filter(Boolean)
  return parts.map((v, i) => {
    const n = Number(v)
    if (!Number.isFinite(n)) throw new Error(`Non-numeric value at index ${i}: "${v}"`)
    return n
  })
}

import type { DatasetStats } from './types'

const sorted = (data: number[]): number[] => [...data].sort((a, b) => a - b)

const sum = (data: number[]): number => data.reduce((acc, v) => acc + v, 0)

const calcMean = (data: number[]): number => sum(data) / data.length

const calcMedian = (data: number[]): number => {
  const s = sorted(data)
  const mid = Math.floor(s.length / 2)
  return s.length % 2 === 0 ? (s[mid - 1] + s[mid]) / 2 : s[mid]
}

const calcMode = (data: number[]): number[] => {
  const freq = new Map<number, number>()
  for (const v of data) {
    freq.set(v, (freq.get(v) ?? 0) + 1)
  }
  const maxFreq = Math.max(...freq.values())
  if (maxFreq === 1) return [] // no mode when all values appear once
  const modes: number[] = []
  for (const [value, count] of freq) {
    if (count === maxFreq) modes.push(value)
  }
  return modes.sort((a, b) => a - b)
}

/**
 * Calculate the quartile value using the inclusive (interpolation) method.
 * `p` is 0.25 for Q1, 0.75 for Q3.
 */
const calcPercentile = (data: number[], p: number): number => {
  const s = sorted(data)
  const idx = p * (s.length - 1)
  const lower = Math.floor(idx)
  const upper = Math.ceil(idx)
  if (lower === upper) return s[lower]
  return s[lower] + (s[upper] - s[lower]) * (idx - lower)
}

const calcVariance = (data: number[], mean: number): number => {
  const squaredDiffs = data.map((v) => (v - mean) ** 2)
  return sum(squaredDiffs) / data.length
}

/**
 * Compute all descriptive statistics for a numeric dataset.
 * Requires at least one value.
 */
export const computeStats = (data: number[]): DatasetStats => {
  if (data.length === 0) throw new Error('Dataset must contain at least one value')

  const s = sorted(data)
  const mean = calcMean(data)
  const variance = calcVariance(data, mean)
  const min = s[0]
  const max = s[s.length - 1]
  const q1 = calcPercentile(data, 0.25)
  const q3 = calcPercentile(data, 0.75)

  return {
    count: data.length,
    mean,
    median: calcMedian(data),
    mode: calcMode(data),
    standardDeviation: Math.sqrt(variance),
    variance,
    min,
    max,
    range: max - min,
    q1,
    q3,
    iqr: q3 - q1,
  }
}

