// ─── SVG Box Plot ─────────────────────────────────────────────────────

const SVG_W = 700
const SVG_BOX_H = 60
const SVG_PAD = 60

const renderBoxPlots = (datasets: NamedDataset[]) => {
  const globalMin = Math.min(...datasets.map((d) => d.stats.min))
  const globalMax = Math.max(...datasets.map((d) => d.stats.max))
  const spread = globalMax - globalMin || 1
  const svgH = datasets.length * SVG_BOX_H + SVG_PAD

  const scaleX = (v: number): number =>
    SVG_PAD + ((v - globalMin) / spread) * (SVG_W - SVG_PAD * 2)

  const tickCount = 8
  const tickStep = spread / tickCount
  const ticks: number[] = []
  for (let i = 0; i <= tickCount; i++) {
    ticks.push(globalMin + tickStep * i)
  }

  return h(
    'svg',
    {
      viewBox: `0 0 ${SVG_W} ${svgH}`,
      style: { width: '100%', maxWidth: `${SVG_W}px`, height: 'auto' },
    },
    // tick lines
    ...ticks.map((t) =>
      h('line', {
        x1: String(scaleX(t)),
        x2: String(scaleX(t)),
        y1: '0',
        y2: String(svgH - SVG_PAD + 10),
        stroke: '#e5e7eb',
        'stroke-width': '1',
      })
    ),
    // tick labels
    ...ticks.map((t) =>
      h(
        'text',
        {
          x: String(scaleX(t)),
          y: String(svgH - SVG_PAD + 28),
          'text-anchor': 'middle',
          'font-size': '11',
          fill: '#6b7280',
        },
        fmt(t)
      )
    ),
    // box plots per dataset
    ...datasets.flatMap((ds, i) => {
      const { stats } = ds
      const y = i * SVG_BOX_H + 10
      const boxH = SVG_BOX_H - 20
      const midY = y + boxH / 2
      const c = colorFor(i)

      const whiskerLow = Math.max(stats.min, stats.q1 - 1.5 * stats.iqr)
      const whiskerHigh = Math.min(stats.max, stats.q3 + 1.5 * stats.iqr)
      const outliers = ds.data.filter((v) => v < whiskerLow || v > whiskerHigh)

      return [
        // whisker line
        h('line', {
          x1: String(scaleX(whiskerLow)),
          x2: String(scaleX(whiskerHigh)),
          y1: String(midY),
          y2: String(midY),
          stroke: c,
          'stroke-width': '1.5',
        }),
        // whisker left cap
        h('line', {
          x1: String(scaleX(whiskerLow)),
          x2: String(scaleX(whiskerLow)),
          y1: String(y + 5),
          y2: String(y + boxH - 5),
          stroke: c,
          'stroke-width': '1.5',
        }),
        // whisker right cap
        h('line', {
          x1: String(scaleX(whiskerHigh)),
          x2: String(scaleX(whiskerHigh)),
          y1: String(y + 5),
          y2: String(y + boxH - 5),
          stroke: c,
          'stroke-width': '1.5',
        }),
        // IQR box
        h('rect', {
          x: String(scaleX(stats.q1)),
          y: String(y),
          width: String(scaleX(stats.q3) - scaleX(stats.q1)),
          height: String(boxH),
          fill: c,
          'fill-opacity': '0.2',
          stroke: c,
          'stroke-width': '2',
          rx: '3',
        }),
        // median line
        h('line', {
          x1: String(scaleX(stats.median)),
          x2: String(scaleX(stats.median)),
          y1: String(y),
          y2: String(y + boxH),
          stroke: c,
          'stroke-width': '2.5',
        }),
        // mean marker (diamond)
        h('polygon', {
          points: [
            `${scaleX(stats.mean)},${y + 2}`,
            `${scaleX(stats.mean) + 5},${midY}`,
            `${scaleX(stats.mean)},${y + boxH - 2}`,
            `${scaleX(stats.mean) - 5},${midY}`,
          ].join(' '),
          fill: c,
        }),
        // outlier circles
        ...outliers.map((v) =>
          h('circle', {
            cx: String(scaleX(v)),
            cy: String(midY),
            r: '3',
            fill: 'none',
            stroke: c,
            'stroke-width': '1.5',
          })
        ),
        // label
        h(
          'text',
          {
            x: '4',
            y: String(midY + 4),
            'font-size': '12',
            'font-weight': '600',
            fill: c,
          },
          ds.name
        ),
      ]
    })
  )
}

// ─── SVG Histogram ────────────────────────────────────────────────────

const HIST_W = 700
const HIST_H = 260
const HIST_PAD_L = 50
const HIST_PAD_B = 40
const HIST_PAD_T = 20
const HIST_PAD_R = 20

const renderHistogram = (datasets: NamedDataset[]) => {
  const allValues = datasets.flatMap((d) => d.data)
  const globalMin = Math.min(...allValues)
  const globalMax = Math.max(...allValues)
  const binCount = Math.max(5, Math.min(30, Math.ceil(Math.sqrt(allValues.length))))
  const binWidth = (globalMax - globalMin || 1) / binCount

  // Build bins per dataset
  type Bin = { start: number; end: number; counts: number[] }
  const bins: Bin[] = []
  for (let i = 0; i < binCount; i++) {
    bins.push({
      start: globalMin + i * binWidth,
      end: globalMin + (i + 1) * binWidth,
      counts: new Array(datasets.length).fill(0),
    })
  }

  for (let di = 0; di < datasets.length; di++) {
    for (const v of datasets[di].data) {
      let idx = Math.floor((v - globalMin) / binWidth)
      if (idx >= binCount) idx = binCount - 1
      if (idx < 0) idx = 0
      bins[idx].counts[di]++
    }
  }

  const maxCount = Math.max(...bins.flatMap((b) => b.counts))
  const plotW = HIST_W - HIST_PAD_L - HIST_PAD_R
  const plotH = HIST_H - HIST_PAD_T - HIST_PAD_B
  const barGroupW = plotW / binCount
  const barW = barGroupW / datasets.length

  const scaleY = (v: number): number =>
    HIST_PAD_T + plotH - (v / (maxCount || 1)) * plotH

  // Y-axis ticks
  const yTickCount = 5
  const yStep = Math.ceil(maxCount / yTickCount) || 1
  const yTicks: number[] = []
  for (let i = 0; i <= yTickCount; i++) {
    const v = i * yStep
    if (v > maxCount && i > 0) break
    yTicks.push(v)
  }

  return h(
    'svg',
    {
      viewBox: `0 0 ${HIST_W} ${HIST_H}`,
      style: { width: '100%', maxWidth: `${HIST_W}px`, height: 'auto' },
    },
    // y-axis ticks
    ...yTicks.flatMap((t) => [
      h('line', {
        x1: String(HIST_PAD_L),
        x2: String(HIST_W - HIST_PAD_R),
        y1: String(scaleY(t)),
        y2: String(scaleY(t)),
        stroke: '#e5e7eb',
        'stroke-width': '1',
      }),
      h(
        'text',
        {
          x: String(HIST_PAD_L - 8),
          y: String(scaleY(t) + 4),
          'text-anchor': 'end',
          'font-size': '11',
          fill: '#6b7280',
        },
        String(t)
      ),
    ]),
    // bars
    ...bins.flatMap((bin, bi) =>
      datasets.map((_ds, di) => {
        const x = HIST_PAD_L + bi * barGroupW + di * barW
        const barHeight = (bin.counts[di] / (maxCount || 1)) * plotH
        return h('rect', {
          x: String(x),
          y: String(HIST_PAD_T + plotH - barHeight),
          width: String(Math.max(barW - 1, 1)),
          height: String(barHeight),
          fill: colorFor(di),
          'fill-opacity': '0.65',
        })
      })
    ),
    // x-axis labels (every ~3 bins)
    ...bins
      .filter((_, i) => i % Math.max(1, Math.floor(binCount / 8)) === 0 || i === binCount - 1)
      .map((bin) =>
        h(
          'text',
          {
            x: String(HIST_PAD_L + ((bin.start - globalMin) / (binWidth * binCount)) * plotW),
            y: String(HIST_H - HIST_PAD_B + 18),
            'text-anchor': 'middle',
            'font-size': '11',
            fill: '#6b7280',
          },
          fmt(bin.start)
        )
      ),
    // legend
    ...datasets.map((ds, di) =>
      h(
        Fragment,
        {},
        h('rect', {
          x: String(HIST_PAD_L + di * 120),
          y: '4',
          width: '12',
          height: '12',
          fill: colorFor(di),
          rx: '2',
        }),
        h(
          'text',
          {
            x: String(HIST_PAD_L + di * 120 + 16),
            y: '14',
            'font-size': '12',
            'font-weight': '600',
            fill: '#374151',
          },
          ds.name
        )
      )
    )
  )
}

