const renderSummaryTable = (datasets: NamedDataset[]) => {
  const formatCell = (stats: DatasetStats, key: keyof DatasetStats): string => {
    const val = stats[key]
    if (key === 'mode') {
      const modes = val as number[]
      return modes.length === 0 ? 'none' : modes.map(fmt).join(', ')
    }
    return fmt(val as number)
  }

  return h(
    'table',
    { style: tableStyle },
    h(
      'thead',
      {},
      h(
        'tr',
        {},
        h('th', { style: thStyle }, 'Statistic'),
