import type { StoredDatasets } from './types'

const DATA_PATH = './data/datasets.json'

export const loadDatasets = async (): Promise<StoredDatasets> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return (await file.json()) as StoredDatasets
  }
  return { datasets: [] }
}

export const saveDatasets = async (store: StoredDatasets): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(store, null, 2))
}

export const clearDatasets = async (): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify({ datasets: [] }, null, 2))
}

import { parseDataset } from './parse'
import { computeStats } from './stats'
import { renderPage } from './render'
import { loadDatasets, saveDatasets, clearDatasets } from './store'
import type { NamedDataset } from './types'

const PORT = Number(process.env.PORT) || 3000

const buildNamedDatasets = (stored: Awaited<ReturnType<typeof loadDatasets>>): NamedDataset[] =>
  stored.datasets.map((d) => ({
    name: d.name,
    data: d.data,
    stats: computeStats(d.data),
  }))

const htmlResponse = (html: string, status = 200) =>
  new Response(html, {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const handleGet = async (): Promise<Response> => {
  const stored = await loadDatasets()
  const datasets = buildNamedDatasets(stored)
  return htmlResponse(renderPage(datasets))
}

const handleAdd = async (req: Request): Promise<Response> => {
  const form = await req.formData()
  const name = (form.get('name') as string | null)?.trim() ?? ''
  const rawData = (form.get('data') as string | null) ?? ''

  if (!name) {
    const stored = await loadDatasets()
    const datasets = buildNamedDatasets(stored)
    return htmlResponse(renderPage(datasets, 'Dataset name is required.'), 400)
  }

  let data: number[]
  try {
    data = parseDataset(rawData)
  } catch (e) {
    const stored = await loadDatasets()
    const datasets = buildNamedDatasets(stored)
    return htmlResponse(renderPage(datasets, (e as Error).message), 400)
  }

  if (data.length === 0) {
    const stored = await loadDatasets()
    const datasets = buildNamedDatasets(stored)
    return htmlResponse(renderPage(datasets, 'Dataset must contain at least one number.'), 400)
  }

  const stored = await loadDatasets()
  // Replace dataset if name already exists
  const existingIdx = stored.datasets.findIndex((d) => d.name === name)
  if (existingIdx >= 0) {
    stored.datasets[existingIdx] = { name, data }
  } else {
    stored.datasets.push({ name, data })
  }
  await saveDatasets(stored)

  const datasets = buildNamedDatasets(stored)
  return htmlResponse(renderPage(datasets))
}

const handleClear = async (): Promise<Response> => {
  await clearDatasets()
  return htmlResponse(renderPage([]))
}

const handleApiStats = async (req: Request): Promise<Response> => {
  const body = (await req.json()) as { data?: unknown; name?: string }
  if (!body.data || !Array.isArray(body.data)) {
    return Response.json({ error: 'Provide a "data" array of numbers.' }, { status: 400 })
  }

  const data = body.data.map(Number)
  if (data.some((v) => !Number.isFinite(v))) {
    return Response.json({ error: 'All values must be finite numbers.' }, { status: 400 })
  }

  const stats = computeStats(data)
  return Response.json({ name: body.name ?? 'untitled', stats })
}

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)

    if (url.pathname === '/' && req.method === 'GET') {
      return handleGet()
    }
    if (url.pathname === '/add' && req.method === 'POST') {
      return handleAdd(req)
    }
    if (url.pathname === '/clear' && req.method === 'POST') {
      return handleClear()
    }
    if (url.pathname === '/api/stats' && req.method === 'POST') {
      return handleApiStats(req)
    }

    return new Response('Not Found', { status: 404 })
  },
})

console.log(`Statistics Calculator running at http://localhost:${server.port}`)
